-- Poems batch 235
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('aa481fff-6798-49fc-b155-9f7882375710','夜坐用韻簡劉朔齋洪雲巖  其一','李曾伯','宋','宋诗','song-poetry','','[]','一線春從地脈回，工夫先是到江梅。',32,'全唐诗/poet.song.214000.json','["一線春從地脈回，工夫先是到江梅。", "雪邊竟覺丰標別，曾向玉堂堂上開。"]'),
('0be7972d-a67b-48ff-ba4e-4a9ff976f903','夜坐用韻簡劉朔齋洪雲巖  其二','李曾伯','宋','宋诗','song-poetry','','[]','風撼松梢夜作聲，月昏水淺歲將更。',32,'全唐诗/poet.song.214000.json','["風撼松梢夜作聲，月昏水淺歲將更。", "江頭不用嫌凄冷，滕六分明玉汝成。"]'),
('e3a61364-94a7-4b80-9a92-2e57e5c69ef3','用韻答紙衾簡雲巖  其一','李曾伯','宋','宋诗','song-poetry','','[]','骨胎盡出先生楮，醉夢常宜處士梅。',32,'全唐诗/poet.song.214000.json','["骨胎盡出先生楮，醉夢常宜處士梅。", "席上雪鋪便我寢，帳中風動任渠開。"]'),
('4cc4cc27-eefa-458b-87f5-e5237592d938','用韻答紙衾簡雲巖  其二','李曾伯','宋','宋诗','song-poetry','','[]','欹枕猶存舒卷聲，覆寒時與寢衣更。',32,'全唐诗/poet.song.214000.json','["欹枕猶存舒卷聲，覆寒時與寢衣更。", "價廉功倍人人燠，一幅春風造化成。"]'),
('550dd2c4-f68f-4a81-a266-67cb2d0629ba','又用韻簡朔齋  其一','李曾伯','宋','宋诗','song-poetry','','[]','霜透青稜暖弗回，冰侵鶴骨瘦於梅。',32,'全唐诗/poet.song.214000.json','["霜透青稜暖弗回，冰侵鶴骨瘦於梅。", "牀頭幸有溪藤製，喚起家僮亟展開。"]'),
('8a74dcbf-508e-4a24-9a0d-4361ec077364','又用韻簡朔齋  其二','李曾伯','宋','宋诗','song-poetry','','[]','僮擁莆穰不作聲，起來城上已殘更。',32,'全唐诗/poet.song.214000.json','["僮擁莆穰不作聲，起來城上已殘更。", "卷衾還却披衣出，此際如何睡得成。"]'),
('a6a75184-0d12-4125-a664-315ab506f73b','又和答雲巖  其一','李曾伯','宋','宋诗','song-poetry','','[]','翠箔香銷曉夢回，驚殘樓角動寒梅。',32,'全唐诗/poet.song.214000.json','["翠箔香銷曉夢回，驚殘樓角動寒梅。", "夜來頗覺風霜薄，問訊南枝開未開。"]'),
('9f5fd6d4-4c9f-48ec-8e60-81124f7783a1','又和答雲巖  其二','李曾伯','宋','宋诗','song-poetry','','[]','冰柱劉叉素有聲，詩筒毋惜僕頻更。',32,'全唐诗/poet.song.214000.json','["冰柱劉叉素有聲，詩筒毋惜僕頻更。", "鴛鴦瓦上猶留伴，一霎南風又釀成。"]'),
('178d6ddb-ecd7-4919-add5-2404f7fb6a84','湘潭道間農家  其一','李曾伯','宋','宋诗','song-poetry','','[]','三兩人家松柏林，翁垂霜髮媼釵荆。',32,'全唐诗/poet.song.214000.json','["三兩人家松柏林，翁垂霜髮媼釵荆。", "兒耕婦織輸官了，山茗村醪樂此生。"]'),
('54408269-4e8c-4a04-a5ba-bbcc33736130','湘潭道間農家  其二','李曾伯','宋','宋诗','song-poetry','','[]','竹外流泉繞屋鳴，田頭有水不憂晴。',32,'全唐诗/poet.song.214000.json','["竹外流泉繞屋鳴，田頭有水不憂晴。", "春來豈問芳菲事，只辦犁鋤要早耕。"]'),
('81f7ad2c-c3f3-4019-80ac-131225f6f2f8','登嶽寺悅亭','李曾伯','宋','宋诗','song-poetry','','[]','十年兩度看山來，雲瑣融峰特地開。',32,'全唐诗/poet.song.214000.json','["十年兩度看山來，雲瑣融峰特地開。", "辦取籃輿窮勝處，南邊無事嶺頭回。"]'),
('8fd5ec51-b494-4630-9399-86cbdf9ca7e3','禹柏  其一','李曾伯','宋','宋诗','song-poetry','','["\u8861\u5c71"]','奕奕衡山禹甸之，功成手植萬年枝。',32,'全唐诗/poet.song.214000.json','["奕奕衡山禹甸之，功成手植萬年枝。", "蒼然柯派孤根出，如見九州疏濬時。"]'),
('09493b33-0177-49e1-b05e-fab90219e479','禹柏  其二','李曾伯','宋','宋诗','song-poetry','','[]','星嶽鍾爲一木奇，霜皮剝落類駢胝。',32,'全唐诗/poet.song.214000.json','["星嶽鍾爲一木奇，霜皮剝落類駢胝。", "生從洚水初平日，閲盡青山無老時。"]'),
('36af65ac-b534-4104-92a4-b2c1d10e0b3e','衡陽道間  其一','李曾伯','宋','宋诗','song-poetry','','[]','滿林松竹翠交加，路過衡陽得幾家。',32,'全唐诗/poet.song.214000.json','["滿林松竹翠交加，路過衡陽得幾家。", "門傍粉牆人寂寂，一陂春水數株花。"]'),
('3446a03a-50be-4b61-b514-6a5f4e6d808f','衡陽道間  其二','李曾伯','宋','宋诗','song-poetry','','[]','聽徹山鷄喚雨聲，東風未肯放新晴。',32,'全唐诗/poet.song.214000.json','["聽徹山鷄喚雨聲，東風未肯放新晴。", "行人莫歎泥塗苦，且幸田家得水耕。"]'),
('01ccc680-5da4-47c6-a81d-d3c03ae90000','衡陽道間  其三','李曾伯','宋','宋诗','song-poetry','','[]','風著征裘怯晚寒，一番春事在征鞍。',32,'全唐诗/poet.song.214000.json','["風著征裘怯晚寒，一番春事在征鞍。", "羞聽後騎鳴笳鼓，贏得兒童夾道看。"]'),
('99624479-eb40-4571-9b7d-4ccbbe669748','賦新茶','李曾伯','宋','宋诗','song-poetry','','[]','建嶺人誇第一綱，湘中熱後已先嘗。',32,'全唐诗/poet.song.214000.json','["建嶺人誇第一綱，湘中熱後已先嘗。", "雖然聲價殊官焙，反覺山家氣味長。"]'),
('a100df40-6a34-493f-b0db-8ba37c3e2cac','賦廬山','李曾伯','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','地據九江匯，天教五老看。',48,'全唐诗/poet.song.214000.json','["地據九江匯，天教五老看。", "孤標橫碧落，百里見青巒。", "星斗光堪摘，烟霞秀可餐。", "何時謝人事，膏秣以從盤。"]'),
('84d9f7ff-5d11-4cc4-8590-b0b986df987f','過小孤','李曾伯','宋','宋诗','song-poetry','','[]','孤立江淮地，中分南北天。',48,'全唐诗/poet.song.214000.json','["孤立江淮地，中分南北天。", "洪流衝巨塊，對峙束平川。", "屹若壁千仞，遠之螺一拳。", "誰將牛女比，斯事豈其然。"]'),
('e629e6b2-c8bf-402a-9cf1-24e5403c9d0f','阻風池州界','李曾伯','宋','宋诗','song-poetry','','[]','擬以風斯下，胡然日在茲。',48,'全唐诗/poet.song.214000.json','["擬以風斯下，胡然日在茲。", "一頭聊且避，八面欲何施。", "坎有險如此，需於沙待之。", "姑陪鵬力厚，萬里看南爲。"]'),
('e575689c-2b07-43a0-a36d-89ac44a01352','望九華','李曾伯','宋','宋诗','song-poetry','','[]','猶記午橋邊，曾吟太華蓮。',48,'全唐诗/poet.song.214000.json','["猶記午橋邊，曾吟太華蓮。", "浮生春夢耳，山色故人然。", "翠滴層巒雨，青橫一抹烟。", "何時身此境，濯我以清泉。"]'),
('62a7fab6-91de-48b7-8f4a-d77cf113d40d','行銅陵道','李曾伯','宋','宋诗','song-poetry','','[]','夜報風姨息，曉乘波后平。',48,'全唐诗/poet.song.214000.json','["夜報風姨息，曉乘波后平。", "江涵一鏡浄，山列兩眉橫。", "依約燃犀處，分明倒蔗生。", "徐行戒舟子，勿使白鷗驚。"]'),
('23145644-7aad-4e0f-abf4-e46eda6742b7','道間苦熱','李曾伯','宋','宋诗','song-poetry','','[]','火傘漾中流，炎風撼葉舟。',48,'全唐诗/poet.song.214000.json','["火傘漾中流，炎風撼葉舟。", "熱幾堪炙手，矮莫可擡頭。", "晝困杯爲却，宵蚊扇不休。", "清涼一榻地，得此足優游。"]'),
('1745e909-a4d2-444d-bb55-8c9669ac1f24','宿宜興禪房','李曾伯','宋','宋诗','song-poetry','','[]','冬當月初後，天欲試霜時。',48,'全唐诗/poet.song.214000.json','["冬當月初後，天欲試霜時。", "永夜絕人語，新寒聽雁知。", "壯心憂國在，老計入山宜。", "莫作邯鄲夢，蕭蕭鬢已絲。"]'),
('bbe4d689-5c2e-4b43-9e74-d7ff7caf95df','送子倅當塗','李曾伯','宋','宋诗','song-poetry','','[]','久歷家庭役，今欣羽翼成。',48,'全唐诗/poet.song.214000.json','["久歷家庭役，今欣羽翼成。", "此行爲別駕，平步可顓城。", "常整韋絃佩，要持冰檗聲。", "山林佚吾老，有子足光榮。"]'),
('22780964-1d42-4450-b051-05a260a2b862','挽蹇都官  其一','李曾伯','宋','宋诗','song-poetry','','[]','風概推諸老，霜臺偉壯游。',48,'全唐诗/poet.song.214000.json','["風概推諸老，霜臺偉壯游。", "握蘭宜入從，剖竹乃爲州。", "早爲庭闈佚，晚猶鄉國憂。", "甘棠遺笏在，衮衮有公侯。"]'),
('5ff34898-4bd1-43db-b5ab-7637f7434623','挽蹇都官  其二','李曾伯','宋','宋诗','song-poetry','','[]','傾蓋荆州日，揚旌蘭澧時。',48,'全唐诗/poet.song.214000.json','["傾蓋荆州日，揚旌蘭澧時。", "相爲王事慮，猶以歲寒期。", "筆寄嗟麟絕，言忠勿駟追。", "典型今已矣，老淚不勝悲。"]'),
('38b9833f-be53-44bb-812d-ead24c0d051c','淡滄陳校勘以詩稿求序答之  其一','李曾伯','宋','宋诗','song-poetry','','[]','挺秀古靈基，來爲學子師。',48,'全唐诗/poet.song.214000.json','["挺秀古靈基，來爲學子師。", "壯心存遠業，餘力付新詩。", "闊步雲霄了，細吟風月宜。", "老來無軟語，敢以此相期。"]'),
('2ac07748-2a41-48f6-a54b-2a90d3a16cc3','淡滄陳校勘以詩稿求序答之  其二','李曾伯','宋','宋诗','song-poetry','','[]','先生杖屨所，童子釣游曾。',48,'全唐诗/poet.song.214000.json','["先生杖屨所，童子釣游曾。", "遺我奇哉作，非吾耄矣能。", "柳凋懷故老，梅小類新朋。", "喚醒黄粱夢，書幃二尺燈。"]'),
('cc977846-5266-4b67-89eb-8ac9f0d548b7','丁巳到宜興墳庵','李曾伯','宋','宋诗','song-poetry','','[]','歸來閑未久，老去役何堪。',48,'全唐诗/poet.song.214000.json','["歸來閑未久，老去役何堪。", "未遠蜀天北，又之湘水南。", "奔馳緣未足，辛苦分當甘。", "徒羨林泉適，長年任住庵。"]'),
('a9763ac1-8264-436f-a148-cb0295f4199b','和晦庵先生定王臺韻','李曾伯','宋','宋诗','song-poetry','','[]','前王千載後，奕代幾人來。',48,'全唐诗/poet.song.214000.json','["前王千載後，奕代幾人來。", "漢事一抔土，湘祠數仞臺。", "山容青拱揖，樹影綠周迴。", "客有登臨者，猶存陟屺哀。"]'),
('2f9c2a3d-5192-4413-9098-3157cc443287','送子倅宜春  其一','李曾伯','宋','宋诗','song-poetry','','[]','已佐當塗郡，春臺再往臨。',48,'全唐诗/poet.song.214000.json','["已佐當塗郡，春臺再往臨。", "勿言官是贅，常以國爲心。", "勉勉思全璧，頻頻寄抵金。", "史君天下士，澡雪奉規箴。"]'),
('9bb34bbc-3678-467b-867b-05a6d2bac550','送子倅宜春  其二','李曾伯','宋','宋诗','song-poetry','','[]','愛子喜能仕，戀親猶欲留。',48,'全唐诗/poet.song.214000.json','["愛子喜能仕，戀親猶欲留。", "肯堂斯室就，不稼曷禾收。", "持此一廉往，綽然千里游。", "彼邦存學記，熟復勿貽羞。"]'),
('0f46407e-0264-491e-b8bb-9b32fe4a0c51','登壽沙和抑齋韻','李曾伯','宋','宋诗','song-poetry','','[]','境占祝融勝，鎮從盤古來。',48,'全唐诗/poet.song.214000.json','["境占祝融勝，鎮從盤古來。", "車航一都會，鼎鼐幾樓臺。", "遠水便鷗狎，前峰約雁回。", "當思牧民意，保養甚於胎。"]'),
('c6205005-3091-4e31-9e5d-fd4264fe7c36','跋衡山曾尉持示秀溪翰墨','李曾伯','宋','宋诗','song-poetry','','["\u8861\u5c71"]','故人木已拱，妙墨尚春溫。',48,'全唐诗/poet.song.214000.json','["故人木已拱，妙墨尚春溫。", "三復家庭語，一如樽酒論。", "竹林毋負籍，蘭砌要追元。", "寶此猶圭璧，流芳在後昆。"]'),
('4ff9a111-8ba3-4440-9905-3bb31bb6cdd5','行湘潭道','李曾伯','宋','宋诗','song-poetry','','[]','古驛湘潭道，人家松竹林。',48,'全唐诗/poet.song.214000.json','["古驛湘潭道，人家松竹林。", "山連梅外遠，春入柳邊深。", "征騎雖欣霽，耕犁久望陰。", "貂裘嗟已敝，猶怯老寒侵。"]'),
('4b9b0436-1afe-4d21-bd3a-48635c1268f5','宿梅下','李曾伯','宋','宋诗','song-poetry','','[]','春事已十一，梅花纔兩三。',48,'全唐诗/poet.song.214000.json','["春事已十一，梅花纔兩三。", "青烟回野燒，翠靄護晴嵐。", "風暖雁將北，日遲人漸南。", "病餘宜緩轡，勿用客程貪。"]'),
('25a2b7bd-0279-491a-b9e6-7bd659d31083','宿千坵市曉行','李曾伯','宋','宋诗','song-poetry','','[]','夜宿三家市，晨征十里程。',48,'全唐诗/poet.song.214000.json','["夜宿三家市，晨征十里程。", "竹輿衝霧去，草屐带霜行。", "無犬花村吠，有雞茅店鳴。", "湖南真樂土，鄰柝莫相驚。"]'),
('608c47b4-27d5-4010-861a-00a2c363df44','宿中洞','李曾伯','宋','宋诗','song-poetry','','[]','松老傲前嶺，梅疏卧淺溪。',48,'全唐诗/poet.song.214000.json','["松老傲前嶺，梅疏卧淺溪。", "避風巢上鵲，喚雨竹間雞。", "野迥夕猶牧，田乾春未犁。", "路迢人倦甚，只向近林棲。"]'),
('a2b28378-b424-48be-be46-86431184c355','宿嶽市','李曾伯','宋','宋诗','song-poetry','','[]','登陟天猶暝，棲回日已西。',48,'全唐诗/poet.song.214000.json','["登陟天猶暝，棲回日已西。", "形軀一萍梗，襟袖半塵泥。", "夾道松成徑，誰家花滿溪。", "定臺凝望遠，烟草正萋萋。"]'),
('0c69b484-80e9-4bd7-b101-9618647c23a2','過衡陽晚宿','李曾伯','宋','宋诗','song-poetry','','[]','雨後春寒冽，山前夕照斜。',48,'全唐诗/poet.song.214000.json','["雨後春寒冽，山前夕照斜。", "身猶尋壘燕，聲雜宿林鴉。", "過嶺尚千里，隔村能幾家。", "毋嫌茅店惡，窗下有梅花。"]'),
('8e3721b5-f489-4ddd-bc1e-6def444778ad','將到永州宿村舍','李曾伯','宋','宋诗','song-poetry','','[]','野宿孤村迥，山行十里荒。',48,'全唐诗/poet.song.214000.json','["野宿孤村迥，山行十里荒。", "犢眠衰草壤，馬踏落梅香。", "入眼春晴薄，打頭風勢揚。", "莫嗟登陟苦，明日看瀟湘。"]'),
('89ecea45-6ede-42b9-b5dc-a6e2d20d240f','過永州道間','李曾伯','宋','宋诗','song-poetry','','[]','雨欠農憂燥，風多客苦埃。',48,'全唐诗/poet.song.214000.json','["雨欠農憂燥，風多客苦埃。", "猶寒鶑未出，將社燕還來。", "桃放紅凝臉，梅飄粉褪腮。", "春山如舊識，一笑病顔開。"]'),
('4099012c-86fb-46fc-b4a8-29c9a8745503','永州城南一士夫家可愛','李曾伯','宋','宋诗','song-poetry','','[]','二水城南路，誰人處士家。',48,'全唐诗/poet.song.214000.json','["二水城南路，誰人處士家。", "不爲軒冕累，盡洗市廛華。", "庭立竹千箇，牆留梅數花。", "吾廬歸未得，對此重咨嗟。"]'),
('7a3a6433-bd43-4f30-8bf2-69a459f0d81c','道間紀事','李曾伯','宋','宋诗','song-poetry','','[]','漸遠零陵道，前瞻驛尚賒。',48,'全唐诗/poet.song.214000.json','["漸遠零陵道，前瞻驛尚賒。", "路傍多古木，村外少人家。", "礙眼雲遮岫，薄情風落花。", "堪憐艷陽月，汩汩走塵沙。"]'),
('c0aa00d3-a36f-4f78-83dc-d76b364b6ffa','自和','李曾伯','宋','宋诗','song-poetry','','[]','旅頓飯足飽，村帘酒莫賒。',48,'全唐诗/poet.song.214000.json','["旅頓飯足飽，村帘酒莫賒。", "暮齡嗟客路，春事屬山家。", "蕨長竹將笋，梅殘李始花。", "問翁何處去，嶺外有烟沙。"]'),
('fe3ad5ee-83ff-4288-a780-e6265aadd378','入清湘界','李曾伯','宋','宋诗','song-poetry','','[]','漸近湘山境，土風清且饒。',48,'全唐诗/poet.song.214000.json','["漸近湘山境，土風清且饒。", "林巒接墟市，水竹带溪橋。", "焙出新茶煮，帘垂老酒招。", "春和民氣樂，幾日是花朝。"]'),
('af1b6a32-66df-457b-931c-662ddf0f87b5','和清湘驛頤齋韻','李曾伯','宋','宋诗','song-poetry','','[]','天與粵相接，嶺由秦始開。',48,'全唐诗/poet.song.214000.json','["天與粵相接，嶺由秦始開。", "隔林禽散亂，尋壘燕驚猜。", "芳草春無盡，長亭人幾來。", "山川作時雨，萬里洗烟埃。"]'),
('82758000-21b9-4305-af58-a049b5a2fe05','過興安塔寺僧以先世詩來偶賦','李曾伯','宋','宋诗','song-poetry','','[]','嶺石水分脊，湖南山盡頭。',48,'全唐诗/poet.song.214000.json','["嶺石水分脊，湖南山盡頭。", "廛聲通海遠，塔影插天浮。", "香接寶坊界，星聯銅柱州。", "祖孫凡幾到，亦是宿緣不。"]'),
('da953786-230d-489d-afcc-cbbb8528e702','入興安界','李曾伯','宋','宋诗','song-poetry','','[]','路入興安境，風光異昔年。',48,'全唐诗/poet.song.214000.json','["路入興安境，風光異昔年。", "山川雖好在，井邑頓凄然。", "雨打半頹屋，烟荒未闢田。", "起丁征糴急，官府爲防邊。"]'),
('c475bff5-b73b-405b-9817-2dd3f2e730a9','過靈川縣','李曾伯','宋','宋诗','song-poetry','','[]','去去靈川境，晴嵐带暮烟。',48,'全唐诗/poet.song.214000.json','["去去靈川境，晴嵐带暮烟。", "檳榔新滿市，榕樹老參天。", "舂委工於水，犁資手以佃。", "凄凉海天角，何事羽書傳。"]'),
('59b7a0a5-2fa7-4dfc-9cac-e5f437b1c52b','己酉六月阻水於宜春道間楓樹','李曾伯','宋','宋诗','song-poetry','','[]','去國二千里，離家五十程。',48,'全唐诗/poet.song.214000.json','["去國二千里，離家五十程。", "炎歊無計避，憂患以身更。", "誤矣驂鸞句，傷哉舐犢情。", "何時拂衣去，藜藿保餘生。"]'),
('c347eff6-2751-46a8-89fe-8eba6d7c18be','挽史魯公  其一','李曾伯','宋','宋诗','song-poetry','','[]','經濟由身致，安危主意深。',48,'全唐诗/poet.song.214000.json','["經濟由身致，安危主意深。", "威名振華夏，歲月付山林。", "世望一老在，天胡二豎侵。", "蓋棺公論定，不泯是人心。"]'),
('65311f0d-0f38-4b5c-a98b-fd43934adc6b','挽史魯公  其二','李曾伯','宋','宋诗','song-poetry','','[]','自出權衡下，當從履屐間。',48,'全唐诗/poet.song.214000.json','["自出權衡下，當從履屐間。", "舊游今歷落，往事幾危艱。", "紀德哀辭痛，酬知老淚潸。", "哲人今已矣，魂夢繞鄞山。"]'),
('80cb4b78-2516-4523-826e-68bbb146c68b','過江陵寄陳次賈','李曾伯','宋','宋诗','song-poetry','','[]','擔簦往解蜀山紛，歸舸經行老幾分。',64,'全唐诗/poet.song.214000.json','["擔簦往解蜀山紛，歸舸經行老幾分。", "楚國喜誇新令尹，霸陵疇識故將軍。", "相逢舉酒酹江月，一笑携書訪岫雲。", "乞得身閑了無事，但知耕鑿感吾君。"]'),
('bafcad82-e818-401d-9460-5b70c570e46a','岳陽送管順甫還清湘','李曾伯','宋','宋诗','song-poetry','','[]','度嶺來荆又戍西，驚濤險棧盡同之。',64,'全唐诗/poet.song.214000.json','["度嶺來荆又戍西，驚濤險棧盡同之。", "七年相與猶一日，萬里偕還分兩岐。", "苕隠我歸終此世，寶坊君到出何時。", "交情果未輕捐棄，回首毋忘贈別詩。"]'),
('9414c53f-5012-4836-94cf-1de5edbaf525','過鄂渚登南樓','李曾伯','宋','宋诗','song-poetry','','[]','壯游幾度上南樓，今度重來二十秋。',64,'全唐诗/poet.song.214000.json','["壯游幾度上南樓，今度重來二十秋。", "俯仰之間只猶昨，登臨何處是無愁。", "好山常在世青眼，此水如斯人白頭。", "老興未闌明月上，歸歟笠澤有扁舟。"]'),
('48340e26-b643-40a9-83ce-bc4f989198e5','和劉疏軒雪堂韻','李曾伯','宋','宋诗','song-poetry','','[]','因君郢調問前蹤，賢者斯能樂雪宮。',64,'全唐诗/poet.song.214000.json','["因君郢調問前蹤，賢者斯能樂雪宮。", "四海香名寰宇外，百年公論黨碑中。", "癯然鶴骨存生氣，寂甚鸞膠續古風。", "留得墨池芳潤在，草玄猶可憶揚雄。"]'),
('6eab94f0-3be9-44d3-857e-a5c929fdd310','和疏軒琵琶亭韻','李曾伯','宋','宋诗','song-poetry','','[]','高亭俯瞰蓼蘋洲，人老香山月自秋。',64,'全唐诗/poet.song.214000.json','["高亭俯瞰蓼蘋洲，人老香山月自秋。", "過耳好音堪一笑，傷心往事只輕漚。", "休嗟塞上明妃調，且送江頭過客舟。", "壯士肯爲兒女淚，柔腸一任惱蘇州。"]'),
('09acf38f-7eb2-4eb1-a4ef-d91215a050ff','望富池卷雪樓作','李曾伯','宋','宋诗','song-poetry','','[]','忠貫羲娥勇冠軍，虎臣勳烈在三分。',64,'全唐诗/poet.song.214000.json','["忠貫羲娥勇冠軍，虎臣勳烈在三分。", "江東父老猶王我，天下英雄有使君。", "萬頃怒濤翻白雪，一樓晴靄插紅雲。", "我來多謝神鴉力，風送牙檣意許勤。"]'),
('41a3f711-3924-42ad-8aa9-ec46f49e8ede','阻風黄盆口','李曾伯','宋','宋诗','song-poetry','','[]','三日江行兩日風，短篷掀舞浪花中。',64,'全唐诗/poet.song.214000.json','["三日江行兩日風，短篷掀舞浪花中。", "危疑正貴須臾忍，靜定將收造化功。", "休歎退飛猶六鷁，會看遇順若孤鴻。", "挽回一息南薰力，穩送征檣秋浦東。"]'),
('ed82348d-90dd-4ed0-b5f3-473ba15dca8c','戊戌冬護軍援廬濡自柵江入今日過之恍然如昨夢因成','李曾伯','宋','宋诗','song-poetry','','[]','隔江屯塢自孫吳，猶記孤軍出此塗。',64,'全唐诗/poet.song.214000.json','["隔江屯塢自孫吳，猶記孤軍出此塗。", "閲十九年如夢覺，歷千萬里幾馳驅。", "月沉荒壘馬橫塞，風捲寒沙雁宿蘆。", "憶著當時身是膽，歸休毋更老江湖。"]'),
('703ebe53-d4f1-4304-9f35-241a9a5ee386','阻風固城湖','李曾伯','宋','宋诗','song-poetry','','[]','歷峽浮江萬里歸，一湖乃爾尼留之。',64,'全唐诗/poet.song.214000.json','["歷峽浮江萬里歸，一湖乃爾尼留之。", "由吾天籟偶相值，豈汝川靈敢肆欺。", "上水雖饒趨下便，北風會有轉南時。", "浮生只作無心看，何用咨咨咄咄爲。"]'),
('170df12c-d902-4da3-84be-7c74e32ad1de','固城湖邊即事','李曾伯','宋','宋诗','song-poetry','','[]','孤舟橫岸水潺湲，野色天成一段閑。',64,'全唐诗/poet.song.214000.json','["孤舟橫岸水潺湲，野色天成一段閑。", "十數牧兒黄犢側，兩三釣叟白鷗間。", "叢叢烟樹誰家市，淺淺雲巒甚處山。", "風定浪平歸路穩，更無魂夢到蕭關。"]'),
('d4406a95-7fd5-4b82-825b-3eaf860fddee','道間即事亦有間而感慨','李曾伯','宋','宋诗','song-poetry','','[]','八載天涯喜遂歸，吳鄉當暑亦相宜。',64,'全唐诗/poet.song.214000.json','["八載天涯喜遂歸，吳鄉當暑亦相宜。", "茗烹陽羨慰久間，鱸買松江更一奇。", "老樹經風惟柳長，新田得雨未秋遲。", "不因看鏡驚頭白，將謂情懷只舊時。"]'),
('b077a906-0bc7-4177-88c0-fbc3021e7c1d','過宜興舟中見霅川諸山','李曾伯','宋','宋诗','song-poetry','','[]','八年不見此山青，一見殊增老眼明。',64,'全唐诗/poet.song.214000.json','["八年不見此山青，一見殊增老眼明。", "鬢髮已從霜露改，翠屏只在水天橫。", "纖塵不染皆秋色，久間相於若世情。", "朝爽夕佳常領略，去來爭似釣舟輕。"]'),
('47e9a638-9b47-4d5d-a887-864e4722f872','術士余雲谷求詩和永國韻','李曾伯','宋','宋诗','song-poetry','','[]','心悟玄機妙不傳，家雖谷口近平泉。',64,'全唐诗/poet.song.214000.json','["心悟玄機妙不傳，家雖谷口近平泉。", "且談方外山林樂，休詫人間將相權。", "世事何如難逆睹，吾生已矣莫多纏。", "未能免俗聊相問，更活耕桑得幾年。"]'),
('b2ca8d17-7f18-4996-a1f0-592d5a6bb2ce','初到善權香火院','李曾伯','宋','宋诗','song-poetry','','[]','寺有宗盟幾百年，洪恩新錫出堯天。',64,'全唐诗/poet.song.214000.json','["寺有宗盟幾百年，洪恩新錫出堯天。", "三生香火前因在，一段林巒舊識然。", "華表鶴歸今豈異，葛陂龍化古嘗傳。", "更須行脚江湖了，來結雲山不盡緣。"]'),
('09284d85-d37f-493d-bf8e-24f5fb217865','丁巳閏月六日登岳陽樓','李曾伯','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','二十年前典此州，經行中又幾春秋。',64,'全唐诗/poet.song.214000.json','["二十年前典此州，經行中又幾春秋。", "青山面目元無恙，白髮形骸祗自羞。", "客子登臨知有酒，古心憂愛在斯樓。", "凭欄慨想飛吟過，水視杯坳芥視舟。"]'),
('9cb55168-5c6a-45aa-acae-159fbb826066','長沙郡齋中夜聞雨不寐','李曾伯','宋','宋诗','song-poetry','','[]','簷花窗葉和燈前，全似江南雁到天。',64,'全唐诗/poet.song.214000.json','["簷花窗葉和燈前，全似江南雁到天。", "漸老弗堪秋意早，不眠那爲雨聲然。", "學儒不力冠非誤，善舞何心袖足旋。", "喚醒幾番關塞夢，蛩吟四壁只年年。"]'),
('6d2dec83-4fb5-4793-988c-efbc23817c1c','徐介卿赴召經筵二詩送之  其一','李曾伯','宋','宋诗','song-poetry','','[]','天賦經綸滿壯懷，飽於敭歷老其才。',64,'全唐诗/poet.song.214000.json','["天賦經綸滿壯懷，飽於敭歷老其才。", "江東見謂無卿比，今世誰能舍我哉。", "嶺表分弓寬上顧，淮頭弄印待公來。", "玉階宜罄忠言告，聞說天邊有詔催。"]'),
('2e1011aa-82ee-4efd-a564-a189f2412bb0','徐介卿赴召經筵二詩送之  其二','李曾伯','宋','宋诗','song-poetry','','[]','袂判平山十五年，喜迎召節下樓船。',64,'全唐诗/poet.song.214000.json','["袂判平山十五年，喜迎召節下樓船。", "交情一見歲寒在，世事幾番春夢然。", "我亦將歸謀佚老，公今此去類登仙。", "一杯且酌長沙酒，莫憶燈棋話漢邊。"]'),
('05d2427d-7d62-4da1-a748-e326ac12b7d1','郡圃木樨開第二花','李曾伯','宋','宋诗','song-poetry','','[]','蒼蒼仙種自誰栽，一度秋光兩度開。',64,'全唐诗/poet.song.214000.json','["蒼蒼仙種自誰栽，一度秋光兩度開。", "故遣寶花裝世界，重教金粟見如來。", "香於月下開樽對，意似霜前把菊催。", "生怕重陽風雨近，亟須領略莫遲回。"]'),
('0031b9f0-20b6-42eb-b085-fe7d7e824cfc','登定王臺  其一','李曾伯','宋','宋诗','song-poetry','','[]','漢恩列土育如春，留得芳名遠到今。',64,'全唐诗/poet.song.214000.json','["漢恩列土育如春，留得芳名遠到今。", "幾換人民此城郭，四圍闤闠有山林。", "見長安日存吾敬，望大行雲契彼心。", "忠孝永貽千載後，絕勝易水築黄金。"]'),
('85ec5c3f-28a6-4ed1-8a1e-5d2901ed7566','登定王臺  其二','李曾伯','宋','宋诗','song-poetry','','[]','羽旄鐘鼓舊曾游，溝葉宮花迹尚留。',64,'全唐诗/poet.song.214000.json','["羽旄鐘鼓舊曾游，溝葉宮花迹尚留。", "耆老遺開秦雍土，登臨偉觀楚湘州。", "月明故國存千禩，木落空山又一秋。", "極目長天詩不盡，西風吹雁使人愁。"]'),
('406bb61a-9cf7-4943-bbf9-e53a1049ea27','九日登壽沙城樓','李曾伯','宋','宋诗','song-poetry','','[]','偶因萸菊到城頭，手攬瀟湘一片秋。',64,'全唐诗/poet.song.214000.json','["偶因萸菊到城頭，手攬瀟湘一片秋。", "西北黄塵清遠徼，東南紫氣盛中州。", "衆山環拱皆衡麓，一水橫陳是橘洲。", "且酌芳樽酹千古，去來鷗雁自沉浮。"]'),
('9c20ad70-c5c0-428d-ab07-7385957f7f56','自和','李曾伯','宋','宋诗','song-poetry','','[]','老態龍鍾雪滿頭，黄花招我對清秋。',64,'全唐诗/poet.song.214000.json','["老態龍鍾雪滿頭，黄花招我對清秋。", "東籬幸可安吾土，南服何堪典此州。", "莫憶風巾游漢渚，早呼雨笠訪滄洲。", "明年把酒知何處，預約家僮釀蟻浮。"]'),
('c289bb14-6177-4323-b5d7-2cfeff7f69d5','立春後登裴公亭時已解郡組','李曾伯','宋','宋诗','song-poetry','','[]','公餘贏得片時休，徙倚危亭豁倦眸。',64,'全唐诗/poet.song.214000.json','["公餘贏得片時休，徙倚危亭豁倦眸。", "屹屹獨存今嶽阜，滔滔不盡古湘流。", "猶看雪意微茫在，頓覺春光駘蕩浮。", "舉酒莫論今古事，只將身世付沙鷗。"]'),
('e3945ed3-8b3d-4d42-83c2-c6112fe456f1','登妙高臺','李曾伯','宋','宋诗','song-poetry','','[]','占得湘中地最高，山川端欲助人豪。',64,'全唐诗/poet.song.214000.json','["占得湘中地最高，山川端欲助人豪。", "萍蓬江海通吳會，蘭芷汀洲带楚騷。", "人住翠微藏夕靄，水連碧落見秋毫。", "闌干立盡家何許，徒賦歸心折大刀。"]'),
('27d55ae0-7725-4cd8-a59d-29c6adc5983b','和蕭石城袖示壬午李漕革夫勸駕詩','李曾伯','宋','宋诗','song-poetry','','[]','閲三十載墨猶新，公是當時第一人。',64,'全唐诗/poet.song.214000.json','["閲三十載墨猶新，公是當時第一人。", "馬革伏波慚立柱，羊裘嚴瀨老垂綸。", "觀賓可以觀其主，在子勝如在乃身。", "多少汗顔君袖手，憑誰舉酒問穹旻。"]'),
('1e6310d0-782f-4828-a5d4-9484fb0763ac','道間見梅','李曾伯','宋','宋诗','song-poetry','','[]','虛簷索笑幾逡巡，不得春風不肯春。',64,'全唐诗/poet.song.214000.json','["虛簷索笑幾逡巡，不得春風不肯春。", "忽覩冰肌傍官道，相逢霜鬢在征塵。", "憐渠孤迥猶寒畯，慰我漂摇類故人。", "猶頼東君不捐棄，枝無南北一番新。"]'),
('566aa1d8-e9f8-4c58-92f4-c3dcec5ddbeb','衡陽道間即事','李曾伯','宋','宋诗','song-poetry','','["\u8861\u5c71"]','衡山九十里衡陽，風物熙然冠楚鄉。',64,'全唐诗/poet.song.214000.json','["衡山九十里衡陽，風物熙然冠楚鄉。", "古木千章屯翠幄，小溪數曲卧虹梁。", "雨蔬旋摘充庖美，社酒新篘透甕香。", "村舍春長無一事，門前車馬任渠忙。"]'),
('f4a5049b-cab0-42aa-8aa9-a251a3cee3ed','午行即事','李曾伯','宋','宋诗','song-poetry','','[]','數日征行喜即晴，山明溪秀翠爲屏。',64,'全唐诗/poet.song.214000.json','["數日征行喜即晴，山明溪秀翠爲屏。", "竹門梅出數枝白，松外山橫幾疊青。", "人漸採茶登隴阜，家多釀秫市郵亭。", "短輿午困幾成夢，兩兩枝禽爲喚醒。"]'),
('2a878fcc-7e9c-45a6-8166-7da8dd70467a','過衡州值雨偶賦','李曾伯','宋','宋诗','song-poetry','','[]','行盡瀟湘第幾山，短輿軋軋費躋攀。',64,'全唐诗/poet.song.214000.json','["行盡瀟湘第幾山，短輿軋軋費躋攀。", "柳邊官驛堠十里，竹裏人家屋數間。", "宿靄弄陰風料峭，春泥障路雨斕斑。", "韶華衮衮成虛擲，强托清吟解病顔。"]'),
('338ee05c-13a6-4c19-abec-a23c6b24e072','入祁陽縣界即事','李曾伯','宋','宋诗','song-poetry','','[]','境入祁陽驛堠迢，道旁烟火頓蕭蕭。',64,'全唐诗/poet.song.214000.json','["境入祁陽驛堠迢，道旁烟火頓蕭蕭。", "茅岡叢篠路磊砢，蓬舍扃柴人寂寥。", "市粒頗艱緣歲儉，野芳交發自春饒。", "扶藜勇過黄羆嶺，知竭精忠答聖朝。"]'),
('1743a6a7-9a9d-4810-b3b3-988b8fcd62ff','宿祁陽題縣驛','李曾伯','宋','宋诗','song-poetry','','[]','垂垂白髮老相催，末路崎嶇轂又推。',64,'全唐诗/poet.song.214000.json','["垂垂白髮老相催，末路崎嶇轂又推。", "萬里備更霜雪苦，十年重入瘴鄉來。", "休思往事驂鸞去，恍類前身化鶴回。", "行盡瀟湘春脉脉，故人惟有道邊梅。"]'),
('6690812b-fce5-4cf5-bb60-0bc23acab1ef','永州四十里頭偶賦題郡驛','李曾伯','宋','宋诗','song-poetry','','[]','病軀羸馬陟崔巍，撲面征塵抖擻開。',64,'全唐诗/poet.song.214000.json','["病軀羸馬陟崔巍，撲面征塵抖擻開。", "萬古春愁借山隔，幾番風信把花催。", "染成湘淚笑鄰竹，飄作壽妝嗟辱梅。", "撚盡吟髭無奈困，亟呼茗椀勝村醅。"]'),
('8e1c8a82-688b-4abb-ab4d-22afc2ef6839','道間梅花可愛風後無復存者','李曾伯','宋','宋诗','song-poetry','','[]','可恨封姨妬雙玉，飄殘羽袂委泥塗。',64,'全唐诗/poet.song.214000.json','["可恨封姨妬雙玉，飄殘羽袂委泥塗。", "香餘江路詩傳甫，影落孤山仙去逋。", "桃李兒曹從後我，竹松朋友肯疏吾。", "夢回紙帳身爲蝶，留得掀篷數尺圖。"]'),
('619f6513-d498-40f7-8db0-83bc7fbe87a6','離永州宿愚溪十里村','李曾伯','宋','宋诗','song-poetry','','[]','冷落愚溪十里村，暫容車騎憇柴門。',64,'全唐诗/poet.song.214000.json','["冷落愚溪十里村，暫容車騎憇柴門。", "松荒頓憶陶潜隠，梅落難招宋玉魂。", "累日有風春自暖，今宵無月夜難昏。", "勿令鼓角鳴行帳，田舍將疑有戍屯。"]'),
('cba949aa-d8cb-46b5-9439-56c574ad9b27','晚宿大塘市','李曾伯','宋','宋诗','song-poetry','','[]','僕僕征鞍日向西，相將山色界湘灕。',64,'全唐诗/poet.song.214000.json','["僕僕征鞍日向西，相將山色界湘灕。", "農多火種春猶燒，客每露行朝未炊。", "燕傍人家猶細認，馬行官道似曾知。", "眼前風物紀無盡，賸費吟鞭幾首詩。"]'),
('4f3ccf7a-30a5-4cfa-aaa5-34006ecde7ff','宿深橋驛','李曾伯','宋','宋诗','song-poetry','','[]','湘浦纔春已著鞭，依稀漸近勸耕天。',64,'全唐诗/poet.song.214000.json','["湘浦纔春已著鞭，依稀漸近勸耕天。", "山櫻花落紅飄雨，野草燒殘青入烟。", "雲接嶺頭陰漠漠，泉流澗底響涓涓。", "嚴關兩入知非偶，重扣寶坊占宿緣。"]'),
('edda9c2c-2ea1-4e4b-a0bc-b12724b8abca','轎中午困啜茶偶成','李曾伯','宋','宋诗','song-poetry','','[]','行盡湘中一月春，霜髭幾欲染緇塵。',64,'全唐诗/poet.song.214000.json','["行盡湘中一月春，霜髭幾欲染緇塵。", "山無重數幾何路，花不知名俱可人。", "午困得茶聊吻潤，春愁著柳亦眉顰。", "天教早辦公家事，乞取身歸笠澤濱。"]'),
('c0a5b90c-e32b-4030-9e6a-1b96671aa6d1','夜雨復晴','李曾伯','宋','宋诗','song-poetry','','[]','雨欲今朝忽又晴，客塗憂緯爲關情。',64,'全唐诗/poet.song.214000.json','["雨欲今朝忽又晴，客塗憂緯爲關情。", "木多未葉春幾槁，桃已皆花水未生。", "宿麥既辜秋隴種，新秧正候早田耕。", "蟄龍何處深淵睡，乞取霆聲爲喚驚。"]'),
('87262efb-f7c2-4186-8a36-8f170f68355e','至清湘驛和己酉壁間韻','李曾伯','宋','宋诗','song-poetry','','[]','冰霜染得鬢毛深，又復鈎輈聽嶺禽。',64,'全唐诗/poet.song.214000.json','["冰霜染得鬢毛深，又復鈎輈聽嶺禽。", "老馬已非筋力舊，好山重見面顔今。", "地饒風物皆春意，天念塵煩爲午陰。", "轉首十年成一夢，龍蛇滿壁富新音。"]'),
('2483c7c4-3033-4a6d-bd38-f73d6fc86b26','將至桂林戒弗作詩飲酒','李曾伯','宋','宋诗','song-poetry','','[]','誤領元戎太乙旗，提封四履鎮南籬。',64,'全唐诗/poet.song.214000.json','["誤領元戎太乙旗，提封四履鎮南籬。", "旄倪爭向道塗看，名姓亦爲蠻徼知。", "時務正殷毋事酒，春光雖好莫言詩。", "經營都了家山去，此是從容觴詠時。"]'),
('227048c9-1e38-401c-aa9e-e9fba25f7ce2','勸駕桂林鄉舉','李曾伯','宋','宋诗','song-poetry','','[]','十年復此主文盟，喜得名邦歲貢英。',64,'全唐诗/poet.song.214000.json','["十年復此主文盟，喜得名邦歲貢英。", "宴啟鹿鳴珠照乘，堂開鵬運玉連城。", "梅花雪裏傳魁信，桂子風前送客程。", "若到天庭問南事，細陳長策爲銷兵。"]'),
('d47a3c86-c59d-45a7-91ba-7fc6ec8470bb','送子守衡州','李曾伯','宋','宋诗','song-poetry','','[]','雁峰自昔號名州，爾既難辭我莫留。',64,'全唐诗/poet.song.214000.json','["雁峰自昔號名州，爾既難辭我莫留。", "臨政毋忘宣上德，持身謹勿遺親羞。", "當令民誦循良守，罔俾人譏恩澤侯。", "國事正殷宜黽勉，明年吾自問歸舟。"]'),
('f5237968-2215-4f97-9ea8-0fb3b56edfec','己未元日寄子','李曾伯','宋','宋诗','song-poetry','','[]','子在衡州我桂州，兩州相望共承流。',64,'全唐诗/poet.song.214000.json','["子在衡州我桂州，兩州相望共承流。", "天回北斗又華旦，人立東風正黑頭。", "新歲五更三節序，老夫六十二春秋。", "何時共對屠蘇飲，應念孤雲爲倚樓。"]'),
('c765ef2b-2ffd-4b73-8d51-343dabfcd0ec','別權瀘帥朱杞材太社','李曾伯','宋','宋诗','song-poetry','','[]','猶記衝寒泝峽來，相期偕至亦偕回。',64,'全唐诗/poet.song.214000.json','["猶記衝寒泝峽來，相期偕至亦偕回。", "朝廷有詔許歸老，藩嶽無人值借才。", "顧我凋年嗟已矣，如君英略勉之哉。", "度瀘要了經營事，心放公平手放開。"]'),
('657fafa4-6044-4709-8e98-d0794321e7b6','過新灘作出峽行','李曾伯','宋','宋诗','song-poetry','','[]','蜀道登天難，尤難泝流入。',288,'全唐诗/poet.song.214000.json','["蜀道登天難，尤難泝流入。", "自峽上夔渝，江險灘節密。", "前年衝寒來，水落且石出。", "寄命竹一縷，寸挽退或尺。", "旬宣愧罔功，征戍幸逭責。", "仁哉聖主恩，有詔許歸佚。", "匆匆乘月下，初值朱明律。", "常年桃漲後，此際梅潦溢。", "危漩若釜沸，驚湍如矢激。", "今年獨何異，水勢平於席。", "僅添半篙綠，穩泛萬頃碧。", "縱橫順濆淖，隠見辨沙磧。", "毋庸事盤灘，了不懼觸石。", "一日涪州岸，三宿雲安邑。", "灧澦露山骨，底柱屹中立。", "巫峰披宿霧，奇哉翠欲滴。", "建瓴高屋易，百里一瞬息。", "安然中流坐，恍若前山失。", "舟輕蜚鳥過，岸駃脫兔疾。", "伊灘以新名，此水慮微澀。", "黎明報船步，數尺長一夕。", "波臣信有助，棹師喜何劇。", "前竿與後枕，櫓六視聽一。", "招呼左右向，心手應相得。"]'),
('8dfe0ba2-6eb6-4d93-8560-7fba3922f5e8','阻風太湖沙塘港','李曾伯','宋','宋诗','song-poetry','','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','歸程雪邊來，四旬六千里。',288,'全唐诗/poet.song.214000.json','["歸程雪邊來，四旬六千里。", "瞿唐過灧澦，洞庭至彭蠡。", "涉歷天下險，心有如此水。", "朅來太湖濱，到家步纔跬。", "胡貽蜚廉怒，相挾馮夷氏。", "驚飈晝而作，駭浪暮不已。", "令人向洋歎，可望不可邇。", "組練前陳扼，銀屋平地起。", "逡巡問維楫，飄泊委蘆葦。", "歸心苦何遽，短棹姑小𫇢。", "嘗聞强則避，事當順而理。", "平明遲解纜，天宇果新霽。", "金烏甫生東，魚龍首俱弭。", "上下大圓鏡，四面平如砥。", "天公翻覆手，風后吹噓是。", "巽轉而之坤，帆去隨所指。", "出湖且入港，曾不片時爾。", "前津問錫麓，弗遠尺有咫。", "舟人顧相賀，昨憂變今喜。", "我生客江湖，噫嘻嗟老矣。", "可以速則速，時當止則止。", "豈惟行舟然，世事只如此。", "由茲石塘出，此去皆坦履。", "歸來荷聖恩，全家頼天賜。"]'),
('c8c9c290-ef96-4a12-9174-63f7afedd4a3','題張醫諭活庵','李曾伯','宋','宋诗','song-poetry','','[]','用藥如用兵，命醫猶命將。',90,'全唐诗/poet.song.214000.json','["用藥如用兵，命醫猶命將。", "醫良則身安，將良則師壯。", "表裏孰虛實，存亡在俯仰。", "能出康濟方，憂慮危急狀。", "活法雖指間，活機寓心上。", "活國與活人，一忠乃可仗。", "我願將皆方虎醫扁倉，四海生民舉無恙。"]'),
('b10eb56c-28c5-464e-b77a-a5c0555271b2','湘南樓落成和林書記韻','李曾伯','宋','宋诗','song-poetry','','[]','樂郊從昔推南州，今控西鄙猶心喉。',322,'全唐诗/poet.song.214000.json','["樂郊從昔推南州，今控西鄙猶心喉。", "碧虛境界富登覽，前賢故址存風流。", "斯樓枕江屹雉堞，俯瞰寒碧潜蟠虯。", "夕佳朝爽在几席，岸巾拄笏供遨頭。", "邇年胡雛肆狙伺，南北不間風馬牛。", "經營墉壑備亭障，旗鼓讙亮雄譙樓。", "巋然東壁乃頭角，適與壤會將誰修。", "斯何時也事斯役，或者食肉非良謀。", "緬懷昨夢閲十載，不謂白首重來游。", "雖然左腹證日急，類捨劍棧窺江油。", "視茲罅漏弗補葺，毋乃閒暇忘綢繆。", "梓人餘力建重屋，吾意正豈舒吾眸。", "三湘百粵類砥柱，金城頟頟江浮浮。", "黄茅薰炙鳶墮水，不費矢鏃空群酋。", "疇其載筆紀崖右，落成且也陳觥籌。", "築惟甲戌繼費誓，城沂亦倣書春秋。", "吾皇神武光四表，自此醜類豈復能虔劉。", "佳哉此詩幕中彥，孤凰一鳴驚群啾。", "带篸梅雪久絕響，眼前有景君兼收。", "謾搜枯腹欲貂續，祗覺顔汗包騂羞。"]'),
('1ac50b1c-977b-4dac-a194-79649ad58931','挽尤端明  其一','李曾伯','宋','宋诗','song-poetry','','[]','身際乾淳盛，家傳祖笏棠。',48,'全唐诗/poet.song.214000.json','["身際乾淳盛，家傳祖笏棠。", "典型周大雅，人物魯靈光。", "厚德千鈞重，明時一鑑亡。", "哲人今已矣，夢卜負巖廊。"]'),
('d41a6492-e435-44b4-897c-32f38d91ecaa','挽尤端明  其二','李曾伯','宋','宋诗','song-poetry','','[]','渡江無故老，文武少全材。',48,'全唐诗/poet.song.214000.json','["渡江無故老，文武少全材。", "金玉其相者，朝廷有幾哉。", "鑾坡資潤色，虎帳壯規恢。", "盍展經綸藴，登調鼎鼐梅。"]'),
('15fdfff2-b34e-449a-a48c-38227429947f','挽尤端明  其三','李曾伯','宋','宋诗','song-poetry','','[]','自入烏公府，受知三十秋。',48,'全唐诗/poet.song.214000.json','["自入烏公府，受知三十秋。", "水魚承雅眷，風鶴記良籌。", "一意人才進，平居國事憂。", "絲桐宜束閣，誰似子期不。"]'),
('94d5dd58-6a81-4cb5-b918-6cb75ae9fe77','挽尤端明  其四','李曾伯','宋','宋诗','song-poetry','','[]','憶昨趨湘水，公歸問錫山。',48,'全唐诗/poet.song.214000.json','["憶昨趨湘水，公歸問錫山。", "惜時爲俗累，欠往拜師顔。", "不復親溫厲，疇其念險艱。", "莫持雞炙去，老淚不勝潸。"]'),
('57014549-3745-405f-a92c-0c8cde82ebd5','庚申病中作','李曾伯','宋','宋诗','song-poetry','','[]','六十三年憂患鄉，人言晚景尚悠長。',228,'全唐诗/poet.song.214000.json','["六十三年憂患鄉，人言晚景尚悠長。", "不知氣鬰致痰厥，忽爾異證生微茫。", "操修弗遂仁者壽，治療倍費醫之良。", "今將累日未痊愈，自知不善攝養貽天殃。", "頭目昏眩手足不能動，偃然一榻殊徬徨。", "光摇兩目皎無寐，汗流四體痛欲僵。", "縱然未即致幻化，惟恐廢棄難安强。", "人生修短固定數，不必以此縈吾腸。", "枝披葉殞待風寒，根本弗固安能當。", "平生蹤跡等一夢，未必可保風燈光。", "兒女滿前無顧戀，家山何許莫思量。", "是非得失一勾斷，萬事盡付之遺忘。", "寧神定慮聽造物，至此收拾甘歸藏。", "門前風月正清朗，符到即去庸何傷。"]'),
('9862b47d-317d-4e92-9568-39ddc5c3ed30','記十五日夜星犯月','李曾伯','宋','宋诗','song-poetry','','[]','兩月之間星入斗，疇昔之夜星入月。',208,'全唐诗/poet.song.214000.json','["兩月之間星入斗，疇昔之夜星入月。", "入斗前史驗虜走，入月韓詩應虜滅。", "昭然垂象不輕示，適驗天心厭胡羯。", "此胡蠶食諸戎盡，雲擾中原野流血。", "去年突然渡江左，幾欲長驅控京闕。", "使其得氣不擊敗，延及生靈禍何烈。", "衣冠正統幸陰佑，依然天塹限南北。", "乃知碩果弗盡剝，東南生意不終絕。", "吾皇修德務飭己，悔悟一念足對越。", "正當歲星在吳分，不待一言退熒惑。", "胡運百載天將亡，兩星炯炯豈虛設。", "自今有道守四夷，海寓一家混吳越。", "病夫得復見太平，願以餘年老農業。"]'),
('cd966825-b4db-4c2f-a717-a59ea6ebcea4','庚申七月自桂歸資壽作','李曾伯','宋','宋诗','song-poetry','','[]','三載烟嵐在嶺陬，幾番清夢到松楸。',64,'全唐诗/poet.song.214000.json','["三載烟嵐在嶺陬，幾番清夢到松楸。", "每憐老子身關塞，長憶童時某水丘。", "今得歸來訪漁隠，不妨高卧老菟裘。", "據鞍矍鑠成何事，徒愧平生馬少游。"]'),
('a661809e-4349-4af7-9737-5c047e3ce7d0','歸善權謝福巖','李曾伯','宋','宋诗','song-poetry','','[]','强健南游抱病還，鬢毛剝落足蹣跚。',64,'全唐诗/poet.song.214000.json','["强健南游抱病還，鬢毛剝落足蹣跚。", "喜觀雲衲酬前約，莫聽家僮說舊官。", "幸免如陵羞在隴，將期同愿老於盤。", "當家公案師拈出，更向三山石上看。"]'),
('6ecc88ee-113f-490a-a6f6-a7c1e148cb9a','勉時思王和尚留','李曾伯','宋','宋诗','song-poetry','','[]','面壁者十年，桑下者一宿。',140,'全唐诗/poet.song.214000.json','["面壁者十年，桑下者一宿。", "時止則止行則行，可久則久速則速。", "時思老子苦硬人，孤雲其身心槁木。", "三年牢落此山中，禪衲爭歸衆魔伏。", "平時欲定方外交，白石清泉正相屬。", "我歸師去人謂何，毋乃欲善其身獨。", "巾瓶到處即爲家，何必江湖苦馳逐。", "若還飛錫出門去，此一瓣香誰與續。", "得住且住則爲佳，敬以此爲上人祝。"]'),
('d4987900-eb3c-4d2c-8a80-ca8c663e0a8b','福巖再過公安贈行  其一','李曾伯','宋','宋诗','song-poetry','','[]','記得桂林臨別，勸師緊閉禪關。',28,'全唐诗/poet.song.214000.json','["記得桂林臨別，勸師緊閉禪關。", "又被如來牽率，未容高卧雲山。"]'),
('9106ffca-41f8-4e3c-9ba1-e734cac17afa','福巖再過公安贈行  其二','李曾伯','宋','宋诗','song-poetry','','[]','浙境欲留師住，荆人爭望師來。',28,'全唐诗/poet.song.214000.json','["浙境欲留師住，荆人爭望師來。", "要是因經未了，不妨兩地裴回。"]'),
('251cf3b5-f3cc-4285-8b4c-cbb0e3b654ce','福巖再過公安贈行  其三','李曾伯','宋','宋诗','song-poetry','','[]','方藉名山作主，胡然舊席重開。',28,'全唐诗/poet.song.214000.json','["方藉名山作主，胡然舊席重開。", "了却江湖願力，切須早早歸來。"]'),
('c1e5e8ae-c416-4a3f-b659-b827d9a21153','餞管制幹','李曾伯','宋','宋诗','song-poetry','','[]','畫諾三邊頼一賢，憐余東下病纏綿。',64,'全唐诗/poet.song.214000.json','["畫諾三邊頼一賢，憐余東下病纏綿。", "驅馳不憚數千里，繾綣相於十二年。", "我老已辜康樂屐，君行快著祖生鞭。", "祗慚無力堪吹送，雪意垂垂餞去船。"]'),
('b5cebf95-2e47-4702-beb8-4bedeca47388','辛酉首夏余雲谷自四明來訪且錄示丙辰年所和永國韻恍然喚起昨夢嗟壯健之不可復得今病廢無它問謾書五十六字謝之時病猶未愈','李曾伯','宋','宋诗','song-poetry','','[]','禪榻相逢六載前，當時駑力尚堪鞭。',64,'全唐诗/poet.song.214000.json','["禪榻相逢六載前，當時駑力尚堪鞭。", "繼更烟瘴爲形役，遍歷風濤不意全。", "思舊仙遊嗟已遠，老軀痿廢抑誰憐。", "而今莫問人間事，得正狐丘是甚年。"]'),
('8c6943d9-4fb2-41db-8490-b7b18c0016d9','宣公祠  其一','李曾伯','宋','宋诗','song-poetry','','[]','相唐德叢復興隆，仁義條陳百奏中。',32,'全唐诗/poet.song.214000.json','["相唐德叢復興隆，仁義條陳百奏中。", "正欲諫君今別駕，延齡更不念孤忠。"]'),
('dd73d737-232d-441d-8f65-4a27dabc9b36','宣公祠  其二','李曾伯','宋','宋诗','song-poetry','','[]','雙湖真澤國，千載相公祠。',24,'全唐诗/poet.song.214000.json','["雙湖真澤國，千載相公祠。", "中有釣魚者，問之俱不知。"]'),
('951503c2-ef7b-4f37-92ce-027d7b969a93','遊千山觀','李曾伯','宋','宋诗','song-poetry','','[]','自重來嶺嶠，豈暇訪湖山。',48,'全唐诗/poet.song.214000.json','["自重來嶺嶠，豈暇訪湖山。", "緹騎行邊了，戎旗護戍閒。", "相看羣玉外，一笑六郎間。", "回首西風靜，何愁老漢關。"]'),
('3ebf0099-1e83-4a9c-b4cc-8fde2e1bde3e','善權奇觀','李曾伯','宋','宋诗','song-poetry','','[]','粵從融結此山川，便作人間小洞天。',64,'全唐诗/poet.song.214000.json','["粵從融結此山川，便作人間小洞天。", "香火叢林千古盛，神仙窟宅自今傳。", "品分三洞中猶宇，脈貫兩巖下出泉。", "我自有緣聊乞取，萬松陰裏一牛眠。"]'),
('2e551e9a-9559-4e03-890e-ec7f84869689','句  其一','蔣志父','宋','宋诗','song-poetry','','[]','春風亭上問秋風。',8,'全唐诗/poet.song.214000.json','["春風亭上問秋風。"]'),
('e83b6a95-e2c4-4787-93ed-ee788310d091','句  其二','蔣志父','宋','宋诗','song-poetry','','[]','每恨從來欠機會，却憐今代少英雄。',16,'全唐诗/poet.song.214000.json','["每恨從來欠機會，却憐今代少英雄。"]'),
('a9d34270-faa0-4454-8cdf-a6539fa94b2f','句  其三','蔣志父','宋','宋诗','song-poetry','','[]','能張吾軍從古少，差强人意似君無。',16,'全唐诗/poet.song.214000.json','["能張吾軍從古少，差强人意似君無。"]'),
('c635942d-0b71-4d18-85a9-fb56d01ef782','寓杭次族人催歸詩韻','戴飛','宋','宋诗','song-poetry','','[]','休把詩來只管催，也曾對菊賦歸來。',32,'全唐诗/poet.song.214000.json','["休把詩來只管催，也曾對菊賦歸來。", "閑雲自笑出山去，未雨如何便得回。"]'),
('0b627d1c-5eb9-4515-88e3-84ab79785287','雲巖','章謙亨','宋','宋诗','song-poetry','','[]','造化雕鎸巧，真成一洞天。',48,'全唐诗/poet.song.214000.json','["造化雕鎸巧，真成一洞天。", "曾將修蟒逐，却許蟄龍眠。", "石現金剛足，泉流仙客田。", "炷香吾道者，色體尚依然。"]'),
('95219238-13bb-4999-a084-6e585ad07113','章巖','章謙亨','宋','宋诗','song-poetry','','[]','傑石何空洞，中藏一寺幽。',48,'全唐诗/poet.song.214000.json','["傑石何空洞，中藏一寺幽。", "不須補天漏，時覺有雲浮。", "蟾吐半輪月，鯨吞萬斛舟。", "茲巖本同姓，欲去且遲留。"]'),
('98ae5ba7-b106-46ce-873e-91a55af05fce','西湖觀梅三首  其一','章謙亨','宋','宋诗','song-poetry','','["\u897f\u6e56"]','梅在西湖上，精神別一般。',48,'全唐诗/poet.song.214000.json','["梅在西湖上，精神別一般。", "喜供詩客賞，怕與俗人看。", "映水林文瘦，依山范叔寒。", "生平逢此友，更覺酒腸寬。"]'),
('2a22308a-db91-4642-a114-327e60dfb223','西湖觀梅三首  其二','章謙亨','宋','宋诗','song-poetry','','["\u897f\u6e56"]','不費東君力，常先草木榮。',48,'全唐诗/poet.song.214000.json','["不費東君力，常先草木榮。", "魏徵元娬媚，夷甫太鮮明。", "有色誰同潔，無香可比清。", "飄零惟不惡，羌笛任渠橫。"]'),
('7a29413a-a727-4f80-ae9c-715d1c8f5f1c','西湖觀梅三首  其三','章謙亨','宋','宋诗','song-poetry','','["\u897f\u6e56"]','臘寒徹骨越精神，吐盡清香不待春。',64,'全唐诗/poet.song.214000.json','["臘寒徹骨越精神，吐盡清香不待春。", "華屋芳筵猶惡俗，竹籬茅舍只安貧。", "湖烟籠處難藏艷，窗月飛來爲寫真。", "自得孤山題品後，至今偏解惱詩人。"]'),
('f3a32c3f-3455-4406-a8d2-273c1e45abf2','祖教寺  其一','章謙亨','宋','宋诗','song-poetry','','[]','出郭尋芳作野行，巖高墅曠水流聲。',64,'全唐诗/poet.song.214000.json','["出郭尋芳作野行，巖高墅曠水流聲。", "草亭日午鸚啼巧，竹院更深月色明。", "寶殿鱗鱗章佛界，珠簾卷卷向山清。", "悠然一榻渾無夢，時有溪聲枕外生。"]'),
('3d6684e3-5001-4d7e-b9ee-14320e7d6012','祖教寺  其二','章謙亨','宋','宋诗','song-poetry','','[]','飛鳥遺音入翠林，轉教柳外和鶑吟。',64,'全唐诗/poet.song.214000.json','["飛鳥遺音入翠林，轉教柳外和鶑吟。", "巖留雲雨過朝暮，寺枕溪流亙古今。", "客過端陽欣採艾，僧嫌破衲懶縫針。", "盃中蒲酒休辭醉，目斷青山有遠心。"]'),
('f6879623-c01f-4ffe-a306-24b32ab6ebcd','浄惠院','章謙亨','宋','宋诗','song-poetry','','[]','浄惠荒涼寺，平林淺阜閒。',48,'全唐诗/poet.song.214000.json','["浄惠荒涼寺，平林淺阜閒。", "殿存碧支佛，門對赭亭山。", "遶屋竹陰翠，沿階苔暈斑。", "雨中來託宿，却羨白鷗閑。"]'),
('dce51661-5855-4f99-883f-d5dc4fd5717f','葛稚川煉丹室','施梓人','宋','宋诗','song-poetry','','[]','暇日肩輿上翠微，烟光巒氣濕人衣。',64,'全唐诗/poet.song.214000.json','["暇日肩輿上翠微，烟光巒氣濕人衣。", "桃花片片隨流去，巖漏泠泠作雨飛。", "丹井稚川成藥處，雙峰滕子讀書基。", "觀音閣上清風爽，擬我諸公吟未歸。"]'),
('08273d4e-f484-401f-b20e-fb51956ef798','大滌洞天留題','袁君儒','宋','宋诗','song-poetry','','[]','斷鼇立極天不崩，誰著天柱東南方。',96,'全唐诗/poet.song.214000.json','["斷鼇立極天不崩，誰著天柱東南方。", "渾沌無竅不斧鑿，誰開九鎖如回腸。", "棲真其人今在否，天壇千載空蒼茫。", "我來泉上一撫掌，龍洞激烈而騰驤。", "翠蛟亭前無六月，天爲洗滌心清涼。", "雅欲削去仙隠迹，驅此山過雲水鄉。"]'),
('a8b84e3a-cd43-4ec4-996f-1c2439dd7f47','寄莫道人  其一','陳文孫','宋','宋诗','song-poetry','','[]','林木自春蘭自芽，遊山過我興何賒。',64,'全唐诗/poet.song.214000.json','["林木自春蘭自芽，遊山過我興何賒。", "鐵橋問徑最高頂，石洞開雲隨處家。", "人訝長年能綠髮，我知真性即丹砂。", "談鋒未了歸途速，一雨洗塵清可涯。"]'),
('6ad2d304-3edc-405c-baae-7897f3721329','寄莫道人  其二','陳文孫','宋','宋诗','song-poetry','','[]','暫閑吏債訪仙居，雲亦隨人爲卷舒。',64,'全唐诗/poet.song.214000.json','["暫閑吏債訪仙居，雲亦隨人爲卷舒。", "桑下忽逢三度宿，腹中如飽十年書。", "哦詩對酒誰知我，食柏餐霞一任渠。", "底事若能無障礙，不愁無地著吾廬。"]'),
('0080aeb4-edf7-485c-a190-53fa336f31f7','梅林','周端常','宋','宋诗','song-poetry','','[]','一官負弩精神小，兩木成林氣象清。',32,'全唐诗/poet.song.214000.json','["一官負弩精神小，兩木成林氣象清。", "且道將軍能止渴，正應宰相作和羹。"]'),
('f4ba1d7a-8909-4d22-a8ad-69e5242abaaf','晚泊','黄載','宋','宋诗','song-poetry','','[]','片帆寂寞繞孤村，茅店驚寒半掩門。',32,'全唐诗/poet.song.214000.json','["片帆寂寞繞孤村，茅店驚寒半掩門。", "行草不成風斷雁，一江煙雨正黄昏。"]'),
('f8b0b164-01c9-4b9d-bc3e-db6600e2633e','陪侍丞相安晚先生宿覺際寺夜遇大風可畏遂賦大篇','黄載','宋','宋诗','song-poetry','','[]','船頭落日如血紅，客言今夕當有風。',272,'全唐诗/poet.song.214000.json','["船頭落日如血紅，客言今夕當有風。", "空山夢回刺骨冷，纊被無力身如弓。", "但聞紙窗響僁窣，初意空厨饑鼠出。", "忽然扉戶競開闔，猶謂偷兒入吾室。", "須臾歘作號怒聲，鼙鼓百萬漁陽鳴。", "室廬動摇地欲轉，林木震吼山如崩。", "噫嘻異哉那有此，欹枕恍惚疑夢寐。", "應是錢塘醉未醒，翻海胥濤騁游戲。", "或者客寓紫塞旁，鐵騎赴敵古戰場。", "不然此處安樂國，何遽隉阢猶乘航。", "起來穴牖目如割，平湖已捲十堆雪。", "乃知跋扈是飛廉，似妒晚來客饒舌。", "因思前年到黄岡，朔風摇江驚斷腸。", "驍將忍凍骨比鐵，壯士力鬭身如湯。", "此身彷彿臨皋上，一感還生百惆悵。", "長安貴人正酣眠，日高尚戀銷金帳。", "東窗未白雞未啼，相公自起燒松枝。"]'),
('dfceb7f9-71f9-4b5c-a487-cfb819dfd134','過長安渡','黄載','宋','宋诗','song-poetry','','[]','重來已過十番秋，更十番秋欲白頭。',32,'全唐诗/poet.song.214000.json','["重來已過十番秋，更十番秋欲白頭。", "無限舊時心裏事，青山殘照水東流。"]'),
('9a6efcf6-83b8-4f60-94ae-cbc46bf680d1','贛州道上見上墳者  其一','黄載','宋','宋诗','song-poetry','','[]','翠樹青烟笑語稠，家家領客醉松楸。',32,'全唐诗/poet.song.214000.json','["翠樹青烟笑語稠，家家領客醉松楸。", "老翁哭子氣欲絕，行到前村更轉頭。"]'),
('4da38603-6809-40db-a744-5137195fd488','贛州道上見上墳者  其二','黄載','宋','宋诗','song-poetry','','[]','攫祭烏鴉噪晚田，草芽新染綠如烟。',32,'全唐诗/poet.song.214000.json','["攫祭烏鴉噪晚田，草芽新染綠如烟。", "墓頭寂寂蟲鳴急，惟有春風舞紙錢。"]'),
('90bdd51c-6c5c-49c1-a391-17ce6ec0f217','讀舊稿蛙吹集一絕','黄載','宋','宋诗','song-poetry','','[]','蛙吹兒童事，重開已汗顔。',24,'全唐诗/poet.song.214000.json','["蛙吹兒童事，重開已汗顔。", "更須留近作，待過十年看。"]'),
('3f94b86f-5507-4496-a484-ab8e4e3696c5','題大洪山','黄載','宋','宋诗','song-poetry','','[]','地當平曠易爲山，故得崔嵬漢沔間。',64,'全唐诗/poet.song.214000.json','["地當平曠易爲山，故得崔嵬漢沔間。", "雲霧涌來無下界，樓臺浮起在中天。", "開窗時見雷霆出，隠几閒看日月還。", "更有鐘聲最堪恨，南風時到八陵邊。"]'),
('3c9dd69d-86f1-441c-9d51-b64f71bf5dc2','隨州沙溪','黄載','宋','宋诗','song-poetry','','[]','石路崎嶇石瀨鳴，峰巒回合小原平。',64,'全唐诗/poet.song.214000.json','["石路崎嶇石瀨鳴，峰巒回合小原平。", "桑麻積雨肥春壠，雞犬一村喧晝晴。", "田婦共携中飯去，樵童相喚上山聲。", "邊頭今有江南景，十數年來不用兵。"]'),
('b19690ed-7873-402b-ac1f-641ed56496d0','題峴山','黄載','宋','宋诗','song-poetry','','[]','向來陵谷尚休然，放眼高臺萬象還。',64,'全唐诗/poet.song.214000.json','["向來陵谷尚休然，放眼高臺萬象還。", "南國一池襄漢水，中原千古鄧唐山。", "斜陽淡淡飛鴻沒，芳草萋萋戎馬閒。", "前代英雄亦何許，棹歌日日過滄灣。"]'),
('ad9bca5d-2fc5-4a3c-b4dd-d27dba6f121e','鍾馗觀鬼鬬蟆圖','黄載','宋','宋诗','song-poetry','','[]','誰推酆都扃，逸此魔十二。',330,'全唐诗/poet.song.214000.json','["誰推酆都扃，逸此魔十二。", "相羣鬭蟆供戲劇，綃墨何從拂其迹。", "兩雄鬭於前，四鬼相視欣欣然。", "小蟆對睨攤雙膝，筠籠一蟆跳欲出。", "前者差壯一力肩，後者引索擎於拳。", "髯翁磬折目勝負，突眼老嫗探頭覷。", "就中黄叟如蹲鴟，破帽長袍吾老馗。", "隻眼直下看不匝，諸鬼樂與吾翁狎。", "四丁更與蟆之魁，疾馳不能壓欲頹。", "蟆肥于豚怒於虎，張頤縮項誇相顧。", "昔時唐宋失天經，妖蟆曾搳天眼精。", "今魔視蟆細於螘，魔若跳梁那可指。", "羣陰膠凝互掀翻，六鼇頂戴愁顛連。", "但能伐魔既厥類，芟夷妖蟆談笑耳。", "僇妖之事馗所司，何獨反與爲兒戲。", "不惟失職縱姦宄，鬼禍如蟆將及爾。", "參軍參軍其然乎，或者好事丹青圖。", "諒應馗笑玉川子，誅蟆未誅骨先苦。", "風悲雨凄天地愁，蟆鬼正是相雄秋。", "僅餘一目不可搳，我曷不可相娛說。", "會聞隔簾歌鬭鼃，山鬼性命摧紅牙。"]'),
('9bff5851-4d6f-4277-9d65-856c50680732','絕句','黄載','宋','宋诗','song-poetry','','[]','社寒比臘更清嚴，花蕊蕭疏半欲緘。',32,'全唐诗/poet.song.214000.json','["社寒比臘更清嚴，花蕊蕭疏半欲緘。", "過手重裘猶得力，莫將晴煗信春衫。"]'),
('2479d8b5-51c3-4526-aec0-87144e0e9ac2','舟中夢覺','黄載','宋','宋诗','song-poetry','','[]','夢覺三通鼓，連檣聞欠呵。',48,'全唐诗/poet.song.214000.json','["夢覺三通鼓，連檣聞欠呵。", "世間半夜後，枕上醒人多。", "思想從天落，悲歡奈曉何。", "南柯莫輕笑，未易到南柯。"]'),
('45dea923-2fad-4f5e-8f0b-488d4240b330','洞霄宮  其一','王學可','宋','宋诗','song-poetry','','[]','天柱峰高萬壑分，故留九鎖限塵棼。',64,'全唐诗/poet.song.214000.json','["天柱峰高萬壑分，故留九鎖限塵棼。", "泉飛窗牖長爲雨，日上岡巒半是雲。", "洞擘陰崖通遠岫，石生暗暈作奇紋。", "聖朝每爲民祈福，絕笈求仙漢代君。"]'),
('389c8fce-10ed-4b0d-95c5-6b72d8e77490','洞霄宮  其二','王學可','宋','宋诗','song-poetry','','[]','歷遍江湖幾萬重，豈期方到洞霄中。',64,'全唐诗/poet.song.214000.json','["歷遍江湖幾萬重，豈期方到洞霄中。", "山翻九鎖天分出，洞徹三茅地透東。", "夭矯龍蛇幢節影，晶熒日月御香風。", "茫茫世上尋雲漢，何必仙宮勝此宮。"]'),
('6ccd649c-3491-4566-9bc3-f611355af617','石梁和韻','王學可','宋','宋诗','song-poetry','','[]','天巧何年路，千峰亂入雲。',48,'全唐诗/poet.song.214000.json','["天巧何年路，千峰亂入雲。", "瀑飛雙澗合，崖斷一橋分。", "樹色春猶凍，猿聲夜或聞。", "靈蹤如可見，煮茗共爐熏。"]'),
('8a2aa0cc-54d6-453d-a858-7140ebc80733','題蘇端明書乳泉賦後','王學可','宋','宋诗','song-poetry','','[]','蘇公早聞道，文章乃其戲。',48,'全唐诗/poet.song.214000.json','["蘇公早聞道，文章乃其戲。", "乳泉出重海，作賦聊記異。", "玉池嚥中夜，挈瓶非小智。", "氣者水之生，此語可深味。"]'),
('ad3b554b-4a78-4324-9fee-480ae0cec7c2','登齊山','馮褎然','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','萬山森玉寒如削，一騎奔塵去欲飛。',64,'全唐诗/poet.song.214000.json','["萬山森玉寒如削，一騎奔塵去欲飛。", "路闊並鞍同笑語，酒酣執手話依違。", "英名他日垂青史，好語今朝紀翠微。", "三月錢塘江上道，莫歌金縷易忘歸。"]'),
('53bcc522-1b93-4e42-aa6d-e851e0bbeced','題浯溪  其一','黄社菴','宋','宋诗','song-poetry','','[]','蜀道于今似弈棋，要令一著□安危。',32,'全唐诗/poet.song.214000.json','["蜀道于今似弈棋，要令一著□安危。", "朝廷獨選李曾伯，勳業當如郭子儀。"]'),
('3160284f-81c4-48ab-ac25-c84c17037b35','題浯溪  其二','黄社菴','宋','宋诗','song-poetry','','[]','雖扼咽喉□□間，猶□□脈得良醫。',32,'全唐诗/poet.song.214000.json','["雖扼咽喉□□間，猶□□脈得良醫。", "□□□□平成報，重讀磨崖□字碑。"]'),
('f866a9c9-25c0-4734-90d5-370bf587c56a','題亞愚江浙紀行集句詩','楊之麟','宋','宋诗','song-poetry','','[]','上人胸次有文機，信手招來總是詩。',32,'全唐诗/poet.song.214000.json','["上人胸次有文機，信手招來總是詩。", "莫問鋪排誰句子，逼人清壓雪梅枝。"]'),
('a5328693-a8f8-4555-b171-5e8c98c217ff','題亞愚江浙紀行集句詩','陳書𥩝','宋','宋诗','song-poetry','','[]','未於詩上著工夫，爭把疏愚敵亞愚。',32,'全唐诗/poet.song.214000.json','["未於詩上著工夫，爭把疏愚敵亞愚。", "只盍金沙分半席，歸舟能用幾錢租。"]'),
('be160c1d-a486-47ba-9709-6fccbdc59528','上之回','王諶','宋','宋诗','song-poetry','','[]','蠲吉辰，薦明廷。',144,'全唐诗/poet.song.214000.json','["蠲吉辰，薦明廷。", "祇中壇，賓萬靈。", "醮祠壽宮禮太一，東祀天孫西太室。", "靈芝寶鼎胙元封，親郊雍畤回中峰。", "中峰絕嶮天所劃，百神驅道平如席。", "雲髾秀革高拂空，翠輦玉鸞鳴霹靂。", "試憑蕭關望朔方，月支稽首樓蘭降。", "復朝獨鹿狩鳴澤，芬樹羽林歸建章。", "建章壁門春晝永，井幹泰液多游幸。", "千秋萬歲奈樂何，幾度鸞旗出安定。"]'),
('acd15650-5e20-46a4-a9e7-a6c4affc350a','張守送酒次敬字韻作詩謝之遊北山','王諶','宋','宋诗','song-poetry','','[]','有客可與遊，闕酒得無病。',180,'全唐诗/poet.song.214000.json','["有客可與遊，闕酒得無病。", "豈意四從事，過我不待請。", "洗杓挹風度，免慙林花盛。", "公學此味如，渾厚兼醇正。", "公量虛谷如，有來良善應。", "肯分兵厨瀝，少佐筆力勁。", "罷營杖頭錢，徐取松間徑。", "登臨舊能賦，七發踵枚乘。", "此興老未衰，西日尚餘映。", "風怒雷再鼓，雲破天一鏡。", "山花下野鳥，詩題一堪命。", "府公文章伯，聲稱聳羣聽。", "明朝倒錦囊，非是庶所訂。", "豈伊綵鳳鳴，而聆露鶴警。", "定知謝東山，凡百易子敬。"]'),
('9e434cce-8274-49e4-ac2a-b70c5302e86e','黄雀','王諶','宋','宋诗','song-poetry','','[]','畢逋秦氏烏，差池吳宮燕。',56,'全唐诗/poet.song.214000.json','["畢逋秦氏烏，差池吳宮燕。", "秦人挾彈巢若危，吳宮遺火巢空散。", "不知野田雀，終日茅簷角。", "卑棲俛啄蓬艾間，不畏鷹鸇與繒𥐊。"]'),
('2d24216d-c944-4736-92c5-923b9f9a0486','贈茅也休  其一','王諶','宋','宋诗','song-poetry','','[]','逢人說也休，舉世任沉浮。',48,'全唐诗/poet.song.214000.json','["逢人說也休，舉世任沉浮。", "清磬野雲曉，素琴山月秋。", "詩材頻料理，世事不經求。", "每向滄波上，時時戲鴨鷗。"]'),
('a01c1fb9-8a37-45aa-b9bc-324fa0ff9d11','贈茅也休  其二','王諶','宋','宋诗','song-poetry','','[]','覿面祇談道，知音不和詩。',48,'全唐诗/poet.song.214000.json','["覿面祇談道，知音不和詩。", "盈樽清竹葉，圍坐古梅枝。", "煮茗雲生鼎，抄糜雪滿匙。", "張山山木落，何日又追隨。"]'),
('0132b1d9-1236-4d69-9794-cfe4f11e0297','贈括蒼季此翁','王諶','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','君來古括州，吳楚一節遊。',48,'全唐诗/poet.song.214000.json','["君來古括州，吳楚一節遊。", "衣染匡廬碧，詩清雁蕩秋。", "山行尋隠逸，野坐傲公侯。", "不欲携書獻，文章生古愁。"]'),
('293c5ab5-59e4-4f3d-aa1f-a309d05c789f','次韻謝惠山村送水仙','王諶','宋','宋诗','song-poetry','','[]','自是神仙客，梅花亦讓青。',48,'全唐诗/poet.song.214000.json','["自是神仙客，梅花亦讓青。", "綠垂雲葉重，黄映雪花輕。", "襪小凌波穩，杯斜带露傾。", "一枝來贈我，吟几覺春生。"]'),
('4ea2b06a-d918-4023-a6a2-021964d25d91','早行','王諶','宋','宋诗','song-poetry','','[]','曉入荆溪路，西風快似刀。',48,'全唐诗/poet.song.214000.json','["曉入荆溪路，西風快似刀。", "雪深埋樹脚，水淺見溪毛。", "歲序相將換，人心只自勞。", "牧童牛背卧，令我愧兒曹。"]'),
('21050b4a-44f2-445b-a2b3-631fe1da4d5c','送薛端夫赴武學赴舉','王諶','宋','宋诗','song-poetry','','[]','溫然如美玉，文以武兼之。',48,'全唐诗/poet.song.214000.json','["溫然如美玉，文以武兼之。", "發鏃妙穿的，揮毫不待思。", "行途多早氣，參學已秋期。", "捷報重陽近，黄花汎一巵。"]'),
('3bcdfa6b-7b70-4b95-a2fe-c3e78838ffad','煮筍','王諶','宋','宋诗','song-poetry','','[]','案有磨人墨，囊無使鬼錢。',48,'全唐诗/poet.song.214000.json','["案有磨人墨，囊無使鬼錢。", "難教典班史，只可折花鈿。", "破屋日多雨，頹簷夜見天。", "山童因煮筍，庖下始生烟。"]'),
('67eac3da-5289-4278-8702-022858b62497','飯罷  其一','王諶','宋','宋诗','song-poetry','','[]','飯罷扣松關，襟懷分外寬。',48,'全唐诗/poet.song.214000.json','["飯罷扣松關，襟懷分外寬。", "凍雲深擁寺，寒瀨淺鳴灘。", "苔剝碑文字，香縈古篆盤。", "尋春難著句，爲怕起愁端。"]'),
('16116ea6-a749-4a8c-a056-0dcfc1ecabe5','飯罷  其二','王諶','宋','宋诗','song-poetry','','[]','雪意猶商略，溪雲半有無。',48,'全唐诗/poet.song.214000.json','["雪意猶商略，溪雲半有無。", "短莎眠野犢，枯樹點寒烏。", "牢落詩仍在，蕭條歲已徂。", "過門人挽住，相倩寫桃符。"]'),
('4ce603a2-5e7a-4d1c-b1cb-e4d4d543427c','柳絮','王諶','宋','宋诗','song-poetry','','[]','解作漫天雪，終成滿地灰。',48,'全唐诗/poet.song.214000.json','["解作漫天雪，終成滿地灰。", "行空無罣礙，入幕任徘徊。", "巧趁蜂鬚去，輕隨燕翼來。", "顛狂渾不定，飛舞過樓臺。"]'),
('7bbddd9e-74e7-48cd-9a98-887ff57b292c','北林','王諶','宋','宋诗','song-poetry','','[]','經行到北林，此地轉驚心。',48,'全唐诗/poet.song.214000.json','["經行到北林，此地轉驚心。", "小市魚蝦貴，荒村竹樹深。", "帆檣侵柳影，罾屋占溪陰。", "詩罷還飛去，沙鷗識苦吟。"]'),
('8f56f088-4e09-43bd-b8aa-7858d7c40317','宿北山  其一','王諶','宋','宋诗','song-poetry','','[]','兀坐苦無營，乘閑偶訪僧。',48,'全唐诗/poet.song.214000.json','["兀坐苦無營，乘閑偶訪僧。", "山深雲作伴，庵迥石爲朋。", "古木含蒼蘚，幽花落翠藤。", "昏鐘三扣罷，童子上香燈。"]'),
('9d91ea45-1cde-4834-bffc-8325f974e68c','宿北山  其二','王諶','宋','宋诗','song-poetry','','[]','四壁靜無人，翛然夜不驚。',48,'全唐诗/poet.song.214000.json','["四壁靜無人，翛然夜不驚。", "龕燈光焰薄，紙帳夢魂清。", "有月山猶暗，無風松自鳴。", "結茅終隠此，高枕待升平。"]'),
('81f710ed-a868-4b5a-981b-800a2f97fa78','入邑  其一','王諶','宋','宋诗','song-poetry','','[]','馬踏新松影，衣沾秀麥寒。',48,'全唐诗/poet.song.214000.json','["馬踏新松影，衣沾秀麥寒。", "藤花綴纓珞，竹筍透琅玕。", "詩向閑中得，心因靜處寬。", "一聲幽鳥囀，深在翠林端。"]'),
('30078660-fc45-4f82-8fa0-173fbdad0d4c','入邑  其二','王諶','宋','宋诗','song-poetry','','[]','野蔓侵沙徑，山泉渡石梁。',48,'全唐诗/poet.song.214000.json','["野蔓侵沙徑，山泉渡石梁。", "樹頭蠶葚熟，籬下雀梅香。", "人與春光老，閒隨日影長。", "撚鬚吟不就，窮殺孟襄陽。"]'),
('8da43c31-c3f6-4c5a-bfd8-0c48c46b62e3','題褚道士雪巘詩卷','王諶','宋','宋诗','song-poetry','','[]','五言與七字，句句總清新。',48,'全唐诗/poet.song.214000.json','["五言與七字，句句總清新。", "但得詩囊富，何憂客路貧。", "梅花一巘雪，瑶草半巖春。", "著我司盟去，吟邊養病身。"]'),
('ebd82234-745c-4770-b3dd-6f8303b7b681','酬趙懶翁求墨','王諶','宋','宋诗','song-poetry','','[]','會面苦無因，緘書意亦勤。',48,'全唐诗/poet.song.214000.json','["會面苦無因，緘書意亦勤。", "相望七十里，僅隔一重雲。", "有句來求墨，得詩如見君。", "從知相憶夢，花下擬論文。"]'),
('ac428883-8a8b-40f0-8e21-8769b126f580','道傍廟','王諶','宋','宋诗','song-poetry','','[]','荒祠存玉像，畫壁剝蒼苔。',48,'全唐诗/poet.song.214000.json','["荒祠存玉像，畫壁剝蒼苔。", "額古名難問，村空祭不來。", "亂鴉號古木，鬭雀罥浮埃。", "猶有人求珓，西風動紙灰。"]'),
('c698c05e-6953-4308-aa5f-73670eb14592','生日','王諶','宋','宋诗','song-poetry','','[]','又是逢初度，紅稀綠暗時。',48,'全唐诗/poet.song.214000.json','["又是逢初度，紅稀綠暗時。", "自斟生日酒，閑理去年詩。", "活計惟書在，衰容只鏡知。", "人情與天道，翻覆似枯棋。"]'),
('b2be7f55-530d-4d29-84a3-c35bed527f56','旅中述懷','王諶','宋','宋诗','song-poetry','','[]','未晚僮先卧，無聊自展衾。',48,'全唐诗/poet.song.214000.json','["未晚僮先卧，無聊自展衾。", "一燈愁裏夢，數首客中吟。", "隣舍誰歌曲，譙更遠送音。", "秋風催素髮，憔悴滿華簪。"]'),
('c2e5757c-bae7-4b59-bf9e-9a0dfc6f0394','到此','王諶','宋','宋诗','song-poetry','','[]','到此添離恨，垂楊已拂肩。',48,'全唐诗/poet.song.214000.json','["到此添離恨，垂楊已拂肩。", "擔輕緣少鏹，衣暖欲抽綿。", "春事遽如許，客懷殊未然。", "竹籬沽酒市，雨濕杏花烟。"]'),
('9e951bd3-6fee-438a-aede-0bb31ed63bd9','乍歸','王諶','宋','宋诗','song-poetry','','[]','去日猶殘雪，歸來夏氣清。',48,'全唐诗/poet.song.214000.json','["去日猶殘雪，歸來夏氣清。", "閑隨白雲出，看到綠陰成。", "野色供詩料，山光快客情。", "路逢鄉父老，駐足問行程。"]'),
('6cc4c42f-6896-4cf7-b318-a24fbe4d166f','過山家','王諶','宋','宋诗','song-poetry','','[]','此地知誰隠，當門列翠屏。',48,'全唐诗/poet.song.214000.json','["此地知誰隠，當門列翠屏。", "栽花多是藥，題壁半書經。", "栗鼠咀紅果，山禽墮翠翎。", "峰頭宜眺望，只欠小茅亭。"]'),
('8e39f100-0972-40a5-bf81-b50c93117c1e','簡劉吉父','王諶','宋','宋诗','song-poetry','','[]','長安爲客者，皆是利名人。',48,'全唐诗/poet.song.214000.json','["長安爲客者，皆是利名人。", "只有君同我，惟添病與貧。", "秋風籬下菊，夜雨水邊蓴。", "擬共租船去，歸家趁小春。"]'),
('725d2437-400f-493d-9438-574a2601b099','簡章伯和','王諶','宋','宋诗','song-poetry','','[]','論交三十載，彼此坐詩窮。',48,'全唐诗/poet.song.214000.json','["論交三十載，彼此坐詩窮。", "只恨性各別，其他心盡同。", "茶苗封穀雨，書葉寄蘋風。", "無限懷君意，鶑聲綠樹中。"]'),
('5b931ab1-3ecf-41ea-b4bb-57ba5125ea73','舟行即事','王諶','宋','宋诗','song-poetry','','[]','釣艇橫溪水，漁罾搭槿籬。',48,'全唐诗/poet.song.214000.json','["釣艇橫溪水，漁罾搭槿籬。", "年豐翁自樂，酒熟客先知。", "凉吹生蘋葉，斜陽戀竹枝。", "苦吟渾未就，倚柂立移時。"]'),
('336e0a2a-4d76-4f4b-81a1-48b001e8ef0e','答章伯和問疾','王諶','宋','宋诗','song-poetry','','[]','伏枕屢經旬，醫庸藥不靈。',48,'全唐诗/poet.song.214000.json','["伏枕屢經旬，醫庸藥不靈。", "自從春意動，纔覺病魂醒。", "露洗桃心赤，風揩柳眼青。", "勞君相憶夢，每夜到巖扃。"]'),
('8d45bb64-74e0-41d9-9f66-54b1c6c5403b','贈筆工','王諶','宋','宋诗','song-poetry','','[]','試子玉簪筆，他工總不如。',48,'全唐诗/poet.song.214000.json','["試子玉簪筆，他工總不如。", "毫長宜貯墨，管凈可抄書。", "汝自誇淮兔，吾猶註魯魚。", "鬢毛斑白盡，心折正緣渠。"]'),
('5429862c-abd0-4f76-9544-7368c05f9973','吳江橋','王諶','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','松江期一到，二十二三年。',48,'全唐诗/poet.song.214000.json','["松江期一到，二十二三年。", "今日身臨此，憑虛骨欲仙。", "塔連吳苑樹，帆带洞庭煙。", "見說鱸魚美，囊無斫鱠錢。"]'),
('cd9d98cc-5c47-428b-ab03-6ee6e4d1c193','招玉淵','王諶','宋','宋诗','song-poetry','','[]','欲言非一事，曉夕待君來。',48,'全唐诗/poet.song.214000.json','["欲言非一事，曉夕待君來。", "吟屋新裝辦，閑門未敢開。", "春光歸巷陌，山色入樓臺。", "猶有梅花在，相期把酒杯。"]'),
('321a79dd-1348-4d36-8904-6283aa335f1f','題詩僧亞愚眉白集','王諶','宋','宋诗','song-poetry','','[]','向來已觀集，今見自吟詩。',48,'全唐诗/poet.song.214000.json','["向來已觀集，今見自吟詩。", "天下有清論，僧中真白眉。", "淡如秋水浄，濃比夏雲奇。", "慎勿輕拈出，常人罕見知。"]'),
('3fb627aa-9f23-4db8-8f19-1c164f09f3f0','到李山寺','王諶','宋','宋诗','song-poetry','','[]','策杖扣禪坊，空山草木長。',48,'全唐诗/poet.song.214000.json','["策杖扣禪坊，空山草木長。", "殿荒人曬席，僧去佛無香。", "榆樹苔衣綠，松花粉穗黄。", "茲行無伴侶，獨自繞修廊。"]'),
('3a0fb871-c53a-42eb-a187-b50ad539c7fd','爲簡上人賦古色軒  其一','王諶','宋','宋诗','song-poetry','','[]','簡師得道不參禪，燕坐常居古色軒。',64,'全唐诗/poet.song.214000.json','["簡師得道不參禪，燕坐常居古色軒。", "夏禹告功遺跡在，任公垂釣有車存。", "海通泉洞深千尺，寺映重巖月一痕。", "何日短筇塵外去，瓣香來此叩玄門。"]'),
('edd13d64-b5f1-4281-bb2b-9af144ba04ee','爲簡上人賦古色軒  其二','王諶','宋','宋诗','song-poetry','','[]','小舟吚啞渡橫塘，十里秋畦粳稻香。',64,'全唐诗/poet.song.214000.json','["小舟吚啞渡橫塘，十里秋畦粳稻香。", "莫怪雨聲驚客夢，要催詩句入行囊。", "重過蘋水波浮綠，遥見菊籬花正黄。", "佳節莫論重九後，𫇢篷獨酌汎茱觴。"]'),
('937dd46d-a344-459a-813a-435a3f78a2c9','虎丘','王諶','宋','宋诗','song-poetry','','[]','五百年前吾祖宅，雲孫從昔未曾經。',64,'全唐诗/poet.song.214000.json','["五百年前吾祖宅，雲孫從昔未曾經。", "山藏古寺窗連碧，水繞平田稻正青。", "臺染夜雲微带潤，劍涵秋水尚餘腥。", "僧堂借得羊毛筆，自蘸寒泉寫石屏。"]'),
('bd266e4f-7f2f-42e0-8029-08f98b9f2e72','遠出乍歸','王諶','宋','宋诗','song-poetry','','[]','五旬行李經吳越，四月風光正惠夷。',64,'全唐诗/poet.song.214000.json','["五旬行李經吳越，四月風光正惠夷。", "綠水悠悠晴脈脈，青條總總實離離。", "飛來何處雙黄蝶，叫徹他山一子規。", "却把閑身成倦客，關心書几晝長時。"]'),
('d3c52fbf-433c-4747-88da-0ffec089f1e7','簡吳若清','王諶','宋','宋诗','song-poetry','','[]','絲桐掛壁戶常扃，雅弄深防俗耳聽。',64,'全唐诗/poet.song.214000.json','["絲桐掛壁戶常扃，雅弄深防俗耳聽。", "滴露研朱重點易，焚香炷火細翻經。", "山含晚色千峰紫，松傲新霜一派青。", "獨向巖扉抱高隠，有誰能識少微星。"]'),
('2233a996-b052-407f-a520-f40791bd78d5','舟行','王諶','宋','宋诗','song-poetry','','[]','前面人家是畫圖，數間茅屋映菰蒲。',64,'全唐诗/poet.song.214000.json','["前面人家是畫圖，數間茅屋映菰蒲。", "濛籠雲裏羣峰出，欵乃灘邊一棹孤。", "歲熟農人還自樂，天晴水鳥競相呼。", "絕憐兩岸垂絲柳，比却來時一半枯。"]'),
('6a3bf657-e089-409c-9ffe-28df180d7dae','次岳尚書韻','王諶','宋','宋诗','song-poetry','','[]','細字書橫雙眼明，破窗閲盡幾陰晴。',64,'全唐诗/poet.song.214000.json','["細字書橫雙眼明，破窗閲盡幾陰晴。", "年來干祿渾無夢，老去吟詩尚有情。", "謾向紙田耕石硯，斷無金縷侑銀觥。", "和篇聊博先生笑，應笑寒儒太瘦生。"]'),
('cd46256e-5ce7-4cfb-89e6-8b43a70d7b07','寄王仲衡尚書','王諶','宋','宋诗','song-poetry','','[]','世態翻雲覆雨間，令人合眼夢還山。',64,'全唐诗/poet.song.214000.json','["世態翻雲覆雨間，令人合眼夢還山。", "生平名義入肝膈，歲晚師門要面顔。", "鷗鷺波寬雖有約，鳳凰城近可容閒。", "留年看試調元手，未擬安仁賦拙艱。"]'),
('6567f427-9d82-41ca-ae49-95d1e7239427','歸山','王諶','宋','宋诗','song-poetry','','[]','特地捫蘿入翠微，楊花故故點征衣。',64,'全唐诗/poet.song.214000.json','["特地捫蘿入翠微，楊花故故點征衣。", "遊人盡逐暮光去，野老獨携山色歸。", "擬泛銀濤浮浩渺，難尋玉貌問芳菲。", "吳亡越伯渾休問，且買清樽送落暉。"]'),
('c7c1e2c4-8bb3-4ab4-907f-25961c3800db','留山庵','王諶','宋','宋诗','song-poetry','','[]','遥山一望青如染，到得山邊却不青。',64,'全唐诗/poet.song.214000.json','["遥山一望青如染，到得山邊却不青。", "松徑有風常自掃，巖扉入夜不曾扃。", "燒殘栢子重添火，沽得村醪旋倒瓶。", "却羨山僧無一事，日長簾下自翻經。"]'),
('7a77c800-5052-43bd-8baa-ca4562f3dfba','病起','王諶','宋','宋诗','song-poetry','','[]','連日新晴愜病懷，跧藏一室絕纖埃。',64,'全唐诗/poet.song.214000.json','["連日新晴愜病懷，跧藏一室絕纖埃。", "出來未得寒猶在，窮不奈何春又回。", "酒盞慚疎朋舊少，紙簾不爲俗人開。", "日長自有閒工課，汲水銅瓶浸古梅。"]'),
('2e237818-7246-4204-acf7-40aeab26ef77','借樓','王諶','宋','宋诗','song-poetry','','[]','借得小樓聊寄蹟，夜深猶自未扃扉。',64,'全唐诗/poet.song.214000.json','["借得小樓聊寄蹟，夜深猶自未扃扉。", "鼠摇暗壁驚人夢，螢度破窗粘客衣。", "舊隠圖書從水汎，後園松菊與心違。", "思量應被沙鷗笑，煙雨滿船胡不歸。"]'),
('d7f0d4cd-9e53-4354-a50a-0aeb105a80cc','題雲海亭','王諶','宋','宋诗','song-poetry','','[]','二十年前曾到此，重來又是晚春時。',64,'全唐诗/poet.song.214000.json','["二十年前曾到此，重來又是晚春時。", "蘆因水長全然短，山被雲遮分外奇。", "漁艇添成古圖畫，鴈行點破碧瑠璃。", "布衣憔悴江湖客，閑倚欄干自覓詩。"]'),
('22ecd106-0966-4c5a-a833-1c5a63b1f7e4','秋風','王諶','宋','宋诗','song-poetry','','[]','去年相遇釣魚磯，今歲飄飄又入扉。',64,'全唐诗/poet.song.214000.json','["去年相遇釣魚磯，今歲飄飄又入扉。", "渡月薄侵蟾兔冷，拂雲輕助燕鴻飛。", "逗遛餘響驚殘夢，催促新寒上裌衣。", "欲把絲桐傳此曲，破琴絃斷損金徽。"]'),
('8b2409b7-8821-455d-91e5-1ec07725a9be','泛苕溪','王諶','宋','宋诗','song-poetry','','[]','六幅蒲帆去似飛，浪翻新漲綠沿堤。',64,'全唐诗/poet.song.214000.json','["六幅蒲帆去似飛，浪翻新漲綠沿堤。", "一川水墨王摩詰，十里鶑花杜牧之。", "雲遶楚宮春雨後，煙籠秦樹晚晴時。", "人生來往情何極，江北江南酒一巵。"]'),
('6a6f14d5-49d9-49a7-9334-5860b41ffe5e','遊善區寺','王諶','宋','宋诗','song-poetry','','[]','閑來古寺欲忘歸，無奈征塵染素衣。',64,'全唐诗/poet.song.214000.json','["閑來古寺欲忘歸，無奈征塵染素衣。", "綠葉雲稠荒澗水，白雲青濕舊禪扉。", "窗涵遠色明丹篆，鐘冒嵐煙入翠微。", "盛世登封今已矣，斷碑無語對斜暉。"]'),
('f0760f24-6b8f-4bf9-9e50-4e679d5b4f75','友人招飲','王諶','宋','宋诗','song-poetry','','[]','故人邀我共清樽，躡屐歸來已半醺。',64,'全唐诗/poet.song.214000.json','["故人邀我共清樽，躡屐歸來已半醺。", "無限雨聲供醉筆，一窗燈影共誰分。", "銅瓶火煖鳴天籟，寶鼎香殘拂岫雲。", "今夜夢魂清更甚，扁舟冷伴白鷗羣。"]'),
('66a9dc85-4569-4322-bb18-548a7f70d33e','入山','王諶','宋','宋诗','song-poetry','','[]','入却山來事事宜，眼邊何處不關詩。',64,'全唐诗/poet.song.214000.json','["入却山來事事宜，眼邊何處不關詩。", "風飄花片上書冊，水浸山峰入硯池。", "酒欲飲時斟易盡，棋當勝處著嫌遲。", "箇中自有無窮趣，莫遣兒曹取次知。"]'),
('c0679bc1-0b58-4711-9da4-16fee676e6ae','送墨與則上人','王諶','宋','宋诗','song-poetry','','[]','遣送書齋小浄瓶，麝煤藏久带芳馨。',32,'全唐诗/poet.song.214000.json','["遣送書齋小浄瓶，麝煤藏久带芳馨。", "難書八萬四千偈，只寫多心一卷經。"]'),
('2ba5ec10-5743-4f77-974c-8495d9dd74d4','苕溪舟次','王諶','宋','宋诗','song-poetry','','[]','扁舟煙重冷漁蓑，兩岸人家浸小河。',32,'全唐诗/poet.song.214000.json','["扁舟煙重冷漁蓑，兩岸人家浸小河。", "芳草自生春自老，落花隨雨晚風多。"]'),
('e4c35453-5416-4a25-af94-afb755850aec','山庵即景','王諶','宋','宋诗','song-poetry','','[]','一炷清香一局棋，坐看山雨到來時。',32,'全唐诗/poet.song.214000.json','["一炷清香一局棋，坐看山雨到來時。", "晚晴獨步出門去，雲掛碧青松樹枝。"]'),
('7df0c992-1c5c-4312-b83a-690dfebfdb76','十月晦日睡起','王諶','宋','宋诗','song-poetry','','[]','睡起西窗午正蹉，小春天氣尚融和。',32,'全唐诗/poet.song.214000.json','["睡起西窗午正蹉，小春天氣尚融和。", "顛狂絕笑簷前蝶，不道殘陽已不多。"]'),
('463b23c9-b695-4663-8bbf-777a0589dc56','次亞愚韻  其一','王諶','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','萬里春光眼界明，半窗斜日醉魂醒。',32,'全唐诗/poet.song.214000.json','["萬里春光眼界明，半窗斜日醉魂醒。", "有時夢入廬山去，瀑布聲中拄杖行。"]'),
('49f1e761-51b7-459e-a676-7dcea736d2a4','次亞愚韻  其二','王諶','宋','宋诗','song-poetry','','[]','絲絲楊柳拂輕烟，那惜床頭買酒錢。',32,'全唐诗/poet.song.214000.json','["絲絲楊柳拂輕烟，那惜床頭買酒錢。", "此段風流如不賞，一般佳致又明年。"]'),
('d87a78f2-31f7-47d5-9179-78ce2413a194','次亞愚韻  其三','王諶','宋','宋诗','song-poetry','','[]','梅臉斕斑褪粉粧，桃心依約暈輕黄。',32,'全唐诗/poet.song.214000.json','["梅臉斕斑褪粉粧，桃心依約暈輕黄。", "春風花草經行遍，次第安排到海棠。"]'),
('e762a47e-6696-4e35-a47f-6b53923d1c4e','次亞愚韻  其四','王諶','宋','宋诗','song-poetry','','[]','寒梅一樹照清池，花底嫣香尚覓詩。',32,'全唐诗/poet.song.214000.json','["寒梅一樹照清池，花底嫣香尚覓詩。", "稚子不知吟思苦，却來池上數魚兒。"]'),
