('041fd8cf-bedb-4ce5-b773-de94746804d8','題壺','蕭澥','宋','宋诗','song-poetry','','[]','望斷碧雲無白衣，一春長是獨醒時。',32,'全唐诗/poet.song.214000.json','["望斷碧雲無白衣，一春長是獨醒時。", "煩君卷舌東風裏，休勸饑人食肉糜。"]'),
('7c6393e5-32ea-4503-abf3-306ee3294d33','常山舟中','蕭澥','宋','宋诗','song-poetry','','[]','兩岸人家峙兩樓，中間一水過行舟。',32,'全唐诗/poet.song.214000.json','["兩岸人家峙兩樓，中間一水過行舟。", "倚篷碎擘桃花片，亂擲江心試急流。"]'),
('af2540cf-40d7-4c55-8123-44581897c004','還安舟中','蕭澥','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','亂蟬鳴咽夕陽天，楊柳陰中幾客船。',32,'全唐诗/poet.song.214000.json','["亂蟬鳴咽夕陽天，楊柳陰中幾客船。", "岸下長江流浩浩，誰知岸上有乾田。"]'),
('0fb44819-dc51-4e6e-8641-aa9fd00ef391','過東平悼曾英甫','蕭澥','宋','宋诗','song-poetry','','[]','前時來客此山居，同醉梅邊酒幾壺。',32,'全唐诗/poet.song.214000.json','["前時來客此山居，同醉梅邊酒幾壺。", "不道後來成死別，影堂吟落一燈孤。"]'),
('60592ac7-fe25-4289-a846-f1dec7fbdd50','韶口山家','蕭澥','宋','宋诗','song-poetry','','[]','茅屋一區山四圍，門前蕷圃带茭池。',32,'全唐诗/poet.song.214000.json','["茅屋一區山四圍，門前蕷圃带茭池。", "兒童似駭儒衣到，兩兩三三壁縫窺。"]'),
('43a91dbe-33fa-44e3-88d1-1bbcc3845154','避亂山家  其一','蕭澥','宋','宋诗','song-poetry','','[]','野人生長在高山，道路崎嶇輕往還。',32,'全唐诗/poet.song.214000.json','["野人生長在高山，道路崎嶇輕往還。", "長是五更炊未熟，已籠雞鴨送林間。"]'),
('510f5a44-79ba-4eeb-b683-a971762fb108','避亂山家  其二','蕭澥','宋','宋诗','song-poetry','','[]','深村林麓冷颼颼，滿眼風光總是愁。',32,'全唐诗/poet.song.214000.json','["深村林麓冷颼颼，滿眼風光總是愁。", "日月羨渠雙喜鵲，自跳自擲樹梢頭。"]'),
('ed59c762-2c42-4b30-aeb1-4460b8c9322a','亂後過隆教寺','蕭澥','宋','宋诗','song-poetry','','[]','紙窗破碎網蜘蛛，古鐵香爐灰半無。',32,'全唐诗/poet.song.214000.json','["紙窗破碎網蜘蛛，古鐵香爐灰半無。", "吟得詩成無筆在，閑尋枯炭壁間書。"]'),
('9b796bb1-7f11-471b-aada-a8e901e40d03','亂定到邑','蕭澥','宋','宋诗','song-poetry','','[]','蒙蒙野草自榮華，破屋夾茅人賣茶。',32,'全唐诗/poet.song.214000.json','["蒙蒙野草自榮華，破屋夾茅人賣茶。", "滿巷門基带磚石，有時認得故人家。"]'),
('1749757c-ef45-4562-92fb-f419227b5224','寫林和靖梅花詩後','蕭澥','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖幽處卧煙霞，湖裏荷花匝四涯。',32,'全唐诗/poet.song.214000.json','["西湖幽處卧煙霞，湖裏荷花匝四涯。", "何事先生得佳句，荷花却不似梅花。"]'),
('3f2bf8d2-f2bf-47bd-b67c-77d99abdd676','無題','蕭澥','宋','宋诗','song-poetry','','[]','衣縫密密今垂老，襁褓咿咿漸趁行。',32,'全唐诗/poet.song.214000.json','["衣縫密密今垂老，襁褓咿咿漸趁行。", "君縱無情到閨閫，那應母子亦無情。"]'),
('4d9ca90d-2150-4f13-bd41-4d5890a9c1f3','重過鄧村','蕭澥','宋','宋诗','song-poetry','','[]','瘦竹挑雲過此村，十年前事總銷魂。',32,'全唐诗/poet.song.214000.json','["瘦竹挑雲過此村，十年前事總銷魂。", "當時新廟曾題字，壁老泥枯半不存。"]'),
('c727657e-1cae-4ceb-ae1f-58f18cd2ea57','賦楊妃襪','曾原一','宋','宋诗','song-poetry','','[]','萬騎西行駐馬嵬，凌波曾此墮塵埃。',32,'全唐诗/poet.song.214000.json','["萬騎西行駐馬嵬，凌波曾此墮塵埃。", "誰知一掬香羅小，踏轉開元宇宙來。"]'),
('1871d3ed-51f6-4fc3-a7a9-39aece4e4a4e','同戴石屏十人重游分韻得鑿字即席賦','曾原一','宋','宋诗','song-poetry','','[]','綫逕盤邅回，老壁出參錯。',72,'全唐诗/poet.song.214000.json','["綫逕盤邅回，老壁出參錯。", "洞深路欲無，且進還悸愕。", "太虛墮滓液，有此奇偉作。", "芮也勞斧斤，此語失之鑿。", "鬭崖濕生雲，泉雜雲影落。", "殿頭何時仙，怡然騎木鶴。"]'),
('ef16e7c8-9673-40a7-a9ed-95b339c83dcc','金精歌','曾原一','宋','宋诗','song-poetry','','[]','玄龍捲雨翻東溟，萬華變滅如輕塵。',228,'全唐诗/poet.song.214000.json','["玄龍捲雨翻東溟，萬華變滅如輕塵。", "雹拳破瓦萬甲疾，祇恐天地今無春。", "東來一馬當軒下，雲葉眵剝天痕青。", "雲開衡嶽韓子到，此事恍惚今難憑。", "桃源有路不可入，桃花影絕那得尋。", "喳喳鵲鳴拔鳥起，豈子偉語曰滄溟。", "聯騎瘦蹇踏脆綠，見者謂我椒庭人。", "瑶琴飛響暗雪瀑，傑句泣畫逃山精。", "胸蟠玉虹世李白，筆舞鐵鎖今顔卿。", "飛仙遺章出天韻，引觴清酌球琳鳴。", "泉淙淙兮靈鼓，山崇崇兮太古。", "神明有舍炳萬象，何處人間非紫府。", "靈根曄曄貫元氣，瞬睫蓬萊無弱水。", "雲褷褷，露泚泚。", "米珠簸兮方秤，橘社同兮舟里。"]'),
('171abb5c-6a50-4768-8952-53b2fb87edd6','金精山','曾原一','宋','宋诗','song-poetry','','[]','散策深尋紫翠邊，雨餘林密意蒼然。',64,'全唐诗/poet.song.214000.json','["散策深尋紫翠邊，雨餘林密意蒼然。", "玄崖擁路奇千疊，邃洞扃抽自一天。", "殿古尚存唐歲月，地靈疑带漢風烟。", "斜陽欲趁歸樵路，倚杖更聽雲外泉。"]'),
('b64180a9-3a79-4114-97a8-8b2f34ef5cde','東華山','曾原一','宋','宋诗','song-poetry','','[]','行盡青山路，樓居傍石安。',48,'全唐诗/poet.song.214000.json','["行盡青山路，樓居傍石安。", "環雲疑世隔，彎沼倒涵山。", "瀑近晴如雨，巖深暑亦寒。", "道人弄刀鑷，怪我鬢毛斑。"]'),
('e6d4033a-e381-422b-be49-023cc86932b4','作歌咏蘇雲卿','曾原一','宋','宋诗','song-poetry','','[]','東湖湖面波渺瀰，東湖岸上春土肥。',256,'全唐诗/poet.song.214000.json','["東湖湖面波渺瀰，東湖岸上春土肥。", "先生鉏雲明月曉，種來蔬甲今成畦。", "把茅蕭蕭環四壁，此身不願人間識。", "乾坤清夷那復知，寸心杳渺黄塵隔。", "故人子房今九雲，交情不斷江湖濱。", "江西使漕却騶騎，故作敲門問字人。", "黄金百鎰牋一幅，多謝春風到茅屋。", "君爲使者吾邦民，見君容我更樵服。", "故人與我情重哉，君且歸矣明當來。", "明朝啟扉人不見，黄金不動書不開。", "使者持書三太息，封書徑上黄扉側。", "翩翩鶴馭雲冥冥，空向湖山訪行迹。", "向來桐江嚴子陵，曾得故人雙眼青。", "芒鞋却踏京華路，太史驚誇說客星。", "先生得書掉頭去，并此湖光不回顧。", "夢夫孀婦截髻鬟，亦有老大閨中女。"]'),
('d6a334b1-8839-42a2-9f60-3ef9f675757e','題賢女祠','曾原一','宋','宋诗','song-poetry','','[]','翻手作雲覆手雨，劉翁乃爾女如許。',160,'全唐诗/poet.song.214000.json','["翻手作雲覆手雨，劉翁乃爾女如許。", "飄飄上下隨春風，妾身肯似章臺絮。", "門前江水深更深，沈沈此水明妾心。", "後來志士爲感慨，過此往事成悲吟。", "嗟嗟許蔡復許吳，女吳絕蔡成二夫。", "此時哀淚苦幾諫，翁意或可還其初。", "吳家箱幣羅堂前，女兮脈脈胡不言。", "後來吳郎儻不死，清祠未必能江邊。", "女今賢明照天宇，翁也反覆聞千古。", "許吳之日回此天，女賢翁否俱無傳。"]'),
('2300a694-2289-469f-9560-d548029d39f9','題瘦馬歌','曾原一','宋','宋诗','song-poetry','','[]','少盡其力老棄之，可憐骨立行步遲。',64,'全唐诗/poet.song.214000.json','["少盡其力老棄之，可憐骨立行步遲。", "何心更惜乾障泥，病夫醉兀枯行枝。", "主家芻豆豈不飽，吾寧忍死不願肥。", "肥時無奈人爭騎，騎時鞭打無休時。"]'),
('ecbad862-ed85-4358-a7d0-730d33747fc7','寺中僑居','曾原一','宋','宋诗','song-poetry','','[]','懶出前山去，得閑唯訪僧。',48,'全唐诗/poet.song.214000.json','["懶出前山去，得閑唯訪僧。", "窗寒依瘦石，屋老絡枯藤。", "赴飯聽堂鼓，看書傍佛燈。", "西南有孤塔，扶杖亦時登。"]'),
('16b8c084-bb6b-4719-88aa-b344d944616b','句','曾原一','宋','宋诗','song-poetry','','[]','少陵忘却渾閑事，更有離騷忘却梅。',16,'全唐诗/poet.song.214000.json','["少陵忘却渾閑事，更有離騷忘却梅。"]'),
('b7472a30-317d-4eb1-9474-9016839823c0','游金精次韻','曾原郕','宋','宋诗','song-poetry','','[]','鯨奔獸駭羅羣峰，晴嵐溼霧深幾重。',224,'全唐诗/poet.song.214000.json','["鯨奔獸駭羅羣峰，晴嵐溼霧深幾重。", "世言番君勇穿石，此事荒唐敢云實。", "仙凡聚散那得知，祗今流水篆元之。", "沖昇壇在肯回顧，木鶴癡情飛不去。", "五詩遺筆寫元雲，殘碑記載心何勤。", "誰通一罅山前路，車馬塵埃了朝暮。", "劉郎想自天台來，步步錦繡連雲開。", "千崖萬壑玲瓏竅，今日重逢應一笑。", "蒼蒼石鼓青雲齊，名章合刻懸崖西。", "可憐一覺邯鄲炊，胸中五色蟠晴霓。", "此桃種在清虛處，不斷塵埃笑崔護。", "人世從教隔古今，洞府何從認新故。", "我髮白矣骨尚凡，悠悠空老茲山間。", "酌泉祈仙會當見，曾有麻姑訪王遠。"]'),
('dfc3165d-40e0-444c-99ff-59a077a98f25','萍','宋自遜','宋','宋诗','song-poetry','','[]','苦無根蒂逐波流，風約才稀雨復稠。',32,'全唐诗/poet.song.214000.json','["苦無根蒂逐波流，風約才稀雨復稠。", "舊說楊花能變此，是他種子亦輕浮。"]'),
('71ac5a41-b1e4-42c0-b514-aaf82247f5cf','桂花','宋自遜','宋','宋诗','song-poetry','','[]','揭紙糊窗莫放開，園丁新送木犀來。',64,'全唐诗/poet.song.214000.json','["揭紙糊窗莫放開，園丁新送木犀來。", "繞屏著色無非畫，盡日烘香不用煤。", "同氣相求唯徑菊，後生可畏獨江梅。", "月中一本應靈異，待向仙娥覓種栽。"]'),
('1a217140-c25f-4162-82c1-2788f7807075','五月菊','宋自遜','宋','宋诗','song-poetry','','[]','東籬千古屬重陽，此本偏宜夏日長。',32,'全唐诗/poet.song.214000.json','["東籬千古屬重陽，此本偏宜夏日長。", "會得淵明高卧意，故來同占北窗凉。"]'),
('c186e99a-b20e-47a3-8e48-2cd6d07ca5ef','種柳','宋自遜','宋','宋诗','song-poetry','','[]','短研深煨倒插宜，明年便有綠垂垂。',32,'全唐诗/poet.song.214000.json','["短研深煨倒插宜，明年便有綠垂垂。", "只因造化大容易，不見歲寒冰雪時。"]'),
('722fae42-87c0-4156-877c-3deab2e17829','夜雪','宋自遜','宋','宋诗','song-poetry','','[]','雪眼羞明夜轉飛，梅花未覺竹先知。',32,'全唐诗/poet.song.214000.json','["雪眼羞明夜轉飛，梅花未覺竹先知。", "一爐柴火三杯酒，誰記山陰有戴逵。"]'),
('dd8c4fe7-fb41-4e0e-8c3a-618966c478a0','茶磨','宋自遜','宋','宋诗','song-poetry','','[]','韞質他山带玉揮，乾旋坤載妙玄機。',64,'全唐诗/poet.song.214000.json','["韞質他山带玉揮，乾旋坤載妙玄機。", "轉時隠隠海風起，落處紛紛春雪飛。", "圓體外通常不礙，貞心中立動無違。", "世間多少槐安夢，信手頻推爲解圍。"]'),
('5d916d04-9d7a-44ff-adbb-a25acc9ca65c','蚊','宋自遜','宋','宋诗','song-poetry','','[]','朋比趨炎態度輕，禦人口給屢憎人。',32,'全唐诗/poet.song.214000.json','["朋比趨炎態度輕，禦人口給屢憎人。", "雖然暗裏能鑽刺，貪不知幾竟殺身。"]'),
('ec0f9343-cd39-4e49-8e1c-30bdc9092bc9','隠逸','宋自遜','宋','宋诗','song-poetry','','[]','五鼎生封事不難，此身當與道相關。',64,'全唐诗/poet.song.214000.json','["五鼎生封事不難，此身當與道相關。", "天高地下日易晚，古往今來人少閑。", "靖節早辭彭澤縣，子陵終老富春山。", "當時若爲虛名起，未必有名留世間。"]'),
('6913a973-903c-48f6-9165-0a897ec30236','蓮','宋自遜','宋','宋诗','song-poetry','','[]','採花莫掣葉，掣葉傷蓮根。',24,'全唐诗/poet.song.214000.json','["採花莫掣葉，掣葉傷蓮根。", "食子莫棄心，味苦生意存。"]'),
('8d2233ac-49c9-434b-9c85-943a2e8b6407','贈隠者','宋自遜','宋','宋诗','song-poetry','','[]','或居巖谷或居廛，未作天仙且地仙。',64,'全唐诗/poet.song.214000.json','["或居巖谷或居廛，未作天仙且地仙。", "詩只半聯人寡和，畫纔數筆世爭傳。", "彈琴無譜自成曲，賣藥資身不較錢。", "或問先生今幾歲，笑言誰解記生年。"]'),
('bc888c45-4bb8-40ef-9680-650a5f281bf2','贈戴石屏','宋自遜','宋','宋诗','song-poetry','','[]','又是六年別，渾無一字書。',48,'全唐诗/poet.song.214000.json','["又是六年別，渾無一字書。", "性寬難得老，交久只如初。", "白髮添詩集，黄金散酒壚。", "行程遍江海，何處是吾廬。"]'),
('67f443c1-65ee-4c24-85cb-210dbdbb1a7c','答客問','宋自遜','宋','宋诗','song-poetry','','[]','豈是林逋放鶴遲，習閑成懶靜相宜。',64,'全唐诗/poet.song.214000.json','["豈是林逋放鶴遲，習閑成懶靜相宜。", "落花時節人中酒，夜雨軒窗客賭棋。", "身外浮名何用覓，人間多事不須知。", "屋邊梅樹梅邊石，歲歲春風日日詩。"]'),
('97621de1-9397-4eb3-a989-db0766e48933','謝深道問近况答之','宋自遜','宋','宋诗','song-poetry','','[]','芃芃秋草閉門深，世事年來口欲瘖。',64,'全唐诗/poet.song.214000.json','["芃芃秋草閉門深，世事年來口欲瘖。", "文欠官銜誰著眼，命無時彩自勞心。", "收書祇願兒能讀，得酒惟須客共斟。", "幸有無絃琴掛壁，不容聲處是知音。"]'),
('27b1a738-5a26-4417-8a5e-90f53f1790fe','和曾子實題畫箋韻','宋自遜','宋','宋诗','song-poetry','','[]','鷺引歸船犬吠籬，片時風景萬千詩。',32,'全唐诗/poet.song.214000.json','["鷺引歸船犬吠籬，片時風景萬千詩。", "向來柳下曾沽酒，不似如今看畫時。"]'),
('f3cac85c-e91c-4a6c-a9a7-8bad8e814782','照鏡辭','宋自遜','宋','宋诗','song-poetry','','[]','匣中青鏡秋月明，妍嗤毫髮無遁形。',64,'全唐诗/poet.song.214000.json','["匣中青鏡秋月明，妍嗤毫髮無遁形。", "人心不同有如面，青銅照面不照心。", "人心本靈本虛靜，誰實昏之私欲勝。", "匣取青銅且勿開，自照心中大圓鏡。"]'),
('80073402-fccf-46cb-bf53-95d837917b9f','閑地','宋自遜','宋','宋诗','song-poetry','','[]','一片寬閑地，半生江海情。',48,'全唐诗/poet.song.214000.json','["一片寬閑地，半生江海情。", "有梅添月色，無竹欠秋聲。", "酒熱渾家醉，誠詩逐字評。", "拙疎塵事少，貧賤也身輕。"]'),
('a863a2af-dbdb-4cb7-90e0-3a378aaab8e1','店翁送花','宋自遜','宋','宋诗','song-poetry','','[]','店翁排日送春花，老去情懷感物華。',32,'全唐诗/poet.song.214000.json','["店翁排日送春花，老去情懷感物華。", "翁欲殷勤留客住，客因花惱轉思家。"]'),
('45fff9da-8bcd-4028-8f92-fd60745d5669','看人取木綿','宋自遜','宋','宋诗','song-poetry','','[]','綠楊有花飛作絮，黄蘆有花亦爲絮。',82,'全唐诗/poet.song.214000.json','["綠楊有花飛作絮，黄蘆有花亦爲絮。", "此絮天寒不可衣，但解隨風亂飛舞。", "木綿蒙茸入機杼，妙勝春蠶繭中縷。", "均爲世上一草木，有用無用廼如許。", "木綿有用稱者稀，楊花蘆花千古傳聲詩。"]'),
('af300e98-82ed-469b-b819-2c54beb4e445','烏鵲引','宋自遜','宋','宋诗','song-poetry','','[]','彼烏鵲兮，無異衆禽之鳴。',46,'全唐诗/poet.song.214000.json','["彼烏鵲兮，無異衆禽之鳴。", "吉凶在人兮，彼鳴何心。", "吁嗟人兮，萬物之靈。", "不能自信兮，占吉凶於二禽。"]'),
('79764429-3e29-46e6-b285-79cafb2419f7','啄木吟','宋自遜','宋','宋诗','song-poetry','','[]','志非啄木在啄蟲，利觜似染蟲血紅。',66,'全唐诗/poet.song.214000.json','["志非啄木在啄蟲，利觜似染蟲血紅。", "木外無蟲蟲在中，外視一啄殊不空。", "人嗟木皮遭囓毀，豈知蟲多木心死。", "木心無蠹木乃榮，安得去國之蠹如此觜。"]'),
('cc5008f7-ec20-41f0-ad48-5fb6313fcf59','買馬','宋自遜','宋','宋诗','song-poetry','','[]','世求駿馬事驅馳，我買人間鈍馬騎。',32,'全唐诗/poet.song.214000.json','["世求駿馬事驅馳，我買人間鈍馬騎。", "不是愛他行路穩，好山多處要尋詩。"]'),
('89029634-9424-4344-a970-86a1e278eaea','山家','宋自遜','宋','宋诗','song-poetry','','[]','一片青山水四圍，家家有竹護柴扉。',64,'全唐诗/poet.song.214000.json','["一片青山水四圍，家家有竹護柴扉。", "養成猿鶴通人語，放去牛羊識路歸。", "紫蕨甘肥輕鼎味，綠蓑安穩勝朝衣。", "浮雲遮斷人間事，浪說桃源今世稀。"]'),
('7bd2f143-03f7-42f1-b776-372eb8e5ffac','田家謠','宋自遜','宋','宋诗','song-poetry','','[]','清溪遶山流，茅屋瞰溪住。',168,'全唐诗/poet.song.214000.json','["清溪遶山流，茅屋瞰溪住。", "山田雖不多，荒年亦禾黍。", "有園不栽花，但種桑與苧。", "有兒只爲農，不士不商旅。", "老翁雪滿頭，煮茗相勞撫。", "問我從何來，今將去何所。", "日月如飛梭，人生幾寒暑。", "浮名底須求，求之亦何補。", "我見貪名人，名成隔千古。", "微利不足營，營之徒自苦。", "我見嗜利人，甘作守錢虜。", "青山塚纍纍，今古一抔土。", "勉我勤歸韉，風雪歲云暮。", "因作田家謠，備述老翁語。"]'),
('9cd16f40-085e-42fc-93e7-2553761ad25b','一室','宋自遜','宋','宋诗','song-poetry','','[]','一室冷如冰，梅花相對清。',48,'全唐诗/poet.song.214000.json','["一室冷如冰，梅花相對清。", "殘年日易晚，夾雪雨難晴。", "身計繭千緒，世紛棋一枰。", "麴生差解事，談笑破愁城。"]'),
('37325f25-5044-4b59-bb19-07af9e54fe57','書報先生壁','宋自遜','宋','宋诗','song-poetry','','[]','一盞清燈到夜深，掩書趺坐學禪心。',32,'全唐诗/poet.song.214000.json','["一盞清燈到夜深，掩書趺坐學禪心。", "山猿白日無蹤跡，夜夜來啼松樹林。"]'),
('329f201c-7699-43f8-9c59-b21af9589f5e','壽鐵石翁','宋自遜','宋','宋诗','song-poetry','','[]','梅傳春信伴持觥，壽數新年滿六庚。',64,'全唐诗/poet.song.214000.json','["梅傳春信伴持觥，壽數新年滿六庚。", "長與白雲分屋住，閒騎黄犢趁山行。", "不因問藥深深隠，除却能詩事事生。", "看到阿咸俱白髮，百年門戶共支撐。"]'),
('2b253b18-700a-4d3f-82dc-44d7c2f075d9','東湖看荷花呈愿父','宋自遜','宋','宋诗','song-poetry','','[]','團團隄路行無極，一株一步楊柳碧。',32,'全唐诗/poet.song.214000.json','["團團隄路行無極，一株一步楊柳碧。", "佳人反覆看荷花，自恨鬢邊簪不得。"]'),
('2bd81d81-3f04-4ba3-8227-d8999e75f00f','挽故知容州朝請陶公章','陳棨','宋','宋诗','song-poetry','','[]','靖節高風去千載，至今遺響在平塘。',64,'全唐诗/poet.song.214000.json','["靖節高風去千載，至今遺響在平塘。", "洗耳洗心甘綠野，濯纓濯足付滄浪。", "松間月色詩千首，竹裏棋聲酒幾觴。", "正受全歸無一欠，未爲公憾爲時傷。"]'),
('bb93c3e2-6991-441a-8c5c-7d29979035de','送胡彥龍過金陵','高彥竹','宋','宋诗','song-poetry','','[]','金陵往事已成虛，江水清清只見魚。',64,'全唐诗/poet.song.214000.json','["金陵往事已成虛，江水清清只見魚。", "遺廟空存元帝像，故家多有二王書。", "秋風出塞調生馬，夜月吟淮跨蹇馿。", "借問新亭諸老淚，而今煙景復何如。"]'),
('44a79ff7-9abf-444b-9353-c13a04462b86','寒夜','高彥竹','宋','宋诗','song-poetry','','[]','轆轤夢斷金梧井，夜月沉沉風露冷。',32,'全唐诗/poet.song.214000.json','["轆轤夢斷金梧井，夜月沉沉風露冷。", "起向庭中獨自行，伴人惟有梅花影。"]'),
('0dd105be-25b3-40a8-abe8-ac36cc159337','送廣帥趙平齋汝暨解印趨朝','李昴英','宋','宋诗','song-poetry','','[]','海瀕老同年，五載依宇下。',288,'全唐诗/poet.song.214000.json','["海瀕老同年，五載依宇下。", "春風舞簑笠，愛日曝田舍。", "喜無撞搪吏，追逐款段馬。", "劇談許絛褐，得趁公餘暇。", "達官來三逕，小隊隣翁詫。", "明公傑俊人，麟族稱大雅。", "典刑樣諸老，胸次郁醖藉。", "西派溯其源，境物入陶寫。", "才高事無難，隻手擘太華。", "乘軺始踰嶺，風采賢使者。", "堂堂開大閫，部屬肅鞾帕。", "臺端有老蜮，闖影含沙射。", "孤忠冕旒知，還許河內借。", "鈴齋安獨處，冷淡閑僧夏。", "例錢推不受，金貝視土苴。", "首祠酌泉翁，坐使饕俗化。", "葭萌細摩拊，生意被原野。", "循良渤海遂，平理潁川霸。", "威風戢偷竊，德意銷詭詐。", "能令颶母伏，默禱雨師灑。", "開倉散窮閭，儉歲低粒價。", "貢場宏敞拓，芘士千間厦。", "歷觀古賢牧，美政公其亞。", "讒夫真枉了，有識共唾駡。"]'),
('bd37cc31-0841-4261-b18c-69de872f2fcf','送荆門王廣文之官','李昴英','宋','宋诗','song-poetry','','[]','京都士如雲，一見知好修。',120,'全唐诗/poet.song.214000.json','["京都士如雲，一見知好修。", "未嘗廣文飯，已替肉食謀。", "炎門恥曳裾，漫郎肯從游。", "驚座吐倔奇，倚麈覺我羞。", "窮邊人憚之，長笑驅行舟。", "遠烽亂夕烟，戎馬驕高秋。", "清野空子衿，叢棘荒半流。", "此去欲何之，幕府應拔尤。", "吾道豈空談，取勝在一籌。", "獻馘早歸來，平步班瀛洲。"]'),
('64505869-c188-4fd4-b297-abc5aa578fab','久住白雲呈鎮長老','李昴英','宋','宋诗','song-poetry','','[]','桑下戒三宿，我此尚留戀。',96,'全唐诗/poet.song.214000.json','["桑下戒三宿，我此尚留戀。", "曹溪悟一宿，我復無知見。", "鎮公房遜客，所須如執券。", "園丁曉供茹，行者時灌硯。", "飯奴更蒭馬，紙帳費香篆。", "主人真好事，應答色無倦。", "欲歸興未闌，欲住面有靦。", "飛錫肯三逕，亦有伊蒲饌。"]'),
('47e93b6a-e059-485a-b418-b35f9902132e','遊峽山和東坡韻','李昴英','宋','宋诗','song-poetry','','[]','雙虬挾泓玉，奧入百轉灣。',96,'全唐诗/poet.song.214000.json','["雙虬挾泓玉，奧入百轉灣。", "向無長公詩，草木今何顔。", "此山二百年，偃蹇客往還。", "長風駕余舟，老人急開關。", "逢迎欠高僧，喜有識面山。", "平生癖幽壑，便合茅三間。", "君命何敢留，歸棹隨賜還。", "慚愧和光翁，笑指青童鬟。"]'),
('62c67f0a-c08e-4b5e-aeac-814ebc0b394e','酌別張子元二首  其一','李昴英','宋','宋诗','song-poetry','','[]','去冬初去國，逆旅等順境。',120,'全唐诗/poet.song.214000.json','["去冬初去國，逆旅等順境。", "禍機衆危之，沙蜮伺人影。", "拂衣肯同歸，荒驛燈夜永。", "幸脫妖蟇口，黑月重磨鏡。", "勤君再行役，我愧心耿耿。", "陛下皇明穹，賢聚纖邪屏。", "石渠盛此士，豈復松廳冷。", "胸中貯奇策，可以靖邊警。", "平生羞轅駒，看取囊露穎。", "堂堂曲江翁，芳躅在梅嶺。"]'),
('07d12ea6-2b7d-4d0a-863a-4ea045191077','酌別張子元二首  其二','李昴英','宋','宋诗','song-poetry','','[]','南士如君幾，妙處方寸境。',120,'全唐诗/poet.song.214000.json','["南士如君幾，妙處方寸境。", "撐腸五千卷，落筆擅三影。", "喜談狂朱雲，恥作諛谷永。", "憂時點髭雪，未肯疎鑷鏡。", "摩挲匣中龍，起視斗牛耿。", "每同畫灰語，寒夜僮僕屏。", "吾儕期歲晏，世俗任炎冷。", "江亭揮別酒，謔笑鬭機警。", "景文兄弟情，畝異禾同穎。", "日邊多便驛，頻書來越嶺。"]'),
('b21b32de-69cd-49d7-8063-7c841be76ff1','重九遊鬰孤臺和座客韻','李昴英','宋','宋诗','song-poetry','','[]','座上多俊人，奇掘角拔犀。',144,'全唐诗/poet.song.214000.json','["座上多俊人，奇掘角拔犀。", "追風飆館游，鼉鳴玉龍嘶。", "夕陽催歸鞭，更酌樽重携。", "懷開鉤鉤簾，語合印印泥。", "似與花神期，拈出糕字題。", "壯哉千尺臺，虎踞譙之西。", "枰中十萬家，一目城市低。", "乘風巾可橋，取月箸可梯。", "豪氣壓崆峒，雙月照虹溪。", "響山慨懷古，妙句吾家雞。", "邦人趁遨頭，壺榼山之蹊。", "最喜秋事成，千畝黄雲齊。"]'),
('c66af2e8-e2bc-4eda-a3b7-11e567fe4877','是日至馬祖巖和前韻','李昴英','宋','宋诗','song-poetry','','[]','九秋天地香，贛産饒木犀。',144,'全唐诗/poet.song.214000.json','["九秋天地香，贛産饒木犀。", "登高詣其巔，風健戲馬嘶。", "偷得一日閑，古錦奚奴携。", "秋陽閣霏雨，飛蓋換障泥。", "舉揚馬祖禪，拂摩老坡題。", "菊萸勸人飲，猛吞玉東西。", "凭闌視九州，莽蒼烟水低。", "如何昌黎翁，華嶺須縛梯。", "野性淡無嗜，所樂惟山溪。", "每羞名利區，得失爭蟲雞。", "意行契真趣，荒苔踏成蹊。", "嘉辰且盡歡，聚散或不齊。"]'),
('07827d43-df75-4744-a7e3-026da39d6e69','肇慶府倅王庚應平反廣府帥司冤獄詩以紀其事','李昴英','宋','宋诗','song-poetry','','[]','人生天地間，本是同胞出。',288,'全唐诗/poet.song.214000.json','["人生天地間，本是同胞出。", "貴賤與賢愚，分殊而理一。", "上帝立君師，朝廷設官職。", "凡百有司存，各欲盡其責。", "一或無人心，何以順天則。", "廣南十四州，官吏幾滿百。", "公道孰扶持，田野多菜色。", "大桀作威福，小桀肆蝥賊。", "周興而爪牙，郄超而賓客。", "君祿君忍欺，天民天弗恤。", "貪饕事篚苞，殘忍尚徽纆。", "可憐田舍翁，駢首膏斧鑕。", "可憐富家兒，鞭背遭黥墨。", "怒氣劇炎火，讒言易轉石。", "恩門甘仰面，墦間爭屈膝。", "喑啞一世人，天高雲霧黑。", "豈無賢大夫，留此一綫脈。", "堂堂西蜀翁，憤氣填胸臆。", "尚友周濂溪，拙矣謀身策。", "念我同胞人，罹此操戈厄。", "苦語爲平反，片言天可質。", "細閲拙錄篇，事事皆陰隲。", "孟子謂非人，由其無隠惻。", "此翁仁者勇，姦諛誅以筆。"]'),
('d4faa835-feb5-478b-a777-086cc8444dc6','苦秋暑引','李昴英','宋','宋诗','song-poetry','','[]','商金久得柄，老火未退舍。',120,'全唐诗/poet.song.214000.json','["商金久得柄，老火未退舍。", "甑中著寰宇，赫酷甚於夏。", "池湯頗殃魚，田龜應害稼。", "桃笙亦漿汗，水國無凉榭。", "扇揮腕欲脫，忍渴畏杯斝。", "樹間寂秋聲，矩令何時下。", "四序本循環，寒暑相代謝。", "炎炎推不去，誰與詰造化。", "人思濯清泠，風露願一借。", "再拜祈蓐收，西陸早命駕。"]'),
('afa77588-c591-474b-a766-8596235c30f9','觀入試者','李昴英','宋','宋诗','song-poetry','','[]','鐘撼雞鳴萬家起，月下紛紛白袍子。',224,'全唐诗/poet.song.214000.json','["鐘撼雞鳴萬家起，月下紛紛白袍子。", "提壺挈榼春遊閙，擎箱擐篋誰家徙。", "通衢隘塞行人絕，露坐欠伸奴跛倚。", "遠聞雷譟轟應答，近亦洶洶殊聒耳。", "軋然棘戶破曉色，陣脚忽移去如蟻。", "壯夫先入護几案，儒雅雍容行且止。", "垂髫趁鬨未知苦，戴白相持歎衰矣。", "自從明詔到郡國，士出深山集城市。", "但能操筆不曳白，秋榜人人都準擬。", "分明結社戰所兵，投合主司誰得髓。", "昨科試人今或亡，三年場屋能消幾。", "功名信分置勿言，身健頻來已堪喜。", "槐黄早脫吾僥倖，因送兒曹得觀視。", "傍人休笑李秀才，三十年前亦如此。"]'),
('a0f97571-94a7-439b-ab57-0e38a24e49e8','再用觀入試韻','李昴英','宋','宋诗','song-poetry','','[]','涵育累朝士興起，薄海絃歌爭教子。',224,'全唐诗/poet.song.214000.json','["涵育累朝士興起，薄海絃歌爭教子。", "籯金世守韋一經，俎豆少成孟三徙。", "盡從科舉梯進取，鶴髮望深門日倚。", "藝先德後已非古，心術乖違徒口耳。", "天門髣髴馮爲馬，陰德却關橋度蟻。", "時來乳臭亦觀光，潦倒英雄頻坎止。", "棘闈投卷姑應之，桂籍題名先定矣。", "可憐數千困眊氉，僅二十人誇利市。", "近歲詞場尚剽拾，文體腐陳難古擬。", "倩人者幸耘人貪，氣習陋汙淪骨髓。", "主司頭腦易冬烘，日色不迷世能幾。", "所憂程文悞後學，豈但升沉繫悲喜。", "他人愛子亦如我，何敢庸心秦越視。", "願言通榜皆實才，如己得之無彼此。"]'),
('71d66ffb-a2eb-4dfb-980b-bd45809a8831','送梁伯隆歸丹谷舊隠','李昴英','宋','宋诗','song-poetry','','[]','昔人入山訪隠君，每恨見山不見人。',212,'全唐诗/poet.song.214000.json','["昔人入山訪隠君，每恨見山不見人。", "子持畫圖走踆踆，人雖可即山非真。", "自言谷中萬修筠，泉鳴琮琤石嶙峋。", "誰甘混跡麋鹿群，雅意遠遊闊見聞。", "飛筇遂過南海瀕，翻海一洗征衣塵。", "東望絕域天無垠，藥洲風月蒲澗雲。", "間出奇語頗自珍，奚囊十襲而三熏。", "槿花猩血荔錦紋，何如故圃桃李春。", "江湖社友杯十分，何如族聚情話親。", "行路之難多酸辛，還家火急埋車輪。", "拂拭磯苔開徑榛，畹蘭籬菊庭古椿。", "贈篇滿篋不療貧，幾人煉藥能輕身。", "本分荷鋤驅犢西疇耘，武夷山下擊壤爲堯民。"]'),
('d84713bc-fa75-41a4-b6c7-172904311218','羅浮何君祐夫相訪惠詩又出所作水墨魚戲題卷末','李昴英','宋','宋诗','song-poetry','','[]','山頭釣引千鈞魚，鐵橋曾逢稚川奴。',147,'全唐诗/poet.song.214000.json','["山頭釣引千鈞魚，鐵橋曾逢稚川奴。", "風波平地誤點額，戲取墨汁翻糢糊。", "縱觀濠上契妙趣，浩浩胸次涵江湖。", "墨雲忽從硯池起，撥剌跳出形模殊。", "大魚騰驤撼風雨，小魚瑣碎游荇蒲。", "技如元放幾許奇，金盤一箇松江鱸。", "試張亭前漲波影，舂鋤飛下傍睢盱。", "世間畫史少活筆，描寫終類鮒肆枯。", "文溪一灣浮釣徒，欠得龍眠爲嚴瀨羊裘圖。"]'),
('32479d80-ae80-493e-a86c-8efc33b4b4bd','三山亭','李昴英','宋','宋诗','song-poetry','','[]','山中招提鼎足踞，路如丁字分頭入。',96,'全唐诗/poet.song.214000.json','["山中招提鼎足踞，路如丁字分頭入。", "遠看港汊紛長繩，俯見阜丘纔小笠。", "班荆坐僕縱之息，爭解綠荷撮紅粒。", "羣然飲澗忽喧噪，石兀深叢疑虎立。", "我起胡床劃孤嘯，前峰響答松風急。", "舉頭雲端尚天半，搘竹扳蘿進千級。"]'),
('4d72cae2-d363-4d68-91c3-d6f213053e1e','題石室木','李昴英','宋','宋诗','song-poetry','','[]','似屈纔伸蛇解蟄，似斷還連龍蛻骨。',50,'全唐诗/poet.song.214000.json','["似屈纔伸蛇解蟄，似斷還連龍蛻骨。", "天河失却古槎橜，落在人間撐突兀。", "若非胸中磊塊灑澆出，老死畫工無此筆。"]'),
('9981670b-2519-45b5-b582-1d964095c87e','題東坡竹','李昴英','宋','宋诗','song-poetry','','[]','葉葉枝枝各標致，密密疎疎總風味。',50,'全唐诗/poet.song.214000.json','["葉葉枝枝各標致，密密疎疎總風味。", "筆爲化工壁爲地，頃刻種成此君子。", "雖然月影水影寫真似，安得千年尚生意。"]'),
('3665440a-314c-4749-ba27-238897e6cbe9','河南掃松訪古勝寺不遇主僧','李昴英','宋','宋诗','song-poetry','','[]','主僧走城磨馿兒，廊僧閉門縮頭龜。',64,'全唐诗/poet.song.214000.json','["主僧走城磨馿兒，廊僧閉門縮頭龜。", "長髮行者披鶉衣，瀹我苦茗行相隨。", "禪床破簟客自展，急呼蒼頭揮大扇。", "卧到夕陽暑力軟，歸趁潮平柁流轉。"]'),
('78ce7393-c9e2-4481-9f3e-ffa8267d3ebf','送鄭雪屋歸里','李昴英','宋','宋诗','song-poetry','','[]','征衣點落紅，君去與春同。',48,'全唐诗/poet.song.214000.json','["征衣點落紅，君去與春同。", "貧到歸時見，吟多醉後工。", "不應冠尚鶡，自許氣如虹。", "急著看山眼，飛帆吸快風。"]'),
('5b020459-119a-4422-a4ef-ceedcc91eb15','送連推黄端簡赴班','李昴英','宋','宋诗','song-poetry','','[]','別我谷之盤，今誰似二難。',48,'全唐诗/poet.song.214000.json','["別我谷之盤，今誰似二難。", "西江詩種好，南斗劍光寒。", "千里依蓮重，三年食蘗安。", "頭班人品稱，春意暖征鞍。"]'),
('3695b7c3-70e9-4d17-8451-abe870eefd7f','武夷觀','李昴英','宋','宋诗','song-poetry','','[]','閑乘石罅船，又到浙江邊。',48,'全唐诗/poet.song.214000.json','["閑乘石罅船，又到浙江邊。", "回向初心地，皈依古洞天。", "成丹呼鶴舞，噴酒起龍眠。", "雨意偏留客，杯茶定宿緣。"]'),
('3d449d38-2f40-47fe-b06d-4aef90ac1c39','建倉解歸詩復徐意一二首  其一','李昴英','宋','宋诗','song-poetry','','[]','恨未澄清盡，孤蹤己不安。',48,'全唐诗/poet.song.214000.json','["恨未澄清盡，孤蹤己不安。", "繆悠臣罪大，感激上恩寬。", "鄉國三千里，人心百八盤。", "夢歸今始驗，爲我謝言官。"]'),
('e6500f30-521d-4014-9c42-0dfc364da4a7','建倉解歸詩復徐意一二首  其二','李昴英','宋','宋诗','song-poetry','','[]','吏擎雙印出，便覺此身輕。',48,'全唐诗/poet.song.214000.json','["吏擎雙印出，便覺此身輕。", "物我忘恩怨，漁樵寄姓名。", "笛聲黄犢背，詩興白鷗盟。", "故舊休相訝，無書到帝城。"]'),
('d346d26c-6cfd-445f-b241-f192a28b19b4','題雪峰因大夢頂相','李昴英','宋','宋诗','song-poetry','','[]','終朝咬菜根，那得許精神。',48,'全唐诗/poet.song.214000.json','["終朝咬菜根，那得許精神。", "自笑形爲贅，從渠畫不真。", "閑雲留片影，活佛化千身。", "大夢何時覺，癡人問木人。"]'),
('0f4e89fa-bb54-4454-95a6-88086d353a34','贈始興順首座','李昴英','宋','宋诗','song-poetry','','["\u897f\u6e56"]','江湖三十載，敗笠破袈裟。',48,'全唐诗/poet.song.214000.json','["江湖三十載，敗笠破袈裟。", "老面阿羅漢，全身小釋迦。", "定無牛犯稼，不見鳥銜花。", "一笑西湖上，相逢且喫茶。"]'),
('f5ae0694-9b6a-477b-8ca4-ad7e3ab4fcc9','景泰寺','李昴英','宋','宋诗','song-poetry','','[]','樹合疑山盡，攀緣有路通。',48,'全唐诗/poet.song.214000.json','["樹合疑山盡，攀緣有路通。", "遠鴉追夕照，低雁壓西風。", "瀑勢雷虛壑，松聲浪半空。", "凭欄僧指似，漲霧是城中。"]'),
('4e6c5dbb-bdbb-4518-9589-be2556dc0853','挽鈍齋先生許象州三首  其一','李昴英','宋','宋诗','song-poetry','','[]','家學存齋授，淵源自晦菴。',48,'全唐诗/poet.song.214000.json','["家學存齋授，淵源自晦菴。", "魁文行海內，師道重天南。", "銜未冰條一，州纔刀夢三。", "芳名却千載，俎豆拜祠龕。"]'),
('907e84ca-e2b0-4ca3-a458-6c8517fec78a','挽鈍齋先生許象州三首  其二','李昴英','宋','宋诗','song-poetry','','[]','義重人誰及，高風有古人。',48,'全唐诗/poet.song.214000.json','["義重人誰及，高風有古人。", "己田分友子，黎事保羈臣。", "抱負耕莘志，依稀陋巷仁。", "丹青遺像在，難寫道心真。"]'),
('98bff5d5-6dec-4c91-8a34-f758bb26b77a','挽鈍齋先生許象州三首  其三','李昴英','宋','宋诗','song-poetry','','[]','丈席即之溫，終身佩一言。',48,'全唐诗/poet.song.214000.json','["丈席即之溫，終身佩一言。", "棟樑失安定，山斗慘韓門。", "慟矣心喪重，凄然手澤存。", "江聲助悲些，莫返大夫魂。"]'),
('6aca3a94-1282-4285-8e93-5abbf512f378','白雲山見五色雀','李昴英','宋','宋诗','song-poetry','','[]','羅浮禽五色，創見此山椒。',48,'全唐诗/poet.song.214000.json','["羅浮禽五色，創見此山椒。", "錦羽嬉同墜，鐵冠遷最喬。", "疑隨仙馭過，喜趁白雲招。", "貴客非關我，勞渠千里遥。"]'),
('76546d78-467f-47cf-b89e-0a280ffb9085','送梁上舍必得大學解試','李昴英','宋','宋诗','song-poetry','','[]','南國去天遠，行程勿滯留。',48,'全唐诗/poet.song.214000.json','["南國去天遠，行程勿滯留。", "試期催負笈，戰决勝焚舟。", "澹墨題金榜，英聲起璧流。", "旦評期望久，著力在毫頭。"]'),
('640195e3-a1af-4b9b-97d5-7e80aed9d543','用前韻送潘上舍','李昴英','宋','宋诗','song-poetry','','[]','謙爲賢業址，取履卜封留。',48,'全唐诗/poet.song.214000.json','["謙爲賢業址，取履卜封留。", "筆下千鈞弩，胸中萬斛舟。", "椿庭聞誨語，米廩友名流。", "連捷歸藍綬，鄰翁好話頭。"]'),
('823ed1d5-4291-453c-8ba0-972f1aece059','挽如老歸真','李昴英','宋','宋诗','song-poetry','','[]','不見纔三日，喧傳已坐亡。',48,'全唐诗/poet.song.214000.json','["不見纔三日，喧傳已坐亡。", "平生功行到，垂絕偈言香。", "緣分無高剎，禪名却四方。", "開包殘藁在，切勿放毫光。"]'),
('1ec3a2b6-15d9-4f95-bd81-c7643f380300','送葉耆卿試太學','李昴英','宋','宋诗','song-poetry','','[]','背城贏一戰，璧水是儒林。',48,'全唐诗/poet.song.214000.json','["背城贏一戰，璧水是儒林。", "詞賦八叉手，功名寸鐵心。", "程兼馳數驛，學苦惜分陰。", "清獻起庚戌，長風送捷音。"]'),
('3c280f5c-a87e-4b2e-bc24-d99fe25c0462','觀穫','李昴英','宋','宋诗','song-poetry','','[]','負郭平田闊，秋深穫課勤。',48,'全唐诗/poet.song.214000.json','["負郭平田闊，秋深穫課勤。", "短鎌行缺月，多稼剪黄雲。", "舊臘占三白，今年稔十分。", "太平村舍裏，墮穗飽雞群。"]'),
('e253feb2-0202-446c-93bd-cfe6eeefbdbd','山行','李昴英','宋','宋诗','song-poetry','','[]','塵中事日生，撥剔且山行。',48,'全唐诗/poet.song.214000.json','["塵中事日生，撥剔且山行。", "襆被欣然出，登車趣便清。", "奴收携蠟屐，客請带棋枰。", "纔過城闉外，耳根無市聲。"]'),
('ce9e3ecd-ac08-48fc-be8a-39e79c4261ce','後峒月溪寺','李昴英','宋','宋诗','song-poetry','','[]','寺巧蟠山背，池圓印寺前。',48,'全唐诗/poet.song.214000.json','["寺巧蟠山背，池圓印寺前。", "連筒泉落罋，如鏡地無磚。", "茗苦苛留客，僧淳懶說禪。", "使君期不至，一宿笑無緣。"]'),
('f1ed60ac-1c53-4306-bd21-491202c069db','樵者','李昴英','宋','宋诗','song-poetry','','[]','近道其樵者，勞哉食束薪。',48,'全唐诗/poet.song.214000.json','["近道其樵者，勞哉食束薪。", "運斤碎盤錯，荷擔下嶙峋。", "恐是仙王質，何須貴買臣。", "路傍迎一笑，笑我絆簪紳。"]'),
('a801f9cd-7efe-4735-a702-a7a3d4120fe4','雲泉亭','李昴英','宋','宋诗','song-poetry','','[]','絕頂鬰其前，寒崖噴玉泉。',48,'全唐诗/poet.song.214000.json','["絕頂鬰其前，寒崖噴玉泉。", "亭成山補闕，境勝我攙先。", "樹杪江天接，榕根石磴懸。", "賞心遂連日，合爲智仙傳。"]'),
('a20e4876-38c8-455d-a1ca-2fdac11f7716','哭清遠權宰樓海司法二首  其一','李昴英','宋','宋诗','song-poetry','','[]','諭賊散私財，冥頑不可囘。',48,'全唐诗/poet.song.214000.json','["諭賊散私財，冥頑不可囘。", "憤然瞋目駡，吾已戴頭來。", "一死當凶刃，千家免劫灰。", "遺孤元未有，行路爲悲哀。"]'),
('0e563984-85db-4d8f-a0b9-de9abc0f00e3','哭清遠權宰樓海司法二首  其二','李昴英','宋','宋诗','song-poetry','','[]','百里稱廉吏，誰歟起釁端。',48,'全唐诗/poet.song.214000.json','["百里稱廉吏，誰歟起釁端。", "州符需賦急，軍餉及期難。", "節義扶澆俗，朝廷贈大官。", "邑人崇廟像，猶似髮衝冠。"]'),
('1542c578-c381-404b-967f-7ebaa7e1291d','送陳大雷試太學','李昴英','宋','宋诗','song-poetry','','[]','裹糧數千里，賈勇萬人場。',48,'全唐诗/poet.song.214000.json','["裹糧數千里，賈勇萬人場。", "庾嶺琴書去，橋門姓字香。", "有司應眼具，喜氣已眉黄。", "踐履宜天相，時文况所長。"]'),
('c9b7a0fe-dd8c-4d15-9b37-02f3e6f12802','悼花首湛長老二首  其一','李昴英','宋','宋诗','song-poetry','','[]','碧眸泓鐵面，跣足衲懸鶉。',48,'全唐诗/poet.song.214000.json','["碧眸泓鐵面，跣足衲懸鶉。", "數日蒲團定，一如泥塑人。", "施錢隨散擲，忍辱已忘嗔。", "丁字何曾識，拈提話轉新。"]'),
('e6209048-c5ab-4a67-bdc1-1974c59f004d','悼花首湛長老二首  其二','李昴英','宋','宋诗','song-poetry','','[]','別我笑吟吟，羅浮願力深。',48,'全唐诗/poet.song.214000.json','["別我笑吟吟，羅浮願力深。", "空拳餬衆口，平地起叢林。", "山迥孤雲沒，溪寒片月沉。", "人今奇坐蛻，在日孰知音。"]'),
('51973a07-4056-4f1a-bbc6-8ffd1582feff','飲赴解試士友二首  其一','李昴英','宋','宋诗','song-poetry','','[]','座滿挺時髦，經明亦富豪。',48,'全唐诗/poet.song.214000.json','["座滿挺時髦，經明亦富豪。", "幾年勤用志，三日健揮毫。", "笑取刀牛角，相逢酒蟹螯。", "有名還有分，秋鶚碧雲高。"]'),
('e073988f-9ba2-4660-b05c-05eb67a3fbf1','飲赴解試士友二首  其二','李昴英','宋','宋诗','song-poetry','','[]','少日諳場屋，斯文爲細論。',48,'全唐诗/poet.song.215000.json','["少日諳場屋，斯文爲細論。", "艱深成札闥，卑弱又西崑。", "與客爲佳讖，當年是解元。", "賀詩多辦取，盛事屬于門。"]'),
('a3cb4326-1582-4409-a22b-3c4aa0b07448','山寺夜起看月','李昴英','宋','宋诗','song-poetry','','[]','丙夜忽窗白，披衣起凭欄。',48,'全唐诗/poet.song.215000.json','["丙夜忽窗白，披衣起凭欄。", "山川如晝見，松檜照人寒。", "孤鶴欬屋脊，群僧鼾紙單。", "燈前呼老佛，妙境許同觀。"]'),
('76f4f3cd-b8e9-4154-a3b8-7da348511523','看僧披剃','李昴英','宋','宋诗','song-poetry','','[]','爾教言無相，誰教蛻髮毛。',48,'全唐诗/poet.song.215000.json','["爾教言無相，誰教蛻髮毛。", "虛名猶度牒，多事更方袍。", "父認師傳的，年推戒臘高。", "冠巾何不可，只要斷塵勞。"]'),
('ef5431ec-8d8a-44eb-a4d5-4fbae390ac56','挽右史方鐵菴詩三首  其一','李昴英','宋','宋诗','song-poetry','','[]','一疏綱常重，端平起直聲。',48,'全唐诗/poet.song.215000.json','["一疏綱常重，端平起直聲。", "難磨石宋璟，不動鐵元城。", "前輩風流在，南州箇信誠。", "精神兼學力，傾倒爲遐氓。"]'),
('ae5fee3d-5b5f-46ee-87c1-269650a56dc0','挽右史方鐵菴詩三首  其二','李昴英','宋','宋诗','song-poetry','','[]','喜怒皆和氣，天全一片春。',48,'全唐诗/poet.song.215000.json','["喜怒皆和氣，天全一片春。", "眼高多識士，心直不疑人。", "稱得深衣古，爭傳判筆神。", "恙微談笑去，忽失玉璘珣。"]'),
('6fb12065-531c-451f-8acc-f36904592c9c','挽右史方鐵菴詩三首  其三','李昴英','宋','宋诗','song-poetry','','[]','紙錢森插竹，遺像在方橋。',48,'全唐诗/poet.song.215000.json','["紙錢森插竹，遺像在方橋。", "月暗甘棠密，風嘶韓木喬。", "所悲緣瘁國，於誼况同朝。", "凄斷黄灣路，丹旌些莫招。"]'),
('b357d8d2-914c-4b8a-a3ac-12cee97831d9','觀定堂','李昴英','宋','宋诗','song-poetry','','[]','梵宮凭水建，蓬荻費芟除。',72,'全唐诗/poet.song.215000.json','["梵宮凭水建，蓬荻費芟除。", "岸破群魚出，枝危獨鶴居。", "定鐘僧睡早，揮麈客談虛。", "月滿龕燈小，風停幡影疎。", "供盤多佛菓，僧飯飽園蔬。", "惟有開山老，清高閉草廬。"]'),
('4082041d-08f5-4d3c-9023-a566ab8d0f01','送高禮部不妄知嚴州','李昴英','宋','宋诗','song-poetry','','[]','從來直氣勁摩空，又吐忠嘉忤九重。',64,'全唐诗/poet.song.215000.json','["從來直氣勁摩空，又吐忠嘉忤九重。", "指斥分明人所忌，去留諄複上能容。", "清風慨慕桐江釣，異渥新疏竹使筒。", "熊軾一行聊復爾，羽儀禁路要夔龍。"]'),
('b3c8ce85-d3bf-4bf4-905d-67830ab053da','別陳霆','李昴英','宋','宋诗','song-poetry','','[]','政喜論文子遽歸，扶胥之口訪韓碑。',64,'全唐诗/poet.song.215000.json','["政喜論文子遽歸，扶胥之口訪韓碑。", "吟篇佳處南游得，行李輕如始至時。", "石友秉心終可托，鐵翁具眼遠相期。", "勉旃辦取蘭闈捷，四六供官且放遲。"]'),
('442466e3-e383-4293-b7e1-de018500237d','美廣帥趙平齋拓貢院','李昴英','宋','宋诗','song-poetry','','[]','圍棘千間手拓開，帥幢元是箇中來。',64,'全唐诗/poet.song.215000.json','["圍棘千間手拓開，帥幢元是箇中來。", "前峰卓卓尖如筆，正路堂堂穩踏槐。", "自此鵠袍容萬士，渾然龍化出倫魁。", "南州盡說明年好，依舊科名得上台。"]'),
('bb54b767-f575-4f91-bdd8-04c67785fba1','送循倅黄必昌之官','李昴英','宋','宋诗','song-poetry','','[]','好風佳月說龍川，人喜新來別乘賢。',64,'全唐诗/poet.song.215000.json','["好風佳月說龍川，人喜新來別乘賢。", "才儘優爲千里式，學今有用四書全。", "黄門祠下揮吟筆，丞相嶺頭先著鞭。", "莫但俛眉銜紙尾，忍教田里苦顛連。"]'),
('91a56d0b-8dd5-47ac-8008-cf1aeb6afce3','白雲登閣','李昴英','宋','宋诗','song-poetry','','[]','白雲捧擁到危巔，傑閣翬飛倚半天。',64,'全唐诗/poet.song.215000.json','["白雲捧擁到危巔，傑閣翬飛倚半天。", "谷響頗疑吟木客，潮囘坐見變桑田。", "幾重山隔幾重海，一日身閑一日僊。", "真樂無如會心處，林花野鳥亦欣然。"]'),
('1f876745-543f-46f5-8753-da34ef3990b0','雲關觀月','李昴英','宋','宋诗','song-poetry','','[]','山間未晚先得月，料想城中見較遲。',64,'全唐诗/poet.song.215000.json','["山間未晚先得月，料想城中見較遲。", "海吐銀蟾漸呈露，林垂翠影早參差。", "孤輪涵澗安禪處，明鏡當空沉籟時。", "夜半衰翁猶獨坐，清光吸盡入詩脾。"]'),
('da8b11bf-d904-4e71-9ef7-4cec16c60ad5','登峽山疾風甚雨','李昴英','宋','宋诗','song-poetry','','[]','長風吹裂碧雲堆，捲取銀河瀉下來。',64,'全唐诗/poet.song.215000.json','["長風吹裂碧雲堆，捲取銀河瀉下來。", "雨攪犀潭千尺浪，煙遮龍窟一聲雷。", "松翁偃蓋巖隈立，猿女穿蘿洞裏囘。", "舊事蘭亭好拈出，婆娑溪曲共流杯。"]'),
('7f3380a2-8d4e-4fa3-b36f-c6af4faab089','峽山飛來殿','李昴英','宋','宋诗','song-poetry','','[]','龍門鑿破碧天池，呈佛高峰插翠微。',64,'全唐诗/poet.song.215000.json','["龍門鑿破碧天池，呈佛高峰插翠微。", "對岸鐘聲猶隠耳，御風簷角尚如翬。", "二神擇地非著相，雙錫騰空向上機。", "此境世間如更有，安知古殿不重飛。"]'),
('b31a7896-a1ac-45dc-9310-9970fddd0cfc','峽山全清閣','李昴英','宋','宋诗','song-poetry','','[]','無塵明鏡太玲瓏，匣向周遭紫翠中。',64,'全唐诗/poet.song.215000.json','["無塵明鏡太玲瓏，匣向周遭紫翠中。", "地有仙家雲母石，天然上界水晶宮。", "通宵如晝溪頭月，盛夏回秋竹罅風。", "萬斛客愁都盪盡，一杯聖酒畫欄東。"]'),
('ddaee201-b94c-4adb-a814-74b46840c68f','同劉朔齋游白雲寺二首  其一','李昴英','宋','宋诗','song-poetry','','[]','衝暑登高人所憚，雲韓龍孟樂相從。',64,'全唐诗/poet.song.215000.json','["衝暑登高人所憚，雲韓龍孟樂相從。", "眼窮溟海九萬里，身在蓬萊第一峰。", "潮長嶼低帆勢急，山迴路曲樹陰重。", "日斜移席臨池飲，戲掬清泉解酒容。"]'),
('f1147173-134e-4f5c-ba25-e0a84db3cb38','同劉朔齋游白雲寺二首  其二','李昴英','宋','宋诗','song-poetry','','[]','勘破禪家最上關，掀髯朗笑響千山。',64,'全唐诗/poet.song.215000.json','["勘破禪家最上關，掀髯朗笑響千山。", "海門正湧冰輪出，昏鼓先催玉節還。", "獨上層巔風浩蕩，歸沿小澗石孱顔。", "尋幽本是閑人事，聊復分君半日閑。"]'),
('69e36123-3d11-4d56-bc2b-f30814ceaf2e','送張子元班見','李昴英','宋','宋诗','song-poetry','','[]','笑掇巍科是管君，等閑馬上換京官。',64,'全唐诗/poet.song.215000.json','["笑掇巍科是管君，等閑馬上換京官。", "扶摇九萬從今易，植立千年自古難。", "多辦衣裘禦風雪，緊操維柁過瀧灘。", "中朝知舊如相問，試把吟篇舉似看。"]'),
('9205fe2b-65a3-4c3b-b102-991b5dcb5ecb','和廣帥宋自牧勸駕韻','李昴英','宋','宋诗','song-poetry','','[]','天將造榜放秋晴，南國新逢運會亨。',64,'全唐诗/poet.song.215000.json','["天將造榜放秋晴，南國新逢運會亨。", "障礙洞開來試者，計偕穩送上華京。", "主人况是梅花宋，寓客漸非日色程。", "面見河南已分曉，佇聆魁捷響仙城。"]'),
('cf7e97ef-c357-4c9c-b7eb-7d5ca0fd0beb','西樵巖','李昴英','宋','宋诗','song-poetry','','[]','巨石卷阿駕半天，樵山風景豈虛傳。',64,'全唐诗/poet.song.215000.json','["巨石卷阿駕半天，樵山風景豈虛傳。", "水簾不捲四時雨，丹竈空凝萬古烟。", "印石尚存烏利跡，問誰曾識紫姑仙。", "我來遊遍登雲谷，更借山僧半榻眠。"]'),
('0221e970-c22e-43b8-807e-2e505f49c03d','送都運陳煒以煩言去','李昴英','宋','宋诗','song-poetry','','[]','鐵漢從來去就輕，當年烏府樹風聲。',64,'全唐诗/poet.song.215000.json','["鐵漢從來去就輕，當年烏府樹風聲。", "福星臨分人安樂，濁世如泥志潔清。", "祠命忽傳姦吏賀，歸裝絕少擔夫驚。", "退菴本愜家林興，父老攀轅却有情。"]'),
('0f4a9488-f644-464e-934f-01c8b3157712','碧霄','李昴英','宋','宋诗','song-poetry','','[]','未到白雲先碧霄，瘦藤支我上山腰。',64,'全唐诗/poet.song.215000.json','["未到白雲先碧霄，瘦藤支我上山腰。", "煙橫遠樹醉眸豁，竹引清泉塵慮澆。", "酒滴松根和露飲，茶烹石鼎抱茅燒。", "平生不被利名鎖，半掩柴扉聽晚樵。"]'),
('dbe70cbc-8613-4676-a969-c5d43e613d3e','送李尉興龍之海豐任','李昴英','宋','宋诗','song-poetry','','[]','書味無窮得屬厭，待瓜六載不辭淹。',64,'全唐诗/poet.song.215000.json','["書味無窮得屬厭，待瓜六載不辭淹。", "乃心雅欲親諸老，初筮惟知守一廉。", "毋縱彎弓獵雞犬，謹防暴客起魚鹽。", "同鄉同姓鍾情處，酌別中秋吸玉蟾。"]'),
('e538e78c-0c5a-45db-aad8-7547e609c287','送舶使孫叔諧東歸','李昴英','宋','宋诗','song-poetry','','[]','蓴鱸高興趁新秋，帆腹吞風湧去舟。',64,'全唐诗/poet.song.215000.json','["蓴鱸高興趁新秋，帆腹吞風湧去舟。", "萬寶集登天子庫，諸蠻遮泣海山樓。", "世間顛倒是非夢，達者逍遥得失侯。", "歸到家林定重九，團欒杯酒菊花浮。"]'),
('e284286c-cc5c-4cb3-b89e-d41d33975369','宴鳴珮亭和趙漕韻','李昴英','宋','宋诗','song-poetry','','[]','數尺飛泉漏隔城，寒巖坳處落琮琤。',64,'全唐诗/poet.song.215000.json','["數尺飛泉漏隔城，寒巖坳處落琮琤。", "懸知勝境無塵到，却訝晴天作雨聲。", "一歃不容貪者飲，兩峰宜著醉翁行。", "此泉千載因人重，曾識光風霽月清。"]'),
('93da1434-b436-4b3a-b49e-b624744b4af7','送三舉人','李昴英','宋','宋诗','song-poetry','','[]','銅蟾滴硯不曾晴，命到通時文乃亨。',64,'全唐诗/poet.song.215000.json','["銅蟾滴硯不曾晴，命到通時文乃亨。", "善射定知楊破的，力耕必穫稼如京。", "錦旗門巷誇聯薦，椽筆春闈又中程。", "擢第三人如下問，定將四字語元城。"]'),
('154bdd6d-96f9-4581-9fbd-99083b9955d1','贛學鄉飲禮成二首  其一','李昴英','宋','宋诗','song-poetry','','[]','風化之原出泮芹，飲循儀禮豆籩陳。',64,'全唐诗/poet.song.215000.json','["風化之原出泮芹，飲循儀禮豆籩陳。", "國中推擇爵齒德，堂上獻酬介僎賓。", "主一敬存容自肅，歌三樂備意相親。", "粲然應接非觀美，所望今人樣古人。"]'),
('c3845eec-2185-4c93-8af5-275a16b329de','贛學鄉飲禮成二首  其二','李昴英','宋','宋诗','song-poetry','','[]','無譁觀者也深衣，古典如迂效頗奇。',64,'全唐诗/poet.song.215000.json','["無譁觀者也深衣，古典如迂效頗奇。", "放出曦輪行事日，飛來捷幟序賓時。", "俎陽便覺春流暢，拜爵潛教俗轉移。", "此禮重行應易易，邦人耳目熟威儀。"]'),
('a684c900-c601-4973-b785-5bbf99d8bbc1','送子先賢歸南海','李昴英','宋','宋诗','song-poetry','','[]','束書相伴到江西，我尚濡留子遽歸。',64,'全唐诗/poet.song.215000.json','["束書相伴到江西，我尚濡留子遽歸。", "輪角難生催別斝，刀頭欲折爲斑衣。", "功名有分須如意，學問無窮更造微。", "若到家林遇奴輩，先教拂拭釣魚磯。"]'),
('021fc137-4f23-4e61-b9e0-ecef7ebff1ac','寄贈竹隠李聘君','李昴英','宋','宋诗','song-poetry','','[]','圓沙有此隠君子，短褐枯筇自一丘。',64,'全唐诗/poet.song.215000.json','["圓沙有此隠君子，短褐枯筇自一丘。", "安樂窩中寬宇宙，逍遥游處眇公侯。", "逢人皆喜一無忤，於世何求百不憂。", "種德已深天必報，大兒玉立最清修。"]'),
('d6c9f292-d124-467e-af85-e52731535e49','同劉朔齋游蒲澗謁菊坡祠','李昴英','宋','宋诗','song-poetry','','[]','曉隨絲轡飯僧坊，丞相祠堂一瓣香。',64,'全唐诗/poet.song.215000.json','["曉隨絲轡飯僧坊，丞相祠堂一瓣香。", "試問神仙蒲九節，何如名德菊孤芳。", "高山仰止堪模楷，百世聞之尚激昂。", "我輩此來深有意，豈專泉石癖膏肓。"]'),
('ca3394ac-618f-4b45-bdaa-26753e721f6f','蒲澗滴水巖觀瀑','李昴英','宋','宋诗','song-poetry','','[]','與可人游五四并，快風吹面洗炎蒸。',64,'全唐诗/poet.song.215000.json','["與可人游五四并，快風吹面洗炎蒸。", "鹿巡夾道千章木，猿掛垂崖百尺藤。", "石室橫琴清振玉，壺瓢酌水冷調冰。", "瀑簾雨後籠山闊，不許塵埃俗耳聽。"]'),
('c4c725c1-e245-4de0-b031-6820d65532de','送鑒師住靈洲寺','李昴英','宋','宋诗','song-poetry','','[]','少年芹泮也儒冠，底事緇袍染異端。',64,'全唐诗/poet.song.215000.json','["少年芹泮也儒冠，底事緇袍染異端。", "孤島一燈開佛屋，長身七尺占僧單。", "鐘鳴魚叩隨緣過，棹舞鷗飛取次看。", "亭下聽經黿在否，石欄摇影碧波寒。"]'),
('b100ae27-e039-45a2-a540-3633b01ee148','贈海珠湛老','李昴英','宋','宋诗','song-poetry','','[]','也曾勘破到風幡，坐得形枯鬢早斑。',64,'全唐诗/poet.song.215000.json','["也曾勘破到風幡，坐得形枯鬢早斑。", "衲子指爲真鐵漢，江神幻出小金山。", "華亭浪急翻船入，葱嶺雲深挈履還。", "香燼未寒行道處，蕭森翠竹護禪關。"]'),
('898f4bd4-86da-46bb-8daa-b022713c0667','送廣東憲陳均二首  其一','李昴英','宋','宋诗','song-poetry','','[]','十五年間再繡衣，幡然一出浩然歸。',64,'全唐诗/poet.song.215000.json','["十五年間再繡衣，幡然一出浩然歸。", "囹空但欲全人命，網打誰能避禍機。", "壬巧交攻邪害正，丁錢奏免是成非。", "離亭父老遮如堵，莫駐春江去棹飛。"]'),
('28b9403a-af2f-42ae-ba29-bf7b439ce5d1','送廣東憲陳均二首  其二','李昴英','宋','宋诗','song-poetry','','[]','我如越雪致狺狺，此事牽連亦到君。',64,'全唐诗/poet.song.215000.json','["我如越雪致狺狺，此事牽連亦到君。", "久矣浮名等蠻觸，付之公論定蕕薰。", "四知誰不推楊震，三已何曾損子文。", "甚欲一行陪祖帳，萬山遥隔幾重雲。"]'),
('a02cf518-7405-42f1-960c-09faaea4e5d2','黄士奇沿檄送其雙親歸閩以詩送之','李昴英','宋','宋诗','song-poetry','','[]','佳哉茂士頗圓機，頻到蕭齋對麈揮。',64,'全唐诗/poet.song.215000.json','["佳哉茂士頗圓機，頻到蕭齋對麈揮。", "官長見知因職業，人生最樂有庭闈。", "東山至寶身當惜，伯玉中年力去非。", "一事說來真可敬，來裝罄矣貸金歸。"]'),
('b0b48a55-73e4-430b-b08d-9b6711532c58','贈曾士倬用許廣文韻','李昴英','宋','宋诗','song-poetry','','[]','里閈如君苦績文，幾年良玉困炎崑。',64,'全唐诗/poet.song.215000.json','["里閈如君苦績文，幾年良玉困炎崑。", "鶚書快甚催隨計，鶴髮忻然慰倚門。", "袍綠光華應分有，汗青久遠要名存。", "江頭目送西行棹，驚起驪龍渴睡昏。"]'),
('ccff4f47-8eec-4bc7-b202-7f5418b7811f','送演姪三首  其一','李昴英','宋','宋诗','song-poetry','','[]','少年政要識艱難，受國恩深早一官。',64,'全唐诗/poet.song.215000.json','["少年政要識艱難，受國恩深早一官。", "著力莫孤先世望，從頭細把四書看。", "金蘭益友真同志，菽水慈親曲盡歡。", "學取老夫窮意思，免教人指袴繻紈。"]'),
('7f96846a-dd0a-43a1-85c0-c0d582f3341f','送演姪三首  其二','李昴英','宋','宋诗','song-poetry','','[]','五常百行異其名，腔子源頭一箇誠。',64,'全唐诗/poet.song.215000.json','["五常百行異其名，腔子源頭一箇誠。", "數馬似愚寧過謹，懸魚雖矯却真清。", "寬和愛衆衆同愛，驕倨輕人人所輕。", "詩好何如勳業好，旂常元不載詩聲。"]'),
('80f4e754-ab6d-41ad-94c0-90811a91a5ec','送演姪三首  其三','李昴英','宋','宋诗','song-poetry','','[]','一同休戚尉相關，肉食那容職曠瘝。',64,'全唐诗/poet.song.215000.json','["一同休戚尉相關，肉食那容職曠瘝。", "驗視難真防木刻，追擒易誤戒弓彎。", "千尋樹看萌芽始，萬里行從跬步間。", "大抵窮通皆定分，炎門邪徑莫躋攀。"]'),
('d1c4c1df-b0f2-4c70-bb52-31fc12a068cf','子先宗友試蘭省送以小詩','李昴英','宋','宋诗','song-poetry','','[]','毫端五色織成章，皎皎清標月照梁。',64,'全唐诗/poet.song.215000.json','["毫端五色織成章，皎皎清標月照梁。", "再戰文場推定霸，一經書法首尊王。", "鞭揚庾嶺梅花早，梯上寒宮桂籍香。", "師道自居吾豈敢，所期竹帛遠流芳。"]'),
('34d79fe5-d5c5-410d-8ec8-ce8a4f79c351','北山證果寺','李昴英','宋','宋诗','song-poetry','','[]','久聞北寺最清幽，因看花田遂一游。',64,'全唐诗/poet.song.215000.json','["久聞北寺最清幽，因看花田遂一游。", "近國好山半煙雨，參天喬木幾春秋。", "香凝永晝添談柄，風送長松爽茗甌。", "此境今纔逢我輩，不留詩去鶴猿羞。"]'),
('23047cf6-6d16-4c5e-b719-cd2412fdc28e','羅浮國醮','李昴英','宋','宋诗','song-poetry','','[]','霓氅蹁躚拜玉宸，發揮道德五千文。',64,'全唐诗/poet.song.215000.json','["霓氅蹁躚拜玉宸，發揮道德五千文。", "步虛夜半千山月，朝斗空中五色雲。", "風雨若時昌國運，乾坤齊壽祝吾君。", "賢侯方寸精誠積，散作豐湖叶氣薰。"]'),
('120b0fa8-f333-4645-a7ed-90d7961f36e8','羅浮飛雲頂','李昴英','宋','宋诗','song-poetry','','[]','山行頗覺思悠然，游遍仙家幾洞天。',64,'全唐诗/poet.song.215000.json','["山行頗覺思悠然，游遍仙家幾洞天。", "登見日亭風刮面，立飛雲頂月齊肩。", "稚川翁有燒丹竈，景泰師留卓錫泉。", "我得真人金石訣，無求自可享長年。"]'),
('c311638f-7dcc-40ac-8d43-9575804a83e3','羅浮峒長寶谷王寧素送藥瓢','李昴英','宋','宋诗','song-poetry','','[]','久矣深山煉鶴形，聞呼峒長又逃名。',64,'全唐诗/poet.song.215000.json','["久矣深山煉鶴形，聞呼峒長又逃名。", "斷崖怪木人稀跡，亂石奔泉澗有聲。", "劍定通神收古匣，棋聊供玩戲紋枰。", "藥瓢解贈寧無意，重到孤菴論養生。"]'),
('7aa39c15-3410-4f00-a32c-31114c6a4ee9','贈雲峰演菴主','李昴英','宋','宋诗','song-poetry','','[]','一菴移向白雲堆，檜柏參天少日栽。',64,'全唐诗/poet.song.215000.json','["一菴移向白雲堆，檜柏參天少日栽。", "頗怪髮如金線樣，想曾眼見鐵橋來。", "佛粘土壁煎茶供，客對蒲團取芋煨。", "却笑老盧懷鉢走，只因說出鏡非臺。"]'),
('0707a6f9-7df4-4a46-9aa8-2423decc76a7','題羅浮沖虛觀化緣疏','李昴英','宋','宋诗','song-poetry','','[]','仙去千年重此山，不禁風雨屋摧殘。',64,'全唐诗/poet.song.215000.json','["仙去千年重此山，不禁風雨屋摧殘。", "金能點化空談易，錢欠通神著力難。", "支厦終非一木了，成裘未免衆毛攢。", "洞天有分人人到，輪奐峨嵯起筆端。"]'),
('19cf8afd-36eb-484d-9633-a87e186f8151','送湛師回羅浮花首山','李昴英','宋','宋诗','song-poetry','','[]','翩然拂袖忽然囘，带得羅浮面目來。',64,'全唐诗/poet.song.215000.json','["翩然拂袖忽然囘，带得羅浮面目來。", "乞食又還雙足繭，坐禪豈是寸心灰。", "故依花首從三靖，旋摘茶芽供一杯。", "蘭若苦空君不厭，可能爲我掃蒼苔。"]'),
('0672ccf6-65c1-42c3-8238-79e0636cfea2','秋試已近用韻勉兒輩','李昴英','宋','宋诗','song-poetry','','[]','鄴軸輪囷數世藏，乃翁曾讀被龍光。',64,'全唐诗/poet.song.215000.json','["鄴軸輪囷數世藏，乃翁曾讀被龍光。", "詩書有種芥拾紫，科舉催人槐落黄。", "學到自然名盛大，文工更要理深長。", "歲當酉戌吾家旺，月府先教竇桂香。"]'),
('5457aa85-faa2-404e-95ae-f911aed473fc','送黄提幹赴班','李昴英','宋','宋诗','song-poetry','','[]','不枉金閨貯一賢，唱名重見冕旒前。',64,'全唐诗/poet.song.215000.json','["不枉金閨貯一賢，唱名重見冕旒前。", "省闈見說第三賦，選調猶遲十八年。", "據實語人南嶠事，無多行李浙江船。", "壺山群彥官今緊，直諒如今合茹連。"]'),
('a64d3287-9072-4938-a910-87eb6c3ca719','送恩平潛使君還里二首  其一','李昴英','宋','宋诗','song-poetry','','[]','風流太守作春遊，到處恩波浩蕩流。',64,'全唐诗/poet.song.215000.json','["風流太守作春遊，到處恩波浩蕩流。", "懷綬故鄉需上日，移舟別浦趁中秋。", "聲歌洋溢行人口，書翰縱橫健筆頭。", "識面雖新心頗熟，殷勤話別送歸舟。"]'),
('5051d0eb-0250-4b21-8968-229f589e9492','送恩平潛使君還里二首  其二','李昴英','宋','宋诗','song-poetry','','[]','五載南州屈重名，活人一段是歸程。',64,'全唐诗/poet.song.215000.json','["五載南州屈重名，活人一段是歸程。", "兩州曾喚兩蘇起，孤節要師孤竹清。", "合有鋒車催赴闕，不應畫戟又專城。", "閑身已决深山底，千里猶能共月明。"]'),
('c79f25ec-9b1a-4b24-ad0f-cae23fe0fe93','壽張新班','李昴英','宋','宋诗','song-poetry','','[]','喜氣稜稜肖紫巖，向來石燕毓奇男。',64,'全唐诗/poet.song.215000.json','["喜氣稜稜肖紫巖，向來石燕毓奇男。", "九十入相今纔半，七日爲人恰後三。", "籍濕金閨穹地步，椒香玉斝盎春酣。", "赤松須待功名遂，蒲澗清泉墨菊潭。"]'),
('6f48bb3b-2696-4d1e-97c2-c15c32c63a44','送次兒解試','李昴英','宋','宋诗','song-poetry','','[]','四度牋名達帝聰，布衣便有此遭逢。',64,'全唐诗/poet.song.215000.json','["四度牋名達帝聰，布衣便有此遭逢。", "吾家積慶爲心印，一戰收功在筆鋒。", "舉子頭場關薦鶚，時文手段要屠龍。", "庭前手植森森桂，飛捷今秋好事重。"]'),
('06b30486-8e58-45b4-aa24-a24106a329ff','紀事保林尉韻','李昴英','宋','宋诗','song-poetry','','[]','清晨風日闢群陰，一紙三熏上帝臨。',64,'全唐诗/poet.song.215000.json','["清晨風日闢群陰，一紙三熏上帝臨。", "或者貪功頻滑手，毅然奮筆特誅心。", "冤辭頼有由言折，聖世難施漢法沉。", "此舉豈謀身禍福，祗憐無罪縶南音。"]'),
('dc2c712a-5e9e-49ca-bc94-3b2c9fbc78e3','聞褫閣職免新任之報二首  其一','李昴英','宋','宋诗','song-poetry','','[]','遠民冤甚草菅芟，抗論公庭出至諴。',64,'全唐诗/poet.song.215000.json','["遠民冤甚草菅芟，抗論公庭出至諴。", "且喜一方全性命，何妨三字減頭銜。", "機關平地藏深穽，仕宦伶人視戲衫。", "五遜州符今免矣，幅巾藜杖可松杉。"]'),
('b1cad052-85ea-455f-bfa1-c6440b97c4de','聞褫閣職免新任之報二首  其二','李昴英','宋','宋诗','song-poetry','','[]','狂妄孤臣罪有餘，三年三度掛丹書。',64,'全唐诗/poet.song.215000.json','["狂妄孤臣罪有餘，三年三度掛丹書。", "群兒過計愁郎罷，外物浮名總子虛。", "只是儒酸真面目，不題道號混樵漁。", "親朋欲語澆教醉，休與時人定毀譽。"]'),
('f5e303e1-d02e-4c4a-b5ac-1deb5b7a42bb','送族子春叟游西廣','李昴英','宋','宋诗','song-poetry','','[]','鳳出丹山定九苞，桂林要揀一枝巢。',64,'全唐诗/poet.song.215000.json','["鳳出丹山定九苞，桂林要揀一枝巢。", "久聞巖竇須幽討，不是豪人莫汎交。", "鶴髮頻將安問寄，螢窗勤把舊書抄。", "功名到底還堅志，崛起新豐一草茅。"]'),
('caad7b5e-01ec-49c0-b410-cb859148b7ca','後峒月溪寺','李昴英','宋','宋诗','song-poetry','','[]','森森杉檜鬰相繆，散策何妨逐勝游。',64,'全唐诗/poet.song.215000.json','["森森杉檜鬰相繆，散策何妨逐勝游。", "梵宇莊嚴傳浙樣，碧池蕩漾納泉流。", "將軍贏得山林在，衲子多因粥飯留。", "眼界雖云欠軒豁，晚凉宜酒且夷猶。"]'),
('6fdaf2ae-089d-40cb-a4ea-5a8bf6e10aef','送荃翁張端義之惠陽','李昴英','宋','宋诗','song-poetry','','["\u592a\u6e56"]','吹面東風豎綠簑，詩翁七十醉婆娑。',64,'全唐诗/poet.song.215000.json','["吹面東風豎綠簑，詩翁七十醉婆娑。", "放懷自號天隨子，知我無如春夢婆。", "吟有小奚磨破硯，卧看赤脚踏行窩。", "太湖爭似黄灣闊，高浪粘天獨笑過。"]'),
('e2e5c4be-26de-4e35-a474-fe7cceb9961b','即席和人韻送荃翁','李昴英','宋','宋诗','song-poetry','','[]','詩似油翁背注油，知音世有幾荆州。',64,'全唐诗/poet.song.215000.json','["詩似油翁背注油，知音世有幾荆州。", "乍寒乍暖方榆火，無米無錢只葉舟。", "客况可堪今老大，人生何必盡封侯。", "津亭且莫匆匆去，萬斛春醪任拍浮。"]'),
('a689c474-3a81-45a9-b871-b457734e8c9d','送李路鈐萬入京','李昴英','宋','宋诗','song-poetry','','[]','運厄南州暴吏專，鶡冠却有好官員。',64,'全唐诗/poet.song.215000.json','["運厄南州暴吏專，鶡冠却有好官員。", "捕猺怕損平人命，製錦盡除常例錢。", "枘鑿一言辭辟郡，胸襟三略合籌邊。", "景文匹馬長相過，我愧才非玉局仙。"]'),
('7ec5a44f-17af-42a5-9c9d-cc97b9fe90ab','和心字韻送林尉公琰校文','李昴英','宋','宋诗','song-poetry','','[]','鵠袍忙立老槐陰，爭望文星早照臨。',64,'全唐诗/poet.song.215000.json','["鵠袍忙立老槐陰，爭望文星早照臨。", "稱物衡無高下手，別形鑑有是非心。", "品題豈逐朱衣轉，沙汰何妨苦海沉。", "將見賢書協輿論，真才到此遇知音。"]'),
('03610a18-0bbb-4f42-9706-1cae010a0a17','蒲澗和東坡韻','李昴英','宋','宋诗','song-poetry','','[]','四時冰柱濕風前，絕頂飛來一派泉。',64,'全唐诗/poet.song.215000.json','["四時冰柱濕風前，絕頂飛來一派泉。", "瘦蔓相牽根太古，蒼崖特立探長天。", "竈荒孤鶴尋遺跡，寺老幽禽闖坐禪。", "閑日頻游歸復夢，結廬曾許躡坡僊。"]'),
('6dd2dd64-47ed-4855-b036-2a1f496a49e5','蒲澗山行宿景泰呈諸友人','李昴英','宋','宋诗','song-poetry','','[]','蒲根採得汎金船，滴水巖前且地僊。',64,'全唐诗/poet.song.215000.json','["蒲根採得汎金船，滴水巖前且地僊。", "造物添支閑歲月，上恩不與好山川。", "意行芳草迷丹竈，旋摘新芽撥澗泉。", "欲雨還晴便登覽，更消一宿白雲巔。"]'),
('2b8bb32b-81f1-425a-8abd-2182279dd5ef','四月十五游僧寺','李昴英','宋','宋诗','song-poetry','','[]','今日快逢僧結夏，不妨乘興扣禪扉。',64,'全唐诗/poet.song.215000.json','["今日快逢僧結夏，不妨乘興扣禪扉。", "山垂遠瀑溪聲急，風捲癡雲雨脚稀。", "囊錦詩成僧借看，紋楸棋落鳥驚飛。", "此來莫訝凭欄久，傑閣新成拂翠微。"]'),
('cfbe81fc-9fb4-44f9-b53f-29d6461df135','代送丘漕迪嚞','李昴英','宋','宋诗','song-poetry','','[]','假帥如公自古無，邦人久矣望鋒車。',64,'全唐诗/poet.song.215000.json','["假帥如公自古無，邦人久矣望鋒車。", "政聲難掩諸公說，明主周知萬里餘。", "豹尾雞翹那欠此，蓴羹鱸鱠且歸歟。", "江頭鼓動江船去，喜氣歡聲動里閭。"]'),
('2f0e47e0-c282-4a00-904d-a292b25151f8','用人韻送梅糾梁現','李昴英','宋','宋诗','song-poetry','','[]','征鞍風軟踏香塵，又送斯人南海瀕。',64,'全唐诗/poet.song.215000.json','["征鞍風軟踏香塵，又送斯人南海瀕。", "糾郡正資賓畫重，洗冤須放筆頭春。", "勉期聖處功夫到，肯學世間兒女顰。", "五瘴由心今一洗，笑渠辟瘴嚼人頻。"]'),
('d764c0ef-f928-4e40-9e60-27d1b5b90e08','送舶使周申','李昴英','宋','宋诗','song-poetry','','[]','堂堂山立舊朝簪，久屈清流督獻琛。',64,'全唐诗/poet.song.215000.json','["堂堂山立舊朝簪，久屈清流督獻琛。", "風趕連艘出獅國，浪吹殘句到雞林。", "平生不隔同年面，中歲難禁惜別心。", "歸見耆英定相問，只言閉戶萬山深。"]'),
('6eacfb10-857f-46e5-ae06-b884be5c70c0','贈宋省元巍薦經義','李昴英','宋','宋诗','song-poetry','','[]','傑作傳來見一班，少年筆力老孱顔。',64,'全唐诗/poet.song.215000.json','["傑作傳來見一班，少年筆力老孱顔。", "根源有學皆堪味，首尾無瑕孰敢刪。", "工要前篇人易取，說須兩段意相關。", "森森天骨晶光縹，去必軒騰十二閑。"]'),
('4349d382-77f8-4ee4-9aa2-95219c73e70a','八月驟寒','李昴英','宋','宋诗','song-poetry','','[]','秋欲中分暑更袢，金風崛起便成寒。',64,'全唐诗/poet.song.215000.json','["秋欲中分暑更袢，金風崛起便成寒。", "桃笙夜展猶嫌執，狐向朝披便怯單。", "翻手炎凉真可笑，循環造化果無端。", "老來一任添霜縷，寒暑難磨只寸丹。"]'),
('fe06f02d-f092-48ef-82b7-2bb3c01986e0','中秋無月','李昴英','宋','宋诗','song-poetry','','[]','已孤前度一中秋，滿望今宵月下游。',64,'全唐诗/poet.song.215000.json','["已孤前度一中秋，滿望今宵月下游。", "藥杵放閑靈兔懶，鏡奩掩却素娥愁。", "知誰有術擎梯取，枉費當年弄斧修。", "天靳清明每如此，樽前休恨翳雲浮。"]'),
('d3c039ae-de69-45ca-93f7-d9eea525c99c','示兒用許廣文韻','李昴英','宋','宋诗','song-poetry','','[]','斐然狂簡不知非，席帽何時免誚譏。',64,'全唐诗/poet.song.215000.json','["斐然狂簡不知非，席帽何時免誚譏。", "官樣詞章惟典雅，心腔理義要深幾。", "各隨鵬鷃高低適，一笑雞蟲得失微。", "偶未成名兒勿恨，我方追悔蹈文闈。"]'),
('e615f9c7-9cb3-4067-b917-be895fca9af9','鑒空閣','李昴英','宋','宋诗','song-poetry','','[]','鑒空閣上賞僧軒，祇樹深開不二門。',64,'全唐诗/poet.song.215000.json','["鑒空閣上賞僧軒，祇樹深開不二門。", "一水橫流界平野，數峰突起補前村。", "舟來舟去人多事，潮落潮生岸有痕。", "鎮日長閒輸老衲，倚筇獨坐古榕根。"]'),
('525431d4-b662-4204-9571-ec4b7f6b872f','建寧解歸寄雪峰因大夢','李昴英','宋','宋诗','song-poetry','','[]','行脚今朝又起單，欣然歸去得安閑。',32,'全唐诗/poet.song.215000.json','["行脚今朝又起單，欣然歸去得安閑。", "從前大夢難忘處，上白雲山望雪山。"]'),
('63ba8623-4259-406e-af66-f66f0cd3271b','弋陽鄭氏翠麓亭','李昴英','宋','宋诗','song-poetry','','[]','管領寒溪揖怪峰，徑穿鉅竹綠陰濃。',32,'全唐诗/poet.song.215000.json','["管領寒溪揖怪峰，徑穿鉅竹綠陰濃。", "幽人去後無猿鶴，冷落亭臺濕蘚封。"]'),
('d34e683f-5fa2-45fd-8df6-7996142e6789','羅浮梁彌僊游爛柯山贈以曲筇方笠','李昴英','宋','宋诗','song-poetry','','[]','葛坡龍竹東坡笠，合伴山人到洞天。',32,'全唐诗/poet.song.215000.json','["葛坡龍竹東坡笠，合伴山人到洞天。", "柯爛想應留斧在，憑君試問石橋仙。"]'),
('8befe6c6-d851-4a6a-84e0-fb2872bfb77b','過嚴子陵釣臺','李昴英','宋','宋诗','song-poetry','','[]','船重祗因將利去，船輕又恐爲名來。',32,'全唐诗/poet.song.215000.json','["船重祗因將利去，船輕又恐爲名來。", "如今羞見先生面，夜半撐船過釣臺。"]'),
('ea36f058-9e83-49fd-a219-1f13d59f8bf4','勸梁青霞歸羅浮舊隠','李昴英','宋','宋诗','song-poetry','','[]','逍遥八極片雲浮，所過名山不久留。',32,'全唐诗/poet.song.215000.json','["逍遥八極片雲浮，所過名山不久留。", "依舊片雲歸石峒，從今休更下山游。"]'),
('31c359ab-cdcc-4e83-81b6-2cf54638f52a','南華寺五首  其一','李昴英','宋','宋诗','song-poetry','','[]','誦經聽得入從門，壁上偷他四偈言。',32,'全唐诗/poet.song.215000.json','["誦經聽得入從門，壁上偷他四偈言。", "畢竟單傳端的處，賣薪供母是心源。"]'),
('3bbf32d2-04ae-4935-bc9a-e84898262474','南華寺五首  其二','李昴英','宋','宋诗','song-poetry','','[]','西方骨董南方寶，留鎮曹溪幾百年。',32,'全唐诗/poet.song.215000.json','["西方骨董南方寶，留鎮曹溪幾百年。", "自是後人當不得，有如翁者亦單傳。"]'),
('b8bb525a-d242-401e-9462-e1c03f9e0691','南華寺五首  其三','李昴英','宋','宋诗','song-poetry','','[]','從前梵說墮虛空，獨有壇經說不同。',32,'全唐诗/poet.song.215000.json','["從前梵說墮虛空，獨有壇經說不同。", "體用圓明皆寶相，一丁不識却心通。"]'),
('75d4e948-a7ce-4ce1-8e60-fa2031fc0349','南華寺五首  其四','李昴英','宋','宋诗','song-poetry','','[]','未參五祖已開山，合下全身此地安。',32,'全唐诗/poet.song.215000.json','["未參五祖已開山，合下全身此地安。", "不是香烟忘故里，衣留孔道要人看。"]'),
('b36d2f6e-226d-4369-955f-8e28d6329458','南華寺五首  其五','李昴英','宋','宋诗','song-poetry','','[]','清者何曾飲盜泉，僧盂底飯逆巢田。',32,'全唐诗/poet.song.215000.json','["清者何曾飲盜泉，僧盂底飯逆巢田。", "此疑欲問師無語，風撼長松嘯半天。"]'),
('659675bd-1f69-438d-ba63-88333a9fec1f','雨行梅關二首  其一','李昴英','宋','宋诗','song-poetry','','[]','濃嵐四合凍雲癡，水墨連屏鬭崛奇。',32,'全唐诗/poet.song.215000.json','["濃嵐四合凍雲癡，水墨連屏鬭崛奇。", "衝雨此行風景別，滿山翠滴水簾垂。"]'),
('a43d29ac-ae6e-4155-9f65-00f0f4fe8606','雨行梅關二首  其二','李昴英','宋','宋诗','song-poetry','','[]','通宵雨滴急催梅，枝北枝南曉盡開。',32,'全唐诗/poet.song.215000.json','["通宵雨滴急催梅，枝北枝南曉盡開。", "多謝花神好看客，隨車十里雪香來。"]'),
('f1e87d91-c8d7-4b31-8712-3e7913fb265a','雪封寺二首  其一','李昴英','宋','宋诗','song-poetry','','[]','鑿通危石張文獻，勘破禪關盧祖師。',32,'全唐诗/poet.song.215000.json','["鑿通危石張文獻，勘破禪關盧祖師。", "奇事已堪誇北客，梅花先暖亦南枝。"]'),
('feaca1f9-20d1-4a8b-b552-ee322a5c0085','雪封寺二首  其二','李昴英','宋','宋诗','song-poetry','','[]','征輿六月度梅關，大地清凉樹影班。',32,'全唐诗/poet.song.215000.json','["征輿六月度梅關，大地清凉樹影班。", "行客不須梅止渴，流泉到耳冷潺潺。"]'),
('e0f96996-6b4e-4dfc-82ce-ee217bc1316e','峽山詩','李昴英','宋','宋诗','song-poetry','','[]','山通一水逕皇都，多少英豪出此途。',32,'全唐诗/poet.song.215000.json','["山通一水逕皇都，多少英豪出此途。", "傳我飛來元羽翼，好風吹送過天衢。"]'),
('07c5572d-17f1-42fa-9bc4-561b1803f07e','靈洲','李昴英','宋','宋诗','song-poetry','','[]','眼前無限往來舟，射利干名不肯休。',32,'全唐诗/poet.song.215000.json','["眼前無限往來舟，射利干名不肯休。", "少見人心如此寺，屹然砥柱在中流。"]'),
('74cdd12a-2d44-4aeb-8373-42ae3df95ca3','池州溪橋','李昴英','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','萬里長江吸一盃，等閑袖劍九華來。',32,'全唐诗/poet.song.215000.json','["萬里長江吸一盃，等閑袖劍九華來。", "溪橋獨坐無人識，又駕長風跨鶴回。"]'),
('bf30b228-9492-4795-ad14-c1fecc07875b','迎廣帥徐意一大參五首  其一','李昴英','宋','宋诗','song-poetry','','[]','桂林舊著繡衣來，久矣餘波拍越臺。',32,'全唐诗/poet.song.215000.json','["桂林舊著繡衣來，久矣餘波拍越臺。", "自古直臣多牧廣，廣平曾賦嶺頭梅。"]'),
('ae003719-5b54-4e2b-ba64-63d022e9de9a','迎廣帥徐意一大參五首  其二','李昴英','宋','宋诗','song-poetry','','[]','曉來竹馬躍兒曹，次第牙幢壓近郊。',32,'全唐诗/poet.song.215000.json','["曉來竹馬躍兒曹，次第牙幢壓近郊。", "五老跨羊持色穗，也應歡喜侯前茅。"]'),
('88309c9e-bf75-4c4d-8080-fc502784ff38','迎廣帥徐意一大參五首  其三','李昴英','宋','宋诗','song-poetry','','[]','別去丹山劃七春，一廛今日是滕民。',32,'全唐诗/poet.song.215000.json','["別去丹山劃七春，一廛今日是滕民。", "擬撐釣舸迎前路，猿鶴從傍冷笑人。"]'),
('dd707839-f2ad-4cfe-8080-fcd7c81c8327','迎廣帥徐意一大參五首  其四','李昴英','宋','宋诗','song-poetry','','[]','魚稻之鄉雁鶩驕，鯨鯢噴沬撼江潮。',32,'全唐诗/poet.song.215000.json','["魚稻之鄉雁鶩驕，鯨鯢噴沬撼江潮。", "明公自是威風手，南土應無莠害苗。"]'),
('4b03703c-cea1-47c4-a0af-1bb2bcefdc8f','迎廣帥徐意一大參五首  其五','李昴英','宋','宋诗','song-poetry','','[]','杜劉二子潁川居，出處雖同語嘿殊。',32,'全唐诗/poet.song.215000.json','["杜劉二子潁川居，出處雖同語嘿殊。", "勿謂寒蟬吾願學，閉門自辦靜工夫。"]'),
('4df932f0-8a34-471a-bb8d-95eb9deccdc7','送魁星與李子先','李昴英','宋','宋诗','song-poetry','','[]','金斗高跳鬼狀獰，世傳此像是魁星。',32,'全唐诗/poet.song.215000.json','["金斗高跳鬼狀獰，世傳此像是魁星。", "祥光閃爍開先兆，助子秋闈筆硯靈。"]'),
('e1615936-4877-432a-bf3b-a7c58d20013d','司法曾子美新第榮歸欲得余詩不敢效世俗諛語二首  其一','李昴英','宋','宋诗','song-poetry','','[]','里同清獻久聞風，耿耿胸中便不同。',32,'全唐诗/poet.song.215000.json','["里同清獻久聞風，耿耿胸中便不同。", "一疏叫雲韋布日，大廷對策想輸忠。"]'),
('9a6e64f0-81f4-4bea-8c1f-6bc9589f1251','司法曾子美新第榮歸欲得余詩不敢效世俗諛語二首  其二','李昴英','宋','宋诗','song-poetry','','[]','舌似河懸筆水翻，春官首疏見忠肝。',32,'全唐诗/poet.song.215000.json','["舌似河懸筆水翻，春官首疏見忠肝。", "士須卓爾名當世，好取前修節行看。"]'),
('1224407b-7ab7-45a4-8a95-8ec3ff7037a6','表釋應端住興化寺以其說而勉之二首  其一','李昴英','宋','宋诗','song-poetry','','[]','鉢中滴水也難消，切莫貪他寺富饒。',32,'全唐诗/poet.song.215000.json','["鉢中滴水也難消，切莫貪他寺富饒。", "留取大皮纏大樹，腹圍緊緊篾三條。"]'),
('305c8f87-387c-4c06-a429-a0b91029c012','表釋應端住興化寺以其說而勉之二首  其二','李昴英','宋','宋诗','song-poetry','','[]','一般奇怪弄精魂，豬蜆皆餐針戲吞。',32,'全唐诗/poet.song.215000.json','["一般奇怪弄精魂，豬蜆皆餐針戲吞。", "未到空通渠地位，只當齋戒作沙門。"]'),
('823b3feb-c499-4f1e-bf3d-89f1206f7392','白雲獅子峰望羅浮','李昴英','宋','宋诗','song-poetry','','[]','不到羅浮瞥六年，後期幾誤鐵橋仙。',32,'全唐诗/poet.song.215000.json','["不到羅浮瞥六年，後期幾誤鐵橋仙。", "遠雲不隔山真面，西麓原同第七天。"]'),
('ab0217e6-b76d-4e37-8af0-49710ba15d41','羅浮桃源峒','李昴英','宋','宋诗','song-poetry','','[]','靈符鎖盡穴中蛇，深入千巖處士家。',32,'全唐诗/poet.song.215000.json','["靈符鎖盡穴中蛇，深入千巖處士家。", "峒戶隔雲呼不應，時時流水出桃花。"]'),
('39965de7-2f15-44e8-af6d-9023b71aafea','戲題羅浮梁彌仙寫真','李昴英','宋','宋诗','song-poetry','','[]','八十童顔雙眼明，浪游湖海一身輕。',32,'全唐诗/poet.song.215000.json','["八十童顔雙眼明，浪游湖海一身輕。", "莫將啖肉先生比，箇是羅浮老樹精。"]'),
('2df42da4-576b-4287-8e29-b77da4feefbd','和徐意一韻贈寶積中空山','李昴英','宋','宋诗','song-poetry','','[]','道是空山却有渠，原來有有亦無無。',32,'全唐诗/poet.song.215000.json','["道是空山却有渠，原來有有亦無無。", "若能空到真空處，萬斛塵埃著碓夫。"]'),
('e2ff517e-bdc6-41e1-a958-10675935c9a7','採陽軒','李昴英','宋','宋诗','song-poetry','','[]','看盡西園十里梅，黄昏寒月趁人回。',32,'全唐诗/poet.song.215000.json','["看盡西園十里梅，黄昏寒月趁人回。", "要圓一段清游事，更訪仙宮索茗杯。"]'),
('db829826-02a3-40e1-8567-fb8d6a1322e3','古成之仙箕','李昴英','宋','宋诗','song-poetry','','[]','翁來靈筆舞龍蛇，翁去瑶壇鎖暮霞。',32,'全唐诗/poet.song.215000.json','["翁來靈筆舞龍蛇，翁去瑶壇鎖暮霞。", "舊事欲談三百載，五雲閣上望仙槎。"]'),
('deb49fc0-94ff-428b-a954-7ce362207850','書龍頭義約簿二首  其一','李昴英','宋','宋诗','song-poetry','','[]','桂菊風香造榜天，門標捷幟地流錢。',32,'全唐诗/poet.song.215000.json','["桂菊風香造榜天，門標捷幟地流錢。", "筆端快便行年順，騎鶴纏腰身兩全。"]'),
('d4458a2d-eb38-4ea2-b51d-3474f0512b3f','書龍頭義約簿二首  其二','李昴英','宋','宋诗','song-poetry','','[]','鵰鶚聯翻二十名，看看金榜是同盟。',32,'全唐诗/poet.song.215000.json','["鵰鶚聯翻二十名，看看金榜是同盟。", "河南人面分明見，盡說龍頭讖已成。"]'),
('5dd83524-2888-44cb-83a2-fcd5d63b14eb','重九日游南山峽覺海寺','李昴英','宋','宋诗','song-poetry','','[]','恰重陽日到南山，小摘黄花供綠樽。',32,'全唐诗/poet.song.215000.json','["恰重陽日到南山，小摘黄花供綠樽。", "鐘叩一聲蕭寺晚，移舟載月過前灣。"]'),
('41d349ae-429d-42e0-9b4b-887efcecc23a','夜夢漁父求詩覺能記其全書贈梁彌仙','李昴英','宋','宋诗','song-poetry','','[]','酒湖無盡春無限，一葉江湖萬里天。',32,'全唐诗/poet.song.215000.json','["酒湖無盡春無限，一葉江湖萬里天。", "明月滿篷風荻響，醉眠正在白鷗邊。"]'),
('975b4174-f3ee-41fa-bf80-8f3f0aed84cf','衆建蓮社堂求疏語','李昴英','宋','宋诗','song-poetry','','[]','遠公鼻孔著蓮香，引得喃喃鬨幾場。',32,'全唐诗/poet.song.215000.json','["遠公鼻孔著蓮香，引得喃喃鬨幾場。", "供佛建菴人更錯，參機元不在西方。"]'),
('675ebcc1-e9d8-4d5f-9cdd-fc4d59e298fd','浄慈釋刺血寫經贊','李昴英','宋','宋诗','song-poetry','','[]','此經如筏，寫之著相。',80,'全唐诗/poet.song.215000.json','["此經如筏，寫之著相。", "而刺血寫，妄中之妄。", "經諸佛說，血父母生。", "何浄何垢，等爲前塵。", "末法闍梨，沉酣入骨。", "一毫且靳，而况於血。", "血猶可舍，是知身幻。", "大痛一囘，直須臂斷。"]'),
('5e2e3dec-7756-4358-bd67-82daf0e73525','三十五代張天師贊','李昴英','宋','宋诗','song-poetry','','[]','冷面皎霜凝，電光雙目崢。',24,'全唐诗/poet.song.215000.json','["冷面皎霜凝，電光雙目崢。", "生來元自別，不但父書靈。"]'),
('b9007882-c8b6-4349-97a8-deca7d7374ef','鍾離仙贊','李昴英','宋','宋诗','song-poetry','','[]','衣兮木葉，髯戟面鐵。',20,'全唐诗/poet.song.215000.json','["衣兮木葉，髯戟面鐵。", "所執何書，願聞其說。"]'),
('1cb215a1-3b22-4bed-b17d-0ec9b8ddec76','呂洞賓贊','李昴英','宋','宋诗','song-poetry','','[]','碧其風巾，皓其雲袍。',20,'全唐诗/poet.song.215000.json','["碧其風巾，皓其雲袍。", "六合飛遨，仙中之豪。"]'),
('7c7fe95f-4f44-44ea-8e06-09e0dc42f7bb','維摩贊','李昴英','宋','宋诗','song-poetry','','[]','丈室著不得文殊，衆香國裏薰教臭。',32,'全唐诗/poet.song.215000.json','["丈室著不得文殊，衆香國裏薰教臭。", "無端詐病却成喑，只爲從前多業口。"]'),
('129785a7-b1b1-4ab9-989b-a8a109563b04','自贊','李昴英','宋','宋诗','song-poetry','','[]','竛竮山癯，搭颯野服。',40,'全唐诗/poet.song.215000.json','["竛竮山癯，搭颯野服。", "煮茗松根，煨芋巖曲。", "且農且漁，非仙非俗。", "淇傍何有，秋鶴霜竹。"]'),
('867359cf-dd53-47cf-8182-eaa5771ded4f','廣州天慶觀衆妙堂東坡井泉銘','李昴英','宋','宋诗','song-poetry','','[]','老經云，坡記成。',64,'全唐诗/poet.song.215000.json','["老經云，坡記成。", "名非古，堂遂輕。", "兩翁像，久晦冥。", "偉方公，舊貫仍。", "取彼欄，護此泓。", "新作蓋，環以銘。", "遺千年，飲清泠。", "續坡誰，李昴英。"]'),
('91592563-4f22-4f9e-8f06-95ce392217a3','行者了寬等題錢買度牒疏四章  其一','李昴英','宋','宋诗','song-poetry','','[]','已辦僧心，未圓僧相。',20,'全唐诗/poet.song.215000.json','["已辦僧心，未圓僧相。", "纔得方兄，便成和尚。"]'),
('3ff953da-abf7-4bb4-9e8a-621f251e4619','行者了寬等題錢買度牒疏四章  其二','李昴英','宋','宋诗','song-poetry','','[]','作佛何曾要裹纏，頂門尚欠世間錢。',32,'全唐诗/poet.song.215000.json','["作佛何曾要裹纏，頂門尚欠世間錢。", "舍身者與舍佛者，選佛場中化有緣。"]'),
('7585b0d2-e345-4113-ba1a-0c3fbc64c088','行者了寬等題錢買度牒疏四章  其三','李昴英','宋','宋诗','song-poetry','','[]','作佛本無相，爲僧却要錢。',24,'全唐诗/poet.song.215000.json','["作佛本無相，爲僧却要錢。", "豈無人割捨，爲結惡因緣。"]'),
('bfb54974-c4fa-4c49-85de-ac74f882312f','行者了寬等題錢買度牒疏四章  其四','李昴英','宋','宋诗','song-poetry','','[]','即心是佛，見性成僧。',20,'全唐诗/poet.song.215000.json','["即心是佛，見性成僧。", "無奈世緣，要二尺綾。"]'),
('c9ac79de-0b04-4a48-b7d2-162d3d8611b6','句','三學諸生','宋','宋诗','song-poetry','','[]','庾嶺梅花清似玉，一番香要一番寒。',16,'全唐诗/poet.song.215000.json','["庾嶺梅花清似玉，一番香要一番寒。"]'),
('91a15b9f-f770-415c-b78f-01585c9ee285','癸丑仲秋建安郡學丁奠退而作頌并勉同志之士頌曰','趙汝騰','宋','宋诗','song-poetry','','[]','建水懷襄，孔殿巋然。',230,'全唐诗/poet.song.215000.json','["建水懷襄，孔殿巋然。", "文未墜地，道昭于天。", "輪奐鼎新，丁奠揭虔。", "肅肅冠佩，粲粲豆籩。", "惟聖立範，載籍具傳。", "渾渾噩噩，書教百篇。", "危微精一，綱領所先。", "詩六義教，風雅頌全。", "曰思無邪，蔽以一言。", "易教精微，四德首元。", "演六十四，母坤父乾。", "春秋事教，惟義與權。", "行夏之時，獨許顔淵。", "樂教導和，鐘鼓管絃。", "雷出地豫，樂之大原。", "禮教導中，三百三千。", "其端辭遜，如始達泉。", "垂茲六教，何千萬年。", "睠惟此邦，儒哲比肩。", "厥有考亭，是紹澗瀍。", "發揮六學，有功聖賢。", "守吏初獻，與士周旋。", "祀畢作頌，同志勉旃。"]'),
('f37b9cbf-a995-49a1-9c0a-11e22c305e7c','乙卯仲春丁奠畢作素王頌一首呈承祭之士頌曰','趙汝騰','宋','宋诗','song-poetry','','[]','於穆素王，天縱將聖。',240,'全唐诗/poet.song.215000.json','["於穆素王，天縱將聖。", "小用于魯，振挈綱領。", "萊兵面却，齊人退聽。", "三都隳姦，兩觀鋤佞。", "市無飾賈，朝無亂政。", "少壯悉遜，道塗不競。", "曲阜大治，諸侯交儆。", "女樂間之，可以出迸。", "俟膰不至，于衛之境。", "留不暖席，去復俄頃。", "幾圍于匡，幸釋以甯。", "歸主蘧瑗，耻居次乘。", "彷徨過宋，流離在鄭。", "魋惡習禮，木不留影。", "立郭東門，纍然誰省。", "在陳徘徊，弗授寸柄。", "河水洋洋，不渡者命。", "蒲盟止兵，蔡懼設穽。", "楚尼書社，彼哉讒勝。", "轍環靡歸，不容何病。", "十有四年，魯復來聘。", "亦莫果用，六經是訂。", "易繫禮編，詩刪書定。", "私淑三千，弦歌雩詠。"]'),
('626eaa50-3c9f-40cd-b55b-58e51a65d45e','贈張彊赴曲江教','趙汝騰','宋','宋诗','song-poetry','','[]','聖人立教，以中爲常。',220,'全唐诗/poet.song.215000.json','["聖人立教，以中爲常。", "不得中行，取獧取狂。", "未見狂者，吾里有張。", "議論傑然，名壓上庠。", "惡彼佞臣，請劍尚方。", "使終天彝，蠶績蟹筐。", "天鑒其忠，策名顔行。", "筮仕分教，九齡之鄉。", "惟九齡公，非血氣剛。", "憂深慮遠，性端行良。", "祿山尚微，測其陸梁。", "國忠林甫，惡未披猖。", "公預窺之，知其亂唐。", "仁必有勇，令名無疆。", "彼元忠輩，初志激昂。", "一遇擯抑，盡斂鋒鋩。", "媕娿喑啞，不敢否臧。", "自謂得計，爵祿之場。", "喪已丘山，得不毫芒。", "士辨薰蕕，與道存亡。", "何以臻茲，惟學問將。", "弱翁懋哉，以保令芳。"]'),
('a1925487-4a8f-4c86-853e-2a5bef55c50a','贈衡陽簿林士愷','趙汝騰','宋','宋诗','song-poetry','','[]','吾黨仲容，行脩能通。',200,'全唐诗/poet.song.215000.json','["吾黨仲容，行脩能通。", "而志卓然，以慕直躬。", "嘗儕扣閽，力摧姦鋒。", "上旌其言，擢第南宮。", "府庠諸生，坐斥怱怱。", "君盡遠詒，盍援掖逢。", "予疏已先，所見略同。", "每起敬愛，有烈士風。", "予歸里閈，時訪藋蓬。", "匪義不談，惟理是窮。", "告予戍及，棲枳湘中。", "壯哉茲行，近紫蓋峰。", "刑使傑然，蜀彥之雄。", "埋輪大勇，折檻精忠。", "朝夕趨承，必得所從。", "一被容接，終身登龍。", "惟仕首輔，必廉必公。", "惟學策要，必敬必恭。", "胡張之鄉，名理之宗。", "公餘取友，以相磨礲。"]'),
('bbdc493d-ffef-4325-9c1c-c9bd4c023ebd','贈林耕叟赴湖帥幕','趙汝騰','宋','宋诗','song-poetry','','[]','東萊之師，是爲拙齋。',210,'全唐诗/poet.song.215000.json','["東萊之師，是爲拙齋。", "學無不究，道無不該。", "體統純正，規模拓恢。", "卓成一家，猶斗之魁。", "未及百年，遺響冷灰。", "我守寶婺，四學是開。", "以導生徒，俾紹東萊。", "回首七霜，諒多成材。", "英英耕叟，我友自孩。", "吐詞不羣，制行亦瑰。", "勉以朱學，持論不回。", "僕家源流，是擁是培。", "仲尼得伋，垂教方來。", "拙齋有孫，其道未頹。", "且告瓜熟，定王之臺。", "僮馬載馳，羔鴈屢催。", "予聞湘流，夙稱聖涯。", "懋陵之邦，元公所胎。", "南軒昭昭，五峰巍巍。", "豈無秀民，可與摩揩。", "求仁得仁，懋哉懋哉。"]'),
('73e9db92-52ff-4179-b145-ae806a135569','贈成師掾公策','趙汝騰','宋','宋诗','song-poetry','','[]','易中之策，陰陽錯綜。',80,'全唐诗/poet.song.215000.json','["易中之策，陰陽錯綜。", "是興神物，以前民用。", "受命如響，吉凶生動。", "子取策名，僕沿理控。", "先覺仲尼，方人子貢。", "惟誠前知，不億而中。", "中庸即易，是道公共。", "非策之策，斯語請誦。"]'),
('c9fac7c5-4682-48ba-a27c-4c3ceeb8ac17','贈陳如晦','趙汝騰','宋','宋诗','song-poetry','','[]','堂堂六湖，清秋玉壺。',80,'全唐诗/poet.song.215000.json','["堂堂六湖，清秋玉壺。", "我則尚友，豈敢爲徒。", "仁義弘毅，不可奪志。", "豈私我朋，義之與比。", "德必有鄰，二彭其人。", "與語終日，澹無一塵。", "以罪來歸，得此四賓。", "甘心澗谷，以老我身。"]'),
('7b1ab82e-5da8-4b79-ab99-6a0698ae6178','贈詹生謁徐徑坂','趙汝騰','宋','宋诗','song-poetry','','[]','賢哉二生，不遠千里。',40,'全唐诗/poet.song.215000.json','["賢哉二生，不遠千里。", "瞻彼徑坂，今之泗水。", "予詩爲容，有進無止。", "非殷洪喬，乃互鄉子。"]'),
('3db3780b-98e0-458e-ae0e-337b698fadf9','次徐徑坂四言韻  其一','趙汝騰','宋','宋诗','song-poetry','','[]','欹枕肱曲，匱藏美玉。',20,'全唐诗/poet.song.215000.json','["欹枕肱曲，匱藏美玉。", "造道高深，庭草交綠。"]'),
('d93537b3-9a84-4567-9251-f3fc673c297a','次徐徑坂四言韻  其二','趙汝騰','宋','宋诗','song-poetry','','[]','中庸致曲，學記琢玉。',20,'全唐诗/poet.song.215000.json','["中庸致曲，學記琢玉。", "子過仙柯，瞻彼淇綠。"]'),
('db7fec53-cb81-472f-a7f9-840cf533bb8d','美李頤老易','趙汝騰','宋','宋诗','song-poetry','','[]','易之廣大，無方無體。',180,'全唐诗/poet.song.215000.json','["易之廣大，無方無體。", "河圖授羲，斯文天啟。", "爰畫以象，是陳八物。", "演六十四，闔闢伸屈。", "文繫繇辭，二千爻旨。", "孔絕韋編，十翼備矣。", "後來濂洛，發明幾盡。", "萬世學者，於此取信。", "弘毅李君，以身體易。", "消長驗氣，吉凶考德。", "方初學時，四載忘寐。", "感蒼筤竹，至産于地。", "蓋三十年，然後成書。", "其語不費，其趣有餘。", "予得其稿，日置書案。", "熟視厥履，爲之三嘆。", "道無隠顯，形上繇下。", "脩辭立誠，窮神知化。"]'),
('a457e421-a2cb-46bd-a840-45781f917ef4','示林宗辰勸學數語','趙汝騰','宋','宋诗','song-poetry','','[]','青出於藍，冰寒於水。',120,'全唐诗/poet.song.215000.json','["青出於藍，冰寒於水。", "立言勸學，荀卿氏子。", "卿不如軻，醇乎醇矣。", "謂學無他，求其放心。", "存則聖賢，舍則犢禽。", "差只毫髮，隔踰丈尋。", "必有事焉，所言何事。", "而勿正心，正亦何累。", "勿忘勿助，持敬之意。", "於此習察，是之謂學。", "於此而勸，其進罔覺。", "勉哉宗辰，說博守約。"]'),
('a0cb39d0-28cc-40fd-a1ca-6d90ced28400','示趙與檳弘毅章','趙汝騰','宋','宋诗','song-poetry','','[]','天之蒼蒼，而在山中。',180,'全唐诗/poet.song.215000.json','["天之蒼蒼，而在山中。", "大畜之象，驗之于躬。", "六尺之微，萬善畢叢。", "往行前言，浩浩無窮。", "一以貫之，何所不容。", "兩間非大，此之謂弘。", "牝馬之貞，行地無疆。", "古往今來，其道有常。", "是以資生，至哉化光。", "君子體之，六二直方。", "直內方外，何用不臧。", "守此之毅，賁育非剛。", "泗亭之參，以此任道。", "繇軻而後，孰其深造。", "濂洛儒先，知德之奧。", "非苟知之，亦免允蹈。", "興夫請書，朝夕戴抱。", "懋哉懋哉，至於華皓。"]'),
('9b0300a3-c80e-4960-93b2-2d1aa9292b30','餞趙文思崇鐖歸上饒','趙汝騰','宋','宋诗','song-poetry','','[]','英英吾宗，神駿之姿。',160,'全唐诗/poet.song.215000.json','["英英吾宗，神駿之姿。", "筆有天巧，自鑄偉詞。", "抱負不凡，植立甚奇。", "爰初筮仕，即不詭隨。", "笑世滔滔，相與磷緇。", "過予告別，凜然自期。", "耻逐京塵，願易叢祠。", "萊衣奉親，樂道忘饑。", "予惟上饒，淵源未衰。", "玉山文獻，考亭所推。", "章澗二泉，名論清規。", "邇來後生，古爲似之。", "仁親友兄，徑坂是師。", "子歸取友，伯塤仲箎。", "咫尺柯山，考德訂疑。", "他日成就，麟祥鳳儀。"]'),
('e663eeca-8c4f-4c74-9b4d-1bd35789665c','寄徐端友立大壽其母夫人','趙汝騰','宋','宋诗','song-poetry','','[]','英英二徐，名德之雛。',130,'全唐诗/poet.song.215000.json','["英英二徐，名德之雛。", "早從爛柯，知所步趨。", "南陔子職，夙夜盡劬。", "九日黄花，采采盈裾。", "請壽堂萱，大年方壺。", "龐眉髮鶴，重錦軒魚。", "母詔子前，問學勉諸。", "參匪直養，心傳泗洙。", "誠身悅親，授伋著書。", "子曰懋哉，益厲厥初。", "榮多遺母，文繡不如。", "戲舞樽前，母爲笑娛。", "我寄四言，俾陳座隅。"]'),
('17a97d03-bede-46c5-a79a-783270afb592','酬盧威仲九日遣青衣送酒','趙汝騰','宋','宋诗','song-poetry','','[]','前年重九日，黄衣携御槧。',168,'全唐诗/poet.song.215000.json','["前年重九日，黄衣携御槧。", "抗牘回天聰，批鱗蒙帝念。", "雖慚獻六箴，猶許疏十漸。", "去年重九日，石鼓償願欠。", "菊叢對佳客，萸觴傾舊釅。", "一時嘯詠狂，萬丈詞華艷。", "今年重九日，龜息靜中驗。", "亭前寒葉落，樓外晴波斂。", "故人何殷勤，清樽持瀲灧。", "思君甲辰疏，擬昔尚方劍。", "士鋒皆辟易，忠舌爲飫饜。", "回首今七秋，日月光同掞。", "知暫陸渾游，難久承明壓。", "老我思荷鋤，一壑柴桑占。"]'),
('0d83f750-aad1-4590-9d5e-cb4e555eae13','暇日領客登眺','趙汝騰','宋','宋诗','song-poetry','','[]','暇日登層城，目眺黄花岡。',120,'全唐诗/poet.song.215000.json','["暇日登層城，目眺黄花岡。", "來山何岌嶪，餘勢猶迴翔。", "郡治枕其中，溪流繞其旁。", "建中實經始，淳祐罹懷襄。", "河伯何不仁，平陸如江洋。", "水餘予領牧，初至覺荒凉。", "頼天賜連稔，田里多稻粱。", "舊觀喜漸復，新屋興未央。", "偶領賓戚游，松下傾盃觴。", "嵐氣接洲渚，舉目皆寒蒼。"]'),
('4bd678dd-aaf8-4deb-95f3-04819c6afe24','爲饒計使題','趙汝騰','宋','宋诗','song-poetry','','[]','煌煌使者軒，新扁煥羣目。',120,'全唐诗/poet.song.215000.json','["煌煌使者軒，新扁煥羣目。", "周爰遠有華，不可居無竹。", "天風泠然來，雲氣滃而簇。", "知君子猷趣，一笑等榮辱。", "每云安樂窩，似勝相州纛。", "憑欄對此君，竟日翫不足。", "余亦慕姱節，時時賦猗綠。", "閒思載醪去，悠悠想九曲。", "新詩带仙姿，霞餐謝粱肉。", "願言植梅友，疎影橫水澳。"]'),
('30d3220e-30ce-473b-9222-2dfd17b06274','徐朝奉誥命下走介賫納徑坂賦成','趙汝騰','宋','宋诗','song-poetry','','[]','驛足行都來，手賫誥一軸。',120,'全唐诗/poet.song.215000.json','["驛足行都來，手賫誥一軸。", "發視喜非常，耆儒見褒錄。", "斯人德無瑕，有子道振玉。", "陛下自好老，微臣耻干祿。", "耕雲入山深，釣月翫水綠。", "一朝朱紱賜，龐眉釋袍鵠。", "萊衣拜稱慶，起舞徧親族。", "我在霞洲上，折屐亦越宿。", "茲忻贊書至，哦詩遣騶僕。", "遥知參侍點，論學紹淇澳。"]'),
('718f9bd8-a3f1-461d-87da-447068ea1b16','和徐徑坂  其一','趙汝騰','宋','宋诗','song-poetry','','[]','我敬楳埜翁，治郡如元結。',48,'全唐诗/poet.song.215000.json','["我敬楳埜翁，治郡如元結。", "一朝殉國死，黄壤恨誰雪。", "赤輸陳蕃心，碧化萇弘血。", "銘筆得柯仙，羣陰消蟋蟀。"]'),
('1c1e8fae-7ae2-4137-9bae-5b5187fe3518','和徐徑坂  其二','趙汝騰','宋','宋诗','song-poetry','','[]','予歸假闔廬，守曰於我館。',48,'全唐诗/poet.song.215000.json','["予歸假闔廬，守曰於我館。", "風雨已遁逃，雲山况奇觀。", "徑坂形聲詩，蓬萊名遂遠。", "求仁居之安，是宅靡有間。"]'),
('44f39167-fb27-40bc-b861-5c069d591d10','食梅','趙汝騰','宋','宋诗','song-poetry','','[]','兒時摘青梅，葉底尋彈丸。',72,'全唐诗/poet.song.215000.json','["兒時摘青梅，葉底尋彈丸。", "所恨襟袖窄，不憚頰舌穿。", "我年不自覺，以我齒尚完。", "嘗新試一薦，喉棘眉先攢。", "豈味不悅口，豈老難强餐。", "人生煎百憂，算梅未爲酸。"]'),
('2138ebbb-7391-4d7c-b553-5b089d4482c8','壽史刑使','趙汝騰','宋','宋诗','song-poetry','','[]','岷峨儲英賢，一例皆家食。',108,'全唐诗/poet.song.215000.json','["岷峨儲英賢，一例皆家食。", "公亦淹海角，麾節猶赫奕。", "七閩政多幸，福星照南極。", "輕裘鎮鈴閤，使斧光衛戟。", "門弧初度臨，和氣徧阡陌。", "宿雨洗瘴氛，朔雲報寒色。", "前期爲重九，後期爲至日。", "中間産蜀珍，天意扶陽脈。", "願言愛剛健，他日壽王國。"]'),
('a7791df6-c7ca-4a54-9e7c-ab0d7232d3d1','謝胡珵使招飲','趙汝騰','宋','宋诗','song-poetry','','[]','疇昔與公同奉常，余爲藉田公社令。',144,'全唐诗/poet.song.215000.json','["疇昔與公同奉常，余爲藉田公社令。", "是時朔祭拜卿少，余已顔衰公秀瑩。", "齋房並公揮麈尾，議論風生真纚纚。", "蜀珍數人皆在坐，盡說功名須遜子。", "回頭一夢十五春，公爲使者余廛民。", "薰風荷畔綠樽設，丹荔粲粲蓮房新。", "語間切切憂民瘼，陰功亟欲蘇全閩。", "出經入傳知言要，湘西絕學今誰紹。", "我老西河欠鞭策，此事須公正英妙。"]'),
('3e353d8d-6d34-46d3-a44c-93ebcd5b6e06','送眉山孫夢得從饒伯輿李純父學','趙汝騰','宋','宋诗','song-poetry','','[]','景山書來說蜀珍，與吾氣象清而真。',112,'全唐诗/poet.song.215000.json','["景山書來說蜀珍，與吾氣象清而真。", "束書亟歸侍溫凊，力祈樸學爲是正。", "程文不過工進取，何若杜門誦論語。", "一言可以行終身，世間至樂惟求仁。", "弋陽餘干相望爾，紫陽的傳伯輿是。", "同志更有李純父，勁節清名照今古。", "爲我問訊出此詩，子親炙之有餘師。"]'),
('62ca0200-638b-48ca-8ddd-9cb447c58d13','示林桂高歌','趙汝騰','宋','宋诗','song-poetry','','[]','丈夫流芳在身後，眼前一食常不飽。',114,'全唐诗/poet.song.215000.json','["丈夫流芳在身後，眼前一食常不飽。", "何况吟工抉元化，萬象日月遭搜攪。", "君不見飯顆山頭餓少陵，柴桑徑裏饑淵明。", "無錢對菊坐終日，得錢沽酒醉交朋。", "又不見春岸飛楊花，聖俞得句貧轉加。", "羊腸遶車聲，黄九一生坐窮鳴。", "歐蘇只得從旁嘆，不爾何由負盛名。"]'),
('ea7b8436-4855-42fd-a7b6-636ff7593b6b','景南將赴武昌道出剡溪戲成贈行','趙汝騰','宋','宋诗','song-poetry','','[]','丈夫未遇時，流俗多白眼。',52,'全唐诗/poet.song.215000.json','["丈夫未遇時，流俗多白眼。", "張耳能致千里客，相如竟輟萬金産。", "方子一世英，要路爭力挽。", "行行取侯封，何必守蠹簡。"]'),
('14949d0d-06b3-43b1-b97f-2df7ffae2514','陳謂老見過云今年六十有九將預爲周身之防余曰君定未死不如覓錢沽酒耳用戲成拙句贈行','趙汝騰','宋','宋诗','song-poetry','','[]','荷鍤自隨劉伯倫，裸葬舊聞楊王孫。',99,'全唐诗/poet.song.215000.json','["荷鍤自隨劉伯倫，裸葬舊聞楊王孫。", "偉哉二子真曠達，身雖殞滅名獨存。", "要知形骸本外物，中有妙用超六根。", "火風地水歸四大，夢幻泡影何足論。", "君不見桓魋石槨秦鐵戶，歌鐘未徹野火焚。", "不如得錢即沽酒，時時醉倒三家村。"]'),
('e4246dce-d851-4bf8-9e05-a66514d67697','和徐徑坂韻二首  其一','趙汝騰','宋','宋诗','song-poetry','','[]','玉柯仙管頻念我，大書束縑濃墨斑。',64,'全唐诗/poet.song.215000.json','["玉柯仙管頻念我，大書束縑濃墨斑。", "寄情縹渺江海際，匠語慘澹雲烟間。", "燃藜太乙中夜照，垂釣客星清晝閒。", "觀公舒卷皆以道，仁智山靜水潺湲。"]'),
('4a1e1449-131a-4519-b58d-081b1399eb23','和徐徑坂韻二首  其二','趙汝騰','宋','宋诗','song-poetry','','[]','學者山斗吾徑坂，杜門養志衣萊斑。',64,'全唐诗/poet.song.215000.json','["學者山斗吾徑坂，杜門養志衣萊斑。", "孤峰度越青雲上，一世失得浮埃間。", "鳳鳴思誠頻遺訊，龍卧草廬相對閒。", "三賢鼎立名師友，衢江萬古身潺湲。"]'),
('b9100c74-6f5a-475a-8c63-763b1537246a','贈武應辰見徐徑坂','趙汝騰','宋','宋诗','song-poetry','','["\u8861\u5c71"]','衡陽布衣武應辰，柯山迎拜新使君。',64,'全唐诗/poet.song.215000.json','["衡陽布衣武應辰，柯山迎拜新使君。", "使君道德今天人，不知肯開衡山雲。", "君看衡雲開未開，吾道所關非小哉。", "應辰爲我三致意，行藏已定顔心齋。"]'),
('dca5d8ba-523e-4a89-b520-c8d5419e9594','示趙與檳','趙汝騰','宋','宋诗','song-poetry','','[]','今年至日有喜色，四方士友來請益。',64,'全唐诗/poet.song.215000.json','["今年至日有喜色，四方士友來請益。", "德場宗英質大學，上饒諸賢問太極。", "草廬一紙隃寄音，徑坂七言大書帛。", "衰予甘遁西河上，點檢身心有方冊。"]'),
('e93e19b0-9e22-4c05-ae23-6004594fcca4','壽史刑使','趙汝騰','宋','宋诗','song-poetry','','[]','羨公博學今揚雄，未許蜀珍專瑞蜀。',160,'全唐诗/poet.song.215000.json','["羨公博學今揚雄，未許蜀珍專瑞蜀。", "喜公奉使今鮮于，又見福星來照福。", "我初敬公因讜疏，萬言批鱗折五鹿。", "我轉敬公緣清操，高吟放鶴孤山麓。", "今茲仗斧更仁厚，庭草不鋤生意足。", "憂時兩鬢白髮增，愛賢一念緇衣篤。", "衰予歸卧西河上，都騎時來尋澗谷。", "清言竟日無盡藏，想見胸中幾天祿。", "若人盍置論思地，垂弧定有鋒車趣。", "去年五言稱公壽，今年笑指湖山綠。"]'),
('ca65c5e5-db00-464e-b88a-f5d41e2e4780','贈璘上人','趙汝騰','宋','宋诗','song-poetry','','[]','潜齋山雨過從久，每說二公不離口。',64,'全唐诗/poet.song.215000.json','["潜齋山雨過從久，每說二公不離口。", "山雨去佐玉樓仙，潜齋起領金壇守。", "一江一浙兩知音，柏枝東指還西否。", "胡然拄杖轉落南，膜拜叢中獅子吼。"]'),
('996bf068-6fac-4677-9ea0-6b307114b415','與張草廬予欲嗣奏聘君草廬寄聲止予歌以答之','趙汝騰','宋','宋诗','song-poetry','','[]','姑蔑之墟，郡郭之隅。',174,'全唐诗/poet.song.215000.json','["姑蔑之墟，郡郭之隅。", "幽閴兮陋巷，卑渫兮繩樞。", "真人兮匵藏，道貌兮山臞。", "有時兮過市，徐行兮當車。", "天津游兮聞鵑而慨嘆，鹿門登兮采藥而躊躇。", "明月兮嘯咏，白雲兮卷舒。", "我評其人，陶邵之徒。", "疇昔歲兮司銀臺，力抗疏兮徵玉廬。", "朝奏墨兮欲下，暮出晝兮尼。", "諸君一笑兮草芥，余三惜兮璠璵。", "擬箋天兮嗣請，近因風兮止余。", "仰高致兮慕予，積卑忱兮願攄。", "善不進兮不已，終當諒乎純愚。"]'),
('c80db0e4-5fbb-450f-bda3-8ba2438372d6','答徐直方問無極歌','趙汝騰','宋','宋诗','song-poetry','','[]','謂無極不可狀兮，造化之樞。',106,'全唐诗/poet.song.215000.json','["謂無極不可狀兮，造化之樞。", "謂無極可狀兮，聲臭俱無。", "至哉濂翁兮，是剏是圖。", "後來諸老兮，交辨鵝湖。", "彼是此非兮，畦畛何殊。", "究其指歸兮，風乎舞雩。", "吾默會於心兮，徵以通書。", "陰陽動靜兮，何始何初。", "人人有是兮，奚問乎呂陸張朱。"]'),
('8831c7dd-2519-4e3c-b193-98456fb2d9d6','遺徐端友壽母夫人','趙汝騰','宋','宋诗','song-poetry','','[]','望東雲兮懷玉，産二英兮鸑鷟。',72,'全唐诗/poet.song.215000.json','["望東雲兮懷玉，産二英兮鸑鷟。", "持榮名兮壽親，頌大椿兮對菊。", "餐初英兮慕屈子之菲菲，飲寒潭兮陋胡廣之碌碌。", "我敬愛之，勉以猗綠。", "垂芳兮無窮，介母兮多福。"]'),
('7383a6d5-98a3-41cd-9d07-c488fbc211f5','趣饒伯輿來期','趙汝騰','宋','宋诗','song-poetry','','[]','忽得高賢訊，篝燈讀數回。',48,'全唐诗/poet.song.215000.json','["忽得高賢訊，篝燈讀數回。", "苦辭白鹿講，盍爲紫陽來。", "水毀祠無恙，堂新教有開。", "須君速戾止，倡道淑英材。"]'),
('653b6e96-670f-4fe9-aeb4-0564f5402316','寄李頤老','趙汝騰','宋','宋诗','song-poetry','','[]','清苦推洪毅，人今合古求。',48,'全唐诗/poet.song.215000.json','["清苦推洪毅，人今合古求。", "道東吾所敬，學北子爲優。", "夜氣存無餒，晨餐缺不憂。", "時來同析理，相對一茶甌。"]'),
('361742cb-cb9f-492c-a0bd-4c5247f012fa','送伯和姪歸里之戍','趙汝騰','宋','宋诗','song-poetry','','[]','留爾紉秋桂，歸歟迫戍瓜。',48,'全唐诗/poet.song.215000.json','["留爾紉秋桂，歸歟迫戍瓜。", "定將儒術飾，肯以惠文誇。", "獄敬裨王國，帷褰佐使家。", "公餘更努力，學似海無涯。"]'),
('94bc1fff-f227-49ed-bd86-5549c58f8fd8','送游幾叟衡山尉','趙汝騰','宋','宋诗','song-poetry','','["\u8861\u5c71"]','西風催仕軔，比部得英曹。',48,'全唐诗/poet.song.215000.json','["西風催仕軔，比部得英曹。", "澤物官無小，觀山嶽最高。", "須知戴星出，慎勿厭塵勞。", "綵棒有餘暇，何妨誦楚騷。"]'),
('0ced75ff-7c67-4aaa-b74f-2288b5bc3353','餞用晦姪南安令  其一','趙汝騰','宋','宋诗','song-poetry','','[]','爾宦神臯日，搢紳無間言。',48,'全唐诗/poet.song.215000.json','["爾宦神臯日，搢紳無間言。", "勇懷南邑綬，爲便北堂萱。", "侍講鸞棲舊，端明棠蔭存。", "時能挹前輩，爲政有根源。"]'),
('793442a6-f339-47ce-a90f-53dbae427552','餞用晦姪南安令  其二','趙汝騰','宋','宋诗','song-poetry','','[]','作邑無他法，精神在拊摩。',48,'全唐诗/poet.song.215000.json','["作邑無他法，精神在拊摩。", "吏肥民必瘦，酒少飯宜多。", "寧拙催科考，須知于蒍歌。", "莫將還債看，好事易蹉跎。"]'),
('3f3b4e41-762d-4703-9a67-560ce38e9244','挽竹湖李端明  其一','趙汝騰','宋','宋诗','song-poetry','','[]','千古筠溪節，名孫尚有諸。',48,'全唐诗/poet.song.215000.json','["千古筠溪節，名孫尚有諸。", "敢言禁闥黯，勇退漢廷疏。", "掃軌門如水，懸魚飯只蔬。", "訃傳纓紱駭，惜綰不中書。"]'),
('0c4bec63-1b47-4afc-8900-387c72ae84f5','挽竹湖李端明  其二','趙汝騰','宋','宋诗','song-poetry','','[]','淡似香山老，臞於涑水翁。',48,'全唐诗/poet.song.215000.json','["淡似香山老，臞於涑水翁。", "政須將及子，心孰不爲公。", "後進師清儉，前旒譽直空。", "墓陵手所築，過者式高風。"]'),
('3b7bb7dd-78fc-41ab-bdaa-8e284039027e','挽盛君時','趙汝騰','宋','宋诗','song-poetry','','[]','忽報斯人訃，傷哉命壓頭。',48,'全唐诗/poet.song.215000.json','["忽報斯人訃，傷哉命壓頭。", "皇皇如有索，落落竟何求。", "學道魚千里，辭家貉一丘。", "幸哉猶有子，可解二親憂。"]'),
('2a289596-d146-484d-8f35-4a3b8024b980','登北苑焙呈高計使謝庾使  其一','趙汝騰','宋','宋诗','song-poetry','','[]','急雨收聲霽景開，蓬仙嶺客島雲來。',64,'全唐诗/poet.song.215000.json','["急雨收聲霽景開，蓬仙嶺客島雲來。", "千叢擷秀牙鋪雪，萬臼研膏杵震雷。", "池上落英留綠葉，眼中飛絮點蒼苔。", "去年醉墨今重看，笑領詩翁瀲灧盃。"]'),
('42460ed4-74a0-467b-bcb0-5a965f08c47f','登北苑焙呈高計使謝庾使  其二','趙汝騰','宋','宋诗','song-poetry','','[]','蜀浙當年貢亦勞，至今惟重建溪毛。',64,'全唐诗/poet.song.215000.json','["蜀浙當年貢亦勞，至今惟重建溪毛。", "地靈丹鳳啣萱草，水聖蒼虯幻雪濤。", "笑指茶星誇小范，愁傷民力歎袁高。", "皇華早晚歸經幄，丁俑應難諫舌逃。"]'),
('4e221a5f-15f4-4281-97f2-a660b92ad834','陪饒計使至北苑焙','趙汝騰','宋','宋诗','song-poetry','','[]','東風未綠無邊草，北苑先抽絕品芽。',64,'全唐诗/poet.song.215000.json','["東風未綠無邊草，北苑先抽絕品芽。", "六轡行山清霧潦，一槍入焙带烟霞。", "鳳呈奇羽名仙麓，龍護香泉供帝家。", "萬碾玉塵飛動處，鬼猶勞矣况人耶。"]'),
('cefe5bff-3b16-4f27-a85d-a4d4e7f9015c','和饒計使北苑焙觀貢品','趙汝騰','宋','宋诗','song-poetry','','[]','使華金掌冠卿材，曾侍紅雲一朶來。',64,'全唐诗/poet.song.215000.json','["使華金掌冠卿材，曾侍紅雲一朶來。", "龍井爲君增洗濯，鳳山來客小低徊。", "膏翻玉雪團香帖，味篤金蘭共酒盃。", "計相他時踵龐老，席前敷奏記東臺。"]'),
('f0d046f4-6dce-4764-be83-8e479dfe23cb','再用韻','趙汝騰','宋','宋诗','song-poetry','','[]','天生神醴地生材，曾感當年鸑鷟來。',64,'全唐诗/poet.song.215000.json','["天生神醴地生材，曾感當年鸑鷟來。", "釣水取清芳酷烈，採山可茹味徘徊。", "能招霞侶雲中笑，得奉龍顔食後盃。", "細品第三綱最勝，人間雙井當輿臺。"]'),
('e21c0be7-ea57-4935-a253-d749ed874b81','謝饒計使遣餉頭貢餘','趙汝騰','宋','宋诗','song-poetry','','[]','仙芽龍水辦頭綱，百草山中不敢香。',64,'全唐诗/poet.song.215000.json','["仙芽龍水辦頭綱，百草山中不敢香。", "表進得陪華使拜，貢餘遣餉守臣嘗。", "擬思苦口陳忠諫，可但飴茶獻上方。", "分我清風生兩腋，惜無文字只枯腸。"]'),
('e5180d0d-9b83-4a25-9820-2a076ea1f2c7','再用韻答饒計使','趙汝騰','宋','宋诗','song-poetry','','[]','周原愔愔隸臺綱，茶篚馳供玉食香。',64,'全唐诗/poet.song.215000.json','["周原愔愔隸臺綱，茶篚馳供玉食香。", "貢重鄭男難並列，品珍考叔未曾嘗。", "乳花烹就分清貺，英草吟成屬大方。", "後蔡前丁同入諷，令人懷古九迴腸。"]'),
('5dc71bc2-8201-475a-8f53-48caad148395','三用韻答饒計使','趙汝騰','宋','宋诗','song-poetry','','[]','郡凋亦辦七茶綱，不似霜臺雀舌香。',64,'全唐诗/poet.song.215000.json','["郡凋亦辦七茶綱，不似霜臺雀舌香。", "上美爲元包錫貢，殘膏分丐雪翻嘗。", "三爲大有天王饗，二得坤中臣道方。", "退食自公味公賜，狂吟牽動璟心腸。"]'),
('794b6f51-dddd-424f-b733-0f87f754cf1c','謝高茶使遣餉頭綱貢餘','趙汝騰','宋','宋诗','song-poetry','','[]','東風吹折鳳山芽，驛獻花箱仗使家。',64,'全唐诗/poet.song.215000.json','["東風吹折鳳山芽，驛獻花箱仗使家。", "遥想仙芳供御盌，應憐味諫落天涯。", "厥包錫貢何年始，其苦如飴信地嘉。", "齋祭無繇陪褥位，膏餘分匄咀菁華。"]'),
('dd7a6af1-ec0e-4c75-941a-64f043b00983','再用韻答高茶使','趙汝騰','宋','宋诗','song-poetry','','[]','凡卉千山未吐芽，天生靈草瑞天家。',64,'全唐诗/poet.song.215000.json','["凡卉千山未吐芽，天生靈草瑞天家。", "漕修貢事東西廨，使起英流南北涯。", "諫苦固應疏汲黯，品高終必相王嘉。", "老衰不辦茶歌獻，但誦周原遠有華。"]'),
('57d06024-407c-4b60-8dc9-e010e6d5c2bd','慶高耻堂柱史都運','趙汝騰','宋','宋诗','song-poetry','','[]','招麾不可獨斯人，中外稱爲社稷臣。',64,'全唐诗/poet.song.215000.json','["招麾不可獨斯人，中外稱爲社稷臣。", "永叔未容居四諫，鮮于且起福全閩。", "光華濡轡今親遣，風采埋輪又一新。", "命下八州俱鼓舞，紫霞老守喜津津。"]'),
('0a7554c2-7866-4d5a-aa4e-d05d98b48daf','慶高耻堂柱史除漕','趙汝騰','宋','宋诗','song-poetry','','[]','九曲山川值異人，仙靈忻舞對波臣。',64,'全唐诗/poet.song.215000.json','["九曲山川值異人，仙靈忻舞對波臣。", "德星臨照來從蜀，瘴霧澄清一洗閩。", "澤物濂翁仁望著，寬民王旦政條新。", "爛柯精舍班荆語，好約秋風到北津。"]'),
('13a23be2-9fac-43ac-a610-1d2c8f917905','再用韻賀計使高耻堂建臺得雨','趙汝騰','宋','宋诗','song-poetry','','[]','皇華都騎訪陳人，似灑仙瓢助守臣。',64,'全唐诗/poet.song.215000.json','["皇華都騎訪陳人，似灑仙瓢助守臣。", "亭午建臺申大雨，作霖用汝澤先閩。", "物情是處皆忻吐，吏習從今一洗新。", "陝事早知付韓范，堯夫定不歎天津。"]'),
('ce908e28-fe4a-4aad-ba38-d285c90d3e29','答高耻堂計使招賞海棠','趙汝騰','宋','宋诗','song-poetry','','[]','皇華相約醉崇臺，正月海棠彌望開。',64,'全唐诗/poet.song.215000.json','["皇華相約醉崇臺，正月海棠彌望開。", "萬象呈春盃瀲灧，千花炫夜燭縈迴。", "雨餘妃带華清沐，雲幕仙從絳闕來。", "明歲公歸對紅藥，吟成寄我館蓬萊。"]'),
('b8c69c55-c033-45f1-9e8c-4ad8b149b684','再答  其一','趙汝騰','宋','宋诗','song-poetry','','[]','西州名品萃東臺，特爲光風連夜開。',64,'全唐诗/poet.song.215000.json','["西州名品萃東臺，特爲光風連夜開。", "春事三分元未半，詩腸一日九周迴。", "雨中有淚坡吟盡，馬上霑花甫醉來。", "郡塢數株寥落甚，園丁愛護剪荒萊。"]'),
('4b33fe7c-8d3e-42bc-9486-5ede3558ce71','再答  其二','趙汝騰','宋','宋诗','song-poetry','','[]','人間姚魏總輿臺，獨占神仙上品開。',64,'全唐诗/poet.song.215000.json','["人間姚魏總輿臺，獨占神仙上品開。", "絕代詞華三峽倒，當時諫草九天迴。", "晚晴大白簷前舉，春暖小車花下來。", "筆補浣花溪畔老，吟工壓倒北山萊。"]'),
('74c1f2b9-961a-48b8-be64-fe8d85de4d6e','再答  其三','趙汝騰','宋','宋诗','song-poetry','','[]','孤風獨上子陵臺，藻思天然頃刻開。',64,'全唐诗/poet.song.215000.json','["孤風獨上子陵臺，藻思天然頃刻開。", "銀燭不妨花下照，鐵心肯向賦中迴。", "休懷濯錦江邊夢，早應築沙堤上來。", "急裹紫霞望公至，也教凡卉識仙萊。"]'),
('adc5d255-69fb-48b0-94c8-0adfba889586','答高計使韻','趙汝騰','宋','宋诗','song-poetry','','[]','使承帝命若予工，膴膴周原布惠風。',64,'全唐诗/poet.song.215000.json','["使承帝命若予工，膴膴周原布惠風。", "正似公權懷筆諫，豈如後蔡譜茶功。", "春盈夏涸疑神水，荼苦飴甘屬太空。", "芹獻固知仍舊比，采蘩泂酌亦昭忠。"]'),
('ce476e89-df94-4762-8778-bf61634d8e7e','和高計使郊行','趙汝騰','宋','宋诗','song-poetry','','[]','春光物色伴揚班，晝出城南暮入閽。',64,'全唐诗/poet.song.215000.json','["春光物色伴揚班，晝出城南暮入閽。", "轉蕙風吹禊亭竹，採桑日照女筐蘩。", "清游得共皇華醉，妙語能追紅藥翻。", "一任鵑鳴芳自若，坐間嘉客意同原。"]'),
('53a4303e-42da-4c91-aaa6-a6570e2e56ca','再用韻答謝石嶼庾使','趙汝騰','宋','宋诗','song-poetry','','[]','一翁閒伴兩星臺，亭畔看花花半開。',64,'全唐诗/poet.song.215000.json','["一翁閒伴兩星臺，亭畔看花花半開。", "我盍歸田垂釣隠，公行持橐侍鸞迴。", "流鶑似避宮粧靚，黄鵠曾將蜀種來。", "二妙賡酬康濟手，橫舟句好相推萊。"]'),
('f30f9cc6-0d86-43d1-9fee-2be240cc3e58','紀游一首呈高計使謝庾使','趙汝騰','宋','宋诗','song-poetry','','[]','天風吹我到丹青，不覺春華又再經。',64,'全唐诗/poet.song.215000.json','["天風吹我到丹青，不覺春華又再經。", "芝叟採來雲冉冉，茶仙嘗後水泠泠。", "溪山信美瑯琊景，宇宙無窮峴首亭。", "登者固多公不朽，老衰得附鳳凰翎。"]'),
('c4cf163b-ef5c-4b25-8fa9-99bf7dbd5cb0','復用韻答高計使謝庾使','趙汝騰','宋','宋诗','song-poetry','','[]','何人潄石枕寒青，飛鳥徘徊不敢經。',64,'全唐诗/poet.song.215000.json','["何人潄石枕寒青，飛鳥徘徊不敢經。", "却騎同登觀溟涬，懷仙遥想戒真泠。", "西山南浦臨流閣，北樹東雲把酒亭。", "道極高明須峻絕，鐵獅峰頂振風翎。"]'),
('7d9b839b-85e3-49f3-a2c8-68ec4a313812','陪高計使柱史謝庾使刑郎登梅仙山丹青閣  其一','趙汝騰','宋','宋诗','song-poetry','','[]','侵雲祠宇絕荒凉，目眴憑虛興寄長。',64,'全唐诗/poet.song.215000.json','["侵雲祠宇絕荒凉，目眴憑虛興寄長。", "仙者遠遊非穆穆，天之視下亦蒼蒼。", "貴公業趁塵泥腐，小尉名爭日月光。", "此地何緣子真到，孤忠處處慕留芳。"]'),
('0aadbd0e-c072-4166-b39e-3013aeb1d719','陪高計使柱史謝庾使刑郎登梅仙山丹青閣  其二','趙汝騰','宋','宋诗','song-poetry','','[]','節迎吹帽約郊行，衣裌登危露未零。',64,'全唐诗/poet.song.215000.json','["節迎吹帽約郊行，衣裌登危露未零。", "一笑向時分皂白，相逢今日共丹青。", "清姿照世郎官宿，勁操擎天柱史星。", "自有此山無此客，來同老守醉還醒。"]'),
('2bb0ea7f-1ac2-4610-9954-f519101a8d2d','又和饒計使丹青閣韻','趙汝騰','宋','宋诗','song-poetry','','[]','久聞傑閣願今酬，亭午登臨到上頭。',64,'全唐诗/poet.song.215000.json','["久聞傑閣願今酬，亭午登臨到上頭。", "二水清澄新雨霽，衆峰蒼峭凍雲留。", "擬賡場圃詩人句，休負煙波墨客愁。", "信使偕行原隰耀，仙山多謝約同遊。"]'),
('8b813e42-8564-44b1-9212-f77a130f0414','又再用韻和','趙汝騰','宋','宋诗','song-poetry','','[]','後期採菊約新酬，笑指西風帽戀頭。',64,'全唐诗/poet.song.215000.json','["後期採菊約新酬，笑指西風帽戀頭。", "陸羽久仙泉水在，紫芝何代寺峰留。", "霞邊野霧供吟嘯，澤畔歸鴻免歎愁。", "愧乏登高能賦手，陪公後乘寫清遊。"]'),
('57a467b5-6239-4835-9a95-6edf85eee1ff','徑坂左司使君惠和近詩爲親而喜合天理之公得性情之正復用韻以慶  其一','趙汝騰','宋','宋诗','song-poetry','','[]','扶杖來觀徧老農，清朝新禮采芝翁。',64,'全唐诗/poet.song.215000.json','["扶杖來觀徧老農，清朝新禮采芝翁。", "德尊韋布封員外，恩重牙緋視治中。", "言悟千秋逢主聖，躬行萬石耀臣工。", "求與抑與從天下，徑坂丹忱殿陛通。"]'),
('e2521f21-8e7f-4630-8a7c-91dd7ceb7ecf','徑坂左司使君惠和近詩爲親而喜合天理之公得性情之正復用韻以慶  其二','趙汝騰','宋','宋诗','song-poetry','','[]','何曾學圃學爲農，陋巷蕭然白髮翁。',64,'全唐诗/poet.song.215000.json','["何曾學圃學爲農，陋巷蕭然白髮翁。", "便拜馮唐長郎署，更榮弘景相山中。", "詔褒忠孝垂青史，上想儀型遣畫工。", "莊叟湛然元不動，平生風雨視窮通。"]'),
('485d0425-ac21-4245-b8ed-26dbb6e99924','奏徑坂尊公致政盛德於上就以詩報之','趙汝騰','宋','宋诗','song-poetry','','[]','拜疏歸田學老農，天高未肯聽衰翁。',64,'全唐诗/poet.song.215000.json','["拜疏歸田學老農，天高未肯聽衰翁。", "逸民且舉邵康節，有子併稱程大中。", "給札說書皆御墨，教忠錫爵勵羣工。", "老臣只代臣頤請，頤不祈恩何自通。"]'),
('1c697d6a-6ad8-4a0b-ba73-3f6d0751fffb','贊徑坂使君柯山仲春講席之盛','趙汝騰','宋','宋诗','song-poetry','','[]','贏糧多士二千餘，爭向柯山講席隅。',64,'全唐诗/poet.song.215000.json','["贏糧多士二千餘，爭向柯山講席隅。", "立天地心鳴道鐸，開生靈眼識師儒。", "孔融魯國奇男子，孟氏鄒人大丈夫。", "我在紫霞洲上笑，惜無羽翼到三衢。"]'),
('46db255b-cb91-4904-b9d2-054fe3a8e4b0','驛至得徑坂講席帛詩喜甚和韻且堅秋風武夷之約  其一','趙汝騰','宋','宋诗','song-poetry','','[]','驛足歸來以口陳，爛柯山色碧嶙峋。',64,'全唐诗/poet.song.215000.json','["驛足歸來以口陳，爛柯山色碧嶙峋。", "橫經二月二十一，聽講三千三百人。", "聖者子孫皆在列，愚而夫婦也知津。", "衰翁首看法筵義，文與正蒙相比倫。"]'),
('5f81e1e7-ec25-4977-8876-fad3af106d8e','驛至得徑坂講席帛詩喜甚和韻且堅秋風武夷之約  其二','趙汝騰','宋','宋诗','song-poetry','','[]','紫霞老子望青霞，喜誦新吟倚鬂華。',64,'全唐诗/poet.song.215000.json','["紫霞老子望青霞，喜誦新吟倚鬂華。", "已遣鳴騶迎道左，那知紉佩尚天涯。", "爲莊椿壽稱觴近，訪武夷仙卜日賒。", "秋夜月明遊九曲，櫂歌聲裏賦巖花。"]'),
('9b380de6-096f-483c-8eb4-6898713b2446','和徐徑坂帛詩韻併約徐立大同賦','趙汝騰','宋','宋诗','song-poetry','','[]','謁想仙姿詩見之，壇高屈宋隸吾麾。',64,'全唐诗/poet.song.215000.json','["謁想仙姿詩見之，壇高屈宋隸吾麾。", "在邦無怨仁何怨，與世多違道不違。", "一魯丈夫獨儒服，百曹相國漫戎衣。", "折衝人物山中隠，誰佐君王立德威。"]'),
('b3998d71-cd7c-4942-a9c0-7d93bae4157e','夢徐徑坂','趙汝騰','宋','宋诗','song-poetry','','["\u897f\u6e56"]','誰云姑蔑遠無諸，夢繞柯僊抱膝廬。',64,'全唐诗/poet.song.215000.json','["誰云姑蔑遠無諸，夢繞柯僊抱膝廬。", "我得閒中繙魯語，公應靜裏玩羲圖。", "雷猶地伏陽新復，雲向天升雨可需。", "好倡諸賢爲時出，只容衰嬾老西湖。"]'),
('8353d582-1efb-45be-8aba-bd42201cdd42','用前韻呈史繡使','趙汝騰','宋','宋诗','song-poetry','','[]','吁嗟膚使襟期厚，來顧陳人老鬢班。',64,'全唐诗/poet.song.215000.json','["吁嗟膚使襟期厚，來顧陳人老鬢班。", "席地樽開樵舍畔，停雲興在玉柯間。", "不知天上皇華貴，也共山中半日閒。", "好向金門領名勝，獨留一叟弄潺湲。"]'),
('96a04d12-1fc7-4ca5-b015-c71a3954da95','和史繡使瑞梅韻','趙汝騰','宋','宋诗','song-poetry','','[]','憶昔朝旌別未央，逋仙風味飽嚌嘗。',64,'全唐诗/poet.song.215000.json','["憶昔朝旌別未央，逋仙風味飽嚌嘗。", "繡衣來酹東濤月，清節更餐南雪香。", "姑射真仙陪直指，綠華再萼瑞高堂。", "蓬萊花使傳春信，早晚芝書趣覲王。"]'),
('3fa27ff3-a8a4-410c-9f39-67506309189b','餞史計使  其一','趙汝騰','宋','宋诗','song-poetry','','[]','祥刑生意徧庭荄，蔽芾棠陰手自栽。',64,'全唐诗/poet.song.215000.json','["祥刑生意徧庭荄，蔽芾棠陰手自栽。", "世降此翁猶尚德，俗衰時輩但論材。", "九仙截𩍐于公去，萬石熏爐召父來。", "攬轡紫陽垂教地，饒何盍聘到崇臺。"]'),
('c4d8d8b8-4a09-4c95-a919-194ef19709c0','餞史計使  其二','趙汝騰','宋','宋诗','song-poetry','','[]','使者星明太史占，東風戒路揭帷襜。',64,'全唐诗/poet.song.215000.json','["使者星明太史占，東風戒路揭帷襜。", "食當加倍稀親酒，獻不求餘少榷鹽。", "因進御茶供味諫，肯然官燭示家廉。", "老生莫效臨岐贈，詩附仁言當束縑。"]'),
('89d6b54e-269c-4729-81a6-07291640d23b','懷史計使','趙汝騰','宋','宋诗','song-poetry','','[]','皇華叱馭遂驅馳，抱病怱怱語別離。',64,'全唐诗/poet.song.215000.json','["皇華叱馭遂驅馳，抱病怱怱語別離。", "不到天風海濤地，空吟春樹暮雲詩。", "似聞信宿留桑下，惜不扁舟趁水涯。", "一笑論文何日再，玉川爲我說相思。"]'),
('0ca65245-703a-42b8-9bfb-0e841c613239','謝史計使寄建茗','趙汝騰','宋','宋诗','song-poetry','','[]','皇華珍意辦頭綱，餘馥吾儕也得嘗。',64,'全唐诗/poet.song.215000.json','["皇華珍意辦頭綱，餘馥吾儕也得嘗。", "黯戇終然言有味，仝衰那得字搜腸。", "耕雲隴畔知無憾，貯月瓢中剩有香。", "獨念郊民多菜色，旱饑粟價踴非常。"]'),
('1d547628-1fd2-4610-b930-af07dc070a02','鎖院既久考文將畢適承按察使房公子靖遣詩相慰因和以答','趙汝騰','宋','宋诗','song-poetry','','[]','恭承禮聘典文宗，秉筆秋闈合至公。',64,'全唐诗/poet.song.215000.json','["恭承禮聘典文宗，秉筆秋闈合至公。", "城郭縱遊知有日，院門深鎖寂無風。", "掄才未擬升司馬，發策方將問卧龍。", "忽辱有詩相慰藉，一時裁答愧怱怱。"]'),
('1a40891f-b116-48b6-99c2-b19702d8db56','別伯輿新鄱陽廣文','趙汝騰','宋','宋诗','song-poetry','','[]','特爲予來冬復春，重尋舊話續新聞。',64,'全唐诗/poet.song.215000.json','["特爲予來冬復春，重尋舊話續新聞。", "諸儒學北今誰嗣，獨步斗南猶有君。", "精舍諸生朝問道，郡齋一叟夜論文。", "縶維不可成分袂，搔首江東日暮雲。"]'),
('92897b79-96a6-4252-ad39-967b3f268d5d','呈竹湖李端明','趙汝騰','宋','宋诗','song-poetry','','["\u897f\u6e56"]','淳祐清忠推杜李，巋然名德頼公存。',64,'全唐诗/poet.song.215000.json','["淳祐清忠推杜李，巋然名德頼公存。", "歲時闊會英耆社，風月稀游獨樂園。", "一榻自觀心主靜，諸賢欲扣我忘言。", "僕歸借屋西湖畔，半載才能兩造門。"]'),
('ed50265c-a820-4cb1-b3bf-93714c172ebb','再用韻答','趙汝騰','宋','宋诗','song-poetry','','[]','敬簡如翁吾所慕，即之目擊道斯存。',64,'全唐诗/poet.song.215000.json','["敬簡如翁吾所慕，即之目擊道斯存。", "斥歸借卧平泉石，倦出幾名傲吏園。", "早日寒齋令尚友，近來徑坂寄傳言。", "文山歲晚梅如雪，擬約龐公到鹿門。"]'),
('76a94739-153c-4742-8f79-2d0129c444ac','次韻叔興見贈','趙汝騰','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','眼界紛紛盡掃除，雲烟杳霧是匡廬。',64,'全唐诗/poet.song.215000.json','["眼界紛紛盡掃除，雲烟杳霧是匡廬。", "江山信美非吾土，井邑繁雄想舊廬。", "落筆縱橫看草檄，感時憂憤欲成書。", "要須起赴功名會，莫守陳編似蠹魚。"]'),
('e9b561d8-909f-463c-804d-75d29bb71f85','寄新衡陽徐使君左司山長','趙汝騰','宋','宋诗','song-poetry','','[]','醉墨淋漓天地間，誰知大德不踰閑。',64,'全唐诗/poet.song.215000.json','["醉墨淋漓天地間，誰知大德不踰閑。", "世無孔子今希孔，國有顔淵易鑄顔。", "多士龍門一喬岳，斯文牛耳兩名山。", "暮春九曲峰前水，一笑風雩氣象還。"]'),
('8d157fc5-18b6-46d3-8675-79544b8b7a18','贈徐國諭','趙汝騰','宋','宋诗','song-poetry','','[]','英英直氣驗操存，夜校羣書日灌園。',64,'全唐诗/poet.song.215000.json','["英英直氣驗操存，夜校羣書日灌園。", "嬾不到城三十載，老猶落筆數千言。", "吳公何敢輕招賈，徐穉茲來特訪蕃。", "衰拙邇來逢盛事，德星遠遠照朱轓。"]'),
('202b9382-902d-4eae-8cca-143e3d665098','贈蕭高士','趙汝騰','宋','宋诗','song-poetry','','[]','槃澗老龍埋骨久，交游得爾最知心。',64,'全唐诗/poet.song.215000.json','["槃澗老龍埋骨久，交游得爾最知心。", "詩摹海嶼天風景，琴弄仙臺玉笥音。", "疇昔羽衣曾過我，只今石鼎又聯吟。", "丹成若欲歸山去，恐被人間有物侵。"]'),
('b51f90f1-7e3a-4005-996f-f650f5099303','贈隆中黄進士','趙汝騰','宋','宋诗','song-poetry','','[]','徧遊天下好山川，歸向隆中葺數椽。',64,'全唐诗/poet.song.215000.json','["徧遊天下好山川，歸向隆中葺數椽。", "似慕孔明效龍卧，尚隨陶侃指牛眠。", "詩書發冢笑何益，富貴乞墦嗟可憐。", "若語人時勸忠孝，福田不似種心田。"]'),
('550c81a2-0dad-4782-86cf-ea3fa22fbe92','勉癸丑新進士','趙汝騰','宋','宋诗','song-poetry','','[]','霞州守吏慶筵開，喜爲朝家得俊材。',64,'全唐诗/poet.song.215000.json','["霞州守吏慶筵開，喜爲朝家得俊材。", "九曲山川增氣槩，八元人物照樽罍。", "讖佳將報淮沙合，文煥新迎御扁來。", "不朽榮華軒冕外，君看雲谷勝雲臺。"]'),
('4cec4670-2208-463a-a8ff-1deb2c9f626b','餞盧威仲','趙汝騰','宋','宋诗','song-poetry','','[]','狐腋羊皮孰劣優，每嗟里社尚沉浮。',64,'全唐诗/poet.song.215000.json','["狐腋羊皮孰劣優，每嗟里社尚沉浮。", "千篇南雪題幾徧，一馬東風去不留。", "吳地名高誦梅福，漢廷語吉趣朱游。", "柯山若問衰陳跡，爲說猶懷畎畝憂。"]'),
('53fe0f4b-6a71-4aa0-a175-bb4887f81a37','再用韻答','趙汝騰','宋','宋诗','song-poetry','','[]','當年骯髒厄伊優，身寄枌榆宅尚浮。',64,'全唐诗/poet.song.215000.json','["當年骯髒厄伊優，身寄枌榆宅尚浮。", "芝鳳未肦羔屢聘，檣烏將發燕難留。", "朝廷終念孔文舉，里社回思馬少游。", "煙霧滄波休健羨，吾儕嫠緯莫忘憂。"]'),
('63da28ca-2fbf-43f8-b871-920e3f4a78a9','寄六湖陳如晦','趙汝騰','宋','宋诗','song-poetry','','[]','琴劍前時爲我來，志同道合味悠哉。',64,'全唐诗/poet.song.215000.json','["琴劍前時爲我來，志同道合味悠哉。", "每憐一水馬頭險，惜放斯人鷁首回。", "魯語手箋應畢卷，汾亭指授想多材。", "不知肯踐詩盟否，菊已凋零梅又開。"]'),
('4b3ae8ed-e44f-4708-b238-e265ad6ea16a','寄程滄洲','趙汝騰','宋','宋诗','song-poetry','','[]','山間藜杖看初春，忽報滄洲除命新。',64,'全唐诗/poet.song.215000.json','["山間藜杖看初春，忽報滄洲除命新。", "今日昌黎司憲部，幾年陸贄任詞臣。", "扶持世道豈無策，宗主時賢今有人。", "老懶貴遊書盡絕，一詩隃寄霅江濱。"]'),
('bdc7ed6d-8504-43dc-9906-1c850cbfa830','寄盧玉堂武子','趙汝騰','宋','宋诗','song-poetry','','[]','建上文忠音響絕，爾來復說蔡翁盧。',64,'全唐诗/poet.song.215000.json','["建上文忠音響絕，爾來復說蔡翁盧。", "君歸南浦顔無怍，我老西河道不孤。", "空有寸心馳記室，絕無一字到中都。", "吟成遣寄嗟何闊，開卷應嗤此叟迂。"]'),
('cf53ec46-59d3-4b68-8b29-898d38330216','詗李斛峰右司','趙汝騰','宋','宋诗','song-poetry','','[]','數士英英未易招，當時一網盡于蕭。',64,'全唐诗/poet.song.215000.json','["數士英英未易招，當時一網盡于蕭。", "公才何止爲陳瓘，朝論今爭推杜喬。", "國定須賢扶宇宙，士惟知道樂簞瓢。", "鳳凰千仞需時下，讒說新來已雪消。"]'),
('98525b2a-cf2d-4cc7-a9cf-5551fc5460b6','詗斛峰李純父右司','趙汝騰','宋','宋诗','song-poetry','','[]','衰拙新來領建安，郡齋夜夢繞餘干。',64,'全唐诗/poet.song.215000.json','["衰拙新來領建安，郡齋夜夢繞餘干。", "東都得爾名節重，西賊聞之心膽寒。", "海內四賢尚家食，閩中一叟愧空餐。", "幔亭仙掌文盟在，好與伯輿來共看。"]'),
('cab14d4c-53a2-42ef-af8d-dc9da2f8dc26','詗湖南刑使趙紫薇','趙汝騰','宋','宋诗','song-poetry','','[]','繡節當年立碧霄，至今遺愛藹懽謠。',64,'全唐诗/poet.song.215000.json','["繡節當年立碧霄，至今遺愛藹懽謠。", "雲烟何止能開霽，山嶽曾聞亦動摇。", "縱未振衣華表著，不應分席混漁樵。", "餘干宰士今喬固，定有詩筒慰寂寥。"]'),
('2a333ba4-6bc5-4f72-b270-6d1bde531fb1','登石鼓追思武夷餘干二老呈威仲','趙汝騰','宋','宋诗','song-poetry','','[]','雲間把酒更持螯，九日登臨意氣豪。',64,'全唐诗/poet.song.215000.json','["雲間把酒更持螯，九日登臨意氣豪。", "自有此山題墨富，獨推二老擅名高。", "禪關曾訪移泉脈，亭扁重書鎮海濤。", "老我空遊愧能賦，得君藻筆僕名騷。"]'),
('7d13d75a-7752-45ac-9be3-6798e11db8ef','再用韻答','趙汝騰','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','不羨叢菊并二螯，羨君出語真俊豪。',64,'全唐诗/poet.song.215000.json','["不羨叢菊并二螯，羨君出語真俊豪。", "崛奇退之石鼓句，清逸永叔廬山高。", "壯懷傾倒湧泉寺，健筆噓吸滄海濤。", "後期進步登大頂，上續風雅卑莊騷。"]'),
('28e5f134-6254-4503-a956-e7cbc482beaf','巖溪書堂登眺','趙汝騰','宋','宋诗','song-poetry','','[]','崎嶇穿竹籃輿側，高下捫蘿石徑幽。',64,'全唐诗/poet.song.215000.json','["崎嶇穿竹籃輿側，高下捫蘿石徑幽。", "虎豹遁時深谷窈，魚龍舞處大江浮。", "公難閒坐山中相，我久吟披澤畔裘。", "白石清泉知此意，請將直釣釣璜流。"]'),
('82cab322-9926-4903-a8f4-13eed8904440','湧泉亭','趙汝騰','宋','宋诗','song-poetry','','[]','湧泉亭畔坐蒙茸，手指三江撫萬松。',64,'全唐诗/poet.song.215000.json','["湧泉亭畔坐蒙茸，手指三江撫萬松。", "石鼓生雲深有意，珠驪吐水密無蹤。", "禽聲人語同時樂，林影日華相映重。", "邂逅一樽開笑口，菊萸猶笑不從容。"]'),
('64c9994b-bc09-4379-8860-c9c8e213b7fd','挽王國錄','趙汝騰','宋','宋诗','song-poetry','','[]','華峰早日得追隨，議論詞章頗俊奇。',64,'全唐诗/poet.song.215000.json','["華峰早日得追隨，議論詞章頗俊奇。", "五羖固應羞自鬻，一夔惜不佐來儀。", "東嘉把盞論文日，婺女停舟問易時。", "黄壤竟埋斯士骨，推賢不早嘆珠遺。"]'),
('36a71aa7-3e6e-4c3e-a3fc-d290466ae38a','挽岩雲趙使君','趙汝騰','宋','宋诗','song-poetry','','[]','憶與東岩居里社，蘿雲松月共詩盟。',64,'全唐诗/poet.song.215000.json','["憶與東岩居里社，蘿雲松月共詩盟。", "傷心遂哭公三世，墮淚難招爾九京。", "領郡抗章生掇禍，過庭吟稿死留名。", "似聞難弟尤儒雅，好率諸郎副旦評。"]'),
('340ada88-189c-45e8-88d7-366f899679d6','挽鄭知府','趙汝騰','宋','宋诗','song-poetry','','[]','先正當年遇阜陵，在廷玉立指忠清。',64,'全唐诗/poet.song.215000.json','["先正當年遇阜陵，在廷玉立指忠清。", "甘棠笏得孫枝紹，使竹符分棣萼榮。", "七袠駸駸登上壽，諸郎鼎鼎擅英名。", "北邙千古知無恨，吟些聊供薤露聲。"]'),
('ccdc1c0e-3019-4088-b26c-48e17ca75936','挽朱夫人','趙汝騰','宋','宋诗','song-poetry','','[]','蘭陔送母度新阡，追憶東岩老謫仙。',64,'全唐诗/poet.song.215000.json','["蘭陔送母度新阡，追憶東岩老謫仙。", "虀辦咄嗟供婦職，肝刲一再續親年。", "六珈偕老榮何盛，二子乘舟晚可憐。", "彤管責堪陳信史，今將列女傳同編。"]'),
('2b943b07-fdd6-4294-aa01-c9aeab4e2c19','寄李頤老','趙汝騰','宋','宋诗','song-poetry','','[]','易說刊成未，心傳自法雲。',24,'全唐诗/poet.song.215000.json','["易說刊成未，心傳自法雲。", "寄聲揚舶使，一力主斯文。"]'),
('b2c10645-1571-40ea-b8e4-054d54050f31','柬陳讜送鵝','趙汝騰','宋','宋诗','song-poetry','','[]','鶃鶃何爲至，於陵轉饋予。',24,'全唐诗/poet.song.215000.json','["鶃鶃何爲至，於陵轉饋予。", "出哇吾不敢，笑付老庖厨。"]'),
('a4691fe1-b7ee-4eb4-a67c-3aff4a3c074f','寄仲節金華牧二首  其一','趙汝騰','宋','宋诗','song-poetry','','[]','猶記衰翁佩印初，曾將四學勸羣儒。',32,'全唐诗/poet.song.215000.json','["猶記衰翁佩印初，曾將四學勸羣儒。", "只今郡守西山後，好勉人人誦呂朱。"]'),
('96f495d8-b97e-4ae6-b04e-f835825b36fe','寄仲節金華牧二首  其二','趙汝騰','宋','宋诗','song-poetry','','[]','傳聞議論異柯山，辨難何妨莫失懽。',32,'全唐诗/poet.song.215000.json','["傳聞議論異柯山，辨難何妨莫失懽。", "試取景仁與君實，中和問答幾書看。"]'),
('81c0792f-f6da-45f2-b3d1-a9700f3aa2c2','寄程滄洲','趙汝騰','宋','宋诗','song-poetry','','[]','身是金華舊使君，聞公新渥倍懽忻。',32,'全唐诗/poet.song.215000.json','["身是金華舊使君，聞公新渥倍懽忻。", "朱轓暫爲東萊起，收拾乾淳未墜文。"]'),
('74ed4405-406d-4311-8058-0308f9697fd8','寄高耻堂','趙汝騰','宋','宋诗','song-poetry','','[]','江西格了使湖南，又似當年朱晦菴。',32,'全唐诗/poet.song.215000.json','["江西格了使湖南，又似當年朱晦菴。", "問學如公真少輩，請將大道講氈談。"]'),
('2ecc0453-927a-427a-a7a6-5fb36024e531','寄徐左司  其一','趙汝騰','宋','宋诗','song-poetry','','[]','紫洲洲上得詩筒，展誦青霞在眼中。',32,'全唐诗/poet.song.215000.json','["紫洲洲上得詩筒，展誦青霞在眼中。", "白首漫郎應號叟，黑頭永叔早稱翁。"]'),
('49ddd5fa-eabd-415d-8cde-d267cb31a1d6','寄徐左司  其二','趙汝騰','宋','宋诗','song-poetry','','[]','人皆山斗瞻吏部，誰敢文章近左司。',32,'全唐诗/poet.song.215000.json','["人皆山斗瞻吏部，誰敢文章近左司。", "君看玉池金鯽句，盡刊腥腐带僊姿。"]'),
('923fbb98-069a-41e6-b225-018c06e2b74b','贈李喜觀謁徐徑坂','趙汝騰','宋','宋诗','song-poetry','','[]','一世龍門未易攀，鯫生負笈造柯山。',32,'全唐诗/poet.song.215000.json','["一世龍門未易攀，鯫生負笈造柯山。", "束脩以上吾斯誨，應許吟風立雪還。"]'),
('7a6dfd28-95dc-4d42-9da9-9e70d885def9','贈林行簡見徐徑坂','趙汝騰','宋','宋诗','song-poetry','','[]','紫霞洲上雨如絲，白髮衰翁有所思。',32,'全唐诗/poet.song.215000.json','["紫霞洲上雨如絲，白髮衰翁有所思。", "吟付三山林敬則，爛柯國手尚觀棋。"]'),
('2fc3f899-7eb8-49df-a952-36d1fb1fce4b','和韻詗徐徑坂','趙汝騰','宋','宋诗','song-poetry','','[]','聖斷鋤姦不大聲，傳聞側席遲幽人。',32,'全唐诗/poet.song.215000.json','["聖斷鋤姦不大聲，傳聞側席遲幽人。", "人今天民之先覺，幡然風俗還振振。"]'),
('804f1caa-03c8-490e-bcab-e15bbe3262c6','次徐徑坂衡陽使君韻示林敬則','趙汝騰','宋','宋诗','song-poetry','','[]','千仞岡頭一振衣，共嗟鳳德卧郊扉。',32,'全唐诗/poet.song.215000.json','["千仞岡頭一振衣，共嗟鳳德卧郊扉。", "近鋤蕭艾知天意，會見朝陽露欲晞。"]'),
('c8ff7ca7-9c32-4012-a4c0-05f74670288c','和徐徑坂衡陽使君韻題漁莊煙雨','趙汝騰','宋','宋诗','song-poetry','','[]','列子御風旬五日，莊周稱壽八千秋。',32,'全唐诗/poet.song.215000.json','["列子御風旬五日，莊周稱壽八千秋。", "歸歟烟雨濛濛景，萼集班衣賸勸酬。"]'),
('02fd7094-0fde-4949-beb1-b412db293abc','送江墨莊  其一','趙汝騰','宋','宋诗','song-poetry','','[]','徑坂仙翁名蓋代，得君膠法喜臨池。',32,'全唐诗/poet.song.215000.json','["徑坂仙翁名蓋代，得君膠法喜臨池。", "鷄林鼠島皆知重，爾亦聲華萬古垂。"]'),
('9b1fdc84-dc72-40ba-99d8-2f7bce6a4897','送江墨莊  其二','趙汝騰','宋','宋诗','song-poetry','','[]','寄語玉柯賢太守，萬間精舍有詩盟。',32,'全唐诗/poet.song.215000.json','["寄語玉柯賢太守，萬間精舍有詩盟。", "邇來曾踐斯言否，此事須公劇力成。"]'),
('42d2cc68-1aaa-4d90-887f-c19775022e6c','送陳善世  其一','趙汝騰','宋','宋诗','song-poetry','','[]','似聞久客滄洲館，曷不相從早數年。',32,'全唐诗/poet.song.215000.json','["似聞久客滄洲館，曷不相從早數年。", "老我一丘事耕釣，勞君千里度山川。"]'),
('7147e171-224c-4e14-aa3e-9a0be6b4c0cd','送陳善世  其二','趙汝騰','宋','宋诗','song-poetry','','[]','抱琴幾宿滯秦溪，多謝常丞寄近詩。',32,'全唐诗/poet.song.215000.json','["抱琴幾宿滯秦溪，多謝常丞寄近詩。", "細咀絕無烟火氣，其人可與遡濂伊。"]'),
('724216fc-377e-47f7-9a7a-42c8c844063f','送陳善世  其三','趙汝騰','宋','宋诗','song-poetry','','[]','不須遠遠苦求師，恭敬淵源可細推。',32,'全唐诗/poet.song.215000.json','["不須遠遠苦求師，恭敬淵源可細推。", "歸路瑞安逢二戴，爲予再四說相思。"]'),
('7e278ce0-dc9f-46c8-8d6f-38f4b38a47f6','答鄭宜中  其一','趙汝騰','宋','宋诗','song-poetry','','[]','太極成爭今幾年，濂翁先得我同然。',32,'全唐诗/poet.song.215000.json','["太極成爭今幾年，濂翁先得我同然。", "經行醉墨怱怱就，不謂朋儕今競傳。"]'),
('847f44a0-0e9b-4b93-9f62-357fcf67f69a','答鄭宜中  其二','趙汝騰','宋','宋诗','song-poetry','','[]','畏暑門稀問字徒，袖中妙語契周圖。',32,'全唐诗/poet.song.215000.json','["畏暑門稀問字徒，袖中妙語契周圖。", "知君十倍侯芭學，老我非雄尚索塗。"]'),
('c204b48d-a8c2-4bc6-93bb-f4e7fae191b0','贈魏安石','趙汝騰','宋','宋诗','song-poetry','','[]','彈鋏歸歟何太速，捫腹掀髯飽藷粥。',32,'全唐诗/poet.song.215000.json','["彈鋏歸歟何太速，捫腹掀髯飽藷粥。", "囊空裘敝未全貧，賸買松明照幽讀。"]'),
('49a46a64-5465-4a15-bece-d8656e6a1599','偶見孟博送仲久詩章輒題二絕代贈  其一','趙汝騰','宋','宋诗','song-poetry','','[]','扁舟乘興山陰道，春半園林雪未消。',32,'全唐诗/poet.song.215000.json','["扁舟乘興山陰道，春半園林雪未消。", "便解貂裘從我在，小窗幽寂共簞瓢。"]'),
('64a97bdc-c6e0-4f19-a994-fc8ab6d75f07','偶見孟博送仲久詩章輒題二絕代贈  其二','趙汝騰','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','且看青山覆白雲，悠悠世事謾知聞。',32,'全唐诗/poet.song.215000.json','["且看青山覆白雲，悠悠世事謾知聞。", "扁舟却絕長江去，回首紅塵路欲分。"]'),
('9af50b1c-dfd9-4493-81e6-5e4c8e5522bb','因遣鄉書贈姜山嗣師','趙汝騰','宋','宋诗','song-poetry','','[]','近市依湖十里間，扁舟朝往暮能還。',32,'全唐诗/poet.song.215000.json','["近市依湖十里間，扁舟朝往暮能還。", "莫教老圃翻鋤盡，留我他年葬骨山。"]'),
('a4559921-69c3-4a67-89ab-1d78cf8624f1','彭松溪簿來承絕句以紫霞翁見號因自號爲紫霞翁成二絕走呈徑坂  其一','趙汝騰','宋','宋诗','song-poetry','','[]','名齋取義本凡庸，借屋蓬萊理釣篷。',32,'全唐诗/poet.song.215000.json','["名齋取義本凡庸，借屋蓬萊理釣篷。", "特爲紫陽訪霞紫，臨流一笑就稱翁。"]'),
('acc46242-a70a-4c6d-b894-b769b647d183','彭松溪簿來承絕句以紫霞翁見號因自號爲紫霞翁成二絕走呈徑坂  其二','趙汝騰','宋','宋诗','song-poetry','','[]','南澗當年浚紫洲，我今取號自虛舟。',32,'全唐诗/poet.song.215000.json','["南澗當年浚紫洲，我今取號自虛舟。", "倚欄惆悵青霞遠，何日從君飛珮游。"]'),
('bab3a040-5b0b-4a42-a758-aa87b1365204','壽致政徐光祿','趙汝騰','宋','宋诗','song-poetry','','[]','易躋廿四中書考，難聚三千聽講生。',32,'全唐诗/poet.song.215000.json','["易躋廿四中書考，難聚三千聽講生。", "入侍親庭爲一笑，方瞳弘景轉精神。"]'),
('93685b0f-3249-4fbb-965b-fdcd22b9a52d','題永陽文獻錄  其一','趙汝騰','宋','宋诗','song-poetry','','[]','姦魂偃月忌吳黄，正氣難摧百鍊剛。',32,'全唐诗/poet.song.215000.json','["姦魂偃月忌吳黄，正氣難摧百鍊剛。", "奇響後來誰接續，玉川拜疏植綱常。"]'),
('9be9c4ab-16cf-4f6d-8611-3f91b73ba146','題永陽文獻錄  其二','趙汝騰','宋','宋诗','song-poetry','','[]','冢中夷跖同枯骨，身後逢干享令名。',32,'全唐诗/poet.song.215000.json','["冢中夷跖同枯骨，身後逢干享令名。", "讀遍永陽文獻錄，可憐齰舌老司成。"]'),
('e1b096a8-4723-4983-9f62-e32b9eee703c','會饒伯輿徐子薦徐立大三高士一首','趙汝騰','宋','宋诗','song-poetry','','[]','英英奇節東州彥，凜凜清風南浦豪。',32,'全唐诗/poet.song.215000.json','["英英奇節東州彥，凜凜清風南浦豪。", "更有餘干饒有道，建安堂上聚三高。"]'),
('43fcd987-df76-4454-a734-2524496bf314','秋詞','趙汝騰','宋','宋诗','song-poetry','','[]','雨放凉飈晚復晴，小窗人亦共秋清。',32,'全唐诗/poet.song.215000.json','["雨放凉飈晚復晴，小窗人亦共秋清。", "月華網在蛛絲上，錯認踈簾挂水晶。"]'),
('02e240c7-7312-4282-a545-da7c1bd39a06','餞新三衢牧常著郎','趙汝騰','宋','宋诗','song-poetry','','[]','咫尺去天郡，少雙名世儒。',48,'全唐诗/poet.song.215000.json','["咫尺去天郡，少雙名世儒。", "兩轓建有日，五袴周無襦。", "孔廟雲來祀，柯山衿珮趨。", "常侯振文化，相業起於衢。"]'),
('f8388492-a339-4991-9fe1-073b735d9a1e','句  其一','趙汝騰','宋','宋诗','song-poetry','','[]','陽萌知獨復，歲寒見孤潔。',12,'全唐诗/poet.song.215000.json','["陽萌知獨復，歲寒見孤潔。"]'),
('fa20acc8-1e38-469d-8d7b-92b457bfb647','句  其二','趙汝騰','宋','宋诗','song-poetry','','[]','蕙菊未開傾竹葉，柴桑有夢繞籃輿。',16,'全唐诗/poet.song.215000.json','["蕙菊未開傾竹葉，柴桑有夢繞籃輿。"]'),
('68602e93-c3e2-44d7-98ff-4d88d4a51f78','句  其三','趙汝騰','宋','宋诗','song-poetry','','[]','芳草綠邊陋鸚鵡，楊花飛處避河豚。',16,'全唐诗/poet.song.215000.json','["芳草綠邊陋鸚鵡，楊花飛處避河豚。"]'),
('d9a2d328-4e5d-4ccd-a057-72eae55d1506','秋闈鎖試贈趙茂實','房子靖','宋','宋诗','song-poetry','','[]','吳淞人物老儒宗，閩浙文章屬鉅公。',64,'全唐诗/poet.song.215000.json','["吳淞人物老儒宗，閩浙文章屬鉅公。", "竹葉幾杯惟對酒，棘闈數仞不通風。", "較文已辨珉兼玉，揭榜應知魚化龍。", "近日有心來聽教，奈何方面事匆匆。"]'),
('76b261d0-e7c2-4a2f-8f14-556c52b52c36','偈頌八十五首  其一','釋妙倫','宋','宋诗','song-poetry','','[]','二千年前，我不如你。',31,'全唐诗/poet.song.215000.json','["二千年前，我不如你。", "二千年後，你不如我。", "看看，冷處與你著把火。"]'),
('b8fba7e8-dbd9-49e3-a51c-e99742b5efc3','偈頌八十五首  其二','釋妙倫','宋','宋诗','song-poetry','','[]','橫一丈，豎十尺。',40,'全唐诗/poet.song.215000.json','["橫一丈，豎十尺。", "明眼衲僧，近傍不得。", "若有人向這裏轉得身吐得氣，祇園水也未到你喫。"]'),
('3050df49-a655-4769-b4b0-490eff0310f0','偈頌八十五首  其三','釋妙倫','宋','宋诗','song-poetry','','[]','穿人鼻孔，換人眼睛。',29,'全唐诗/poet.song.215000.json','["穿人鼻孔，換人眼睛。", "都來只是這一句子，如何見得，題目分明。"]'),
('ed6d34dd-7803-4219-8a56-33e82d0a4422','偈頌八十五首  其四','釋妙倫','宋','宋诗','song-poetry','','[]','曉花初拆露香新，獨向空山冷襯雲。',32,'全唐诗/poet.song.215000.json','["曉花初拆露香新，獨向空山冷襯雲。", "忽被春風輕觸著，淡紅脫落亂紛紛。"]'),
('0317624b-fc95-499f-8814-1b09fb729ca7','偈頌八十五首  其五','釋妙倫','宋','宋诗','song-poetry','','[]','花間蝶舞，柳上鶑啼。',36,'全唐诗/poet.song.215000.json','["花間蝶舞，柳上鶑啼。", "瞿曇未曉，達磨猶迷。", "分付叢林能事漢，臨機一一好提撕。"]'),
('5202b6cd-e4ee-46fa-ac0a-cc8383e8e20b','偈頌八十五首  其六','釋妙倫','宋','宋诗','song-poetry','','[]','落頼家風彼此知，粗茶淡飯暫相依。',32,'全唐诗/poet.song.215000.json','["落頼家風彼此知，粗茶淡飯暫相依。", "弟兄畢竟難同活，不免分頭各自爲。"]'),
('eb9f3763-9267-4569-a7c9-855155b3b582','偈頌八十五首  其七','釋妙倫','宋','宋诗','song-poetry','','[]','四月八，生悉達，天上人間閙聒聒。',48,'全唐诗/poet.song.215000.json','["四月八，生悉達，天上人間閙聒聒。", "老韶陽，要打殺，爭似祇園舀水驀頭潑。", "阿呵呵，雖是死蛇，會弄也活。"]'),
('069c68cc-2ad6-4f76-9851-b57bd4d86f67','偈頌八十五首  其八','釋妙倫','宋','宋诗','song-poetry','','[]','禪禪，斷貫索左穿右穿。',22,'全唐诗/poet.song.215000.json','["禪禪，斷貫索左穿右穿。", "道道，生苕菷橫掃豎掃。"]'),
('7184d77f-7faa-4689-80a4-8c97e7a23efd','偈頌八十五首  其九','釋妙倫','宋','宋诗','song-poetry','','[]','天自高，地自厚。',38,'全唐诗/poet.song.215000.json','["天自高，地自厚。", "一一不是單，三三亦非九。", "唯愛部瀆山前丘大翁，見人長揖高叉手。"]'),
('62400aeb-2dd3-49fa-b298-ebfb3806af04','偈頌八十五首  其一○','釋妙倫','宋','宋诗','song-poetry','','[]','前半夏已去，新事不添。',34,'全唐诗/poet.song.215000.json','["前半夏已去，新事不添。", "後半夏未來，舊事不減。", "而今新也舊也，拈向一邊。"]'),
('c5b5fd15-39c3-45ad-827f-92a6de6e5b87','偈頌八十五首  其一一','釋妙倫','宋','宋诗','song-poetry','','[]','布袋打開，拄杖拈起。',20,'全唐诗/poet.song.215000.json','["布袋打開，拄杖拈起。", "去也由你，住也由你。"]'),
('e46e2637-9d9d-44d3-a2ab-db4b608ca762','偈頌八十五首  其一二','釋妙倫','宋','宋诗','song-poetry','','[]','靈山話月，曹溪指月。',20,'全唐诗/poet.song.215000.json','["靈山話月，曹溪指月。", "檢點將來，只得半橛。"]'),
('86395ebe-92fe-4ae5-9d43-c10364056f1d','偈頌八十五首  其一三','釋妙倫','宋','宋诗','song-poetry','','["\u5199\u8bd7", "\u4e2d\u79cb\u8282", "\u8d4f\u6708"]','團團離海嶠，漸漸出雲衢。',24,'全唐诗/poet.song.215000.json','["團團離海嶠，漸漸出雲衢。", "此夜一輪滿，清光何處無。"]'),
('f5ef81e6-8e80-404e-b1e4-c927e3a0d40b','偈頌八十五首  其一四','釋妙倫','宋','宋诗','song-poetry','','[]','一夏九十日，今朝事已周。',41,'全唐诗/poet.song.215000.json','["一夏九十日，今朝事已周。", "寒山逢拾得，把手話來由。", "且道話箇什麽，梨出青州，棗出鄭州。"]'),
('5a5357b8-596a-47d9-8dc4-0afb2d64484d','偈頌八十五首  其一五','釋妙倫','宋','宋诗','song-poetry','','[]','面面相對，心心相知。',20,'全唐诗/poet.song.215000.json','["面面相對，心心相知。", "人情若好，喫水也肥。"]'),
('a9b06268-6b15-4883-a98f-c27306ab446f','偈頌八十五首  其一六','釋妙倫','宋','宋诗','song-poetry','','[]','沙鷗盡日戲江濱，幾度浮來幾度沈。',32,'全唐诗/poet.song.215000.json','["沙鷗盡日戲江濱，幾度浮來幾度沈。", "漁笛一聲驚起去，依前飛下碧波心。"]'),
('b5e98771-5edf-43e6-8c67-157a1e3803de','偈頌八十五首  其一七','釋妙倫','宋','宋诗','song-poetry','','[]','躘踵幾隻牯牛，總在瑞峰過夏。',59,'全唐诗/poet.song.215000.json','["躘踵幾隻牯牛，總在瑞峰過夏。", "有心卧月眠雲，無意牽犁拽耙。", "溪東溪西，嶺上嶺下。", "飲水自飲水，喫草自喫草，第一不得犯人苗稼。"]'),
('5f806dcc-b7a6-4fae-b533-d326dde3c847','偈頌八十五首  其一八','釋妙倫','宋','宋诗','song-poetry','','[]','來住瑞峰，去住瑞巖。',28,'全唐诗/poet.song.215000.json','["來住瑞峰，去住瑞巖。", "未操雪曲，且打鄉談，天上人間一十三。"]'),
('06ed2eff-ebc2-467b-9ef1-5eb892457423','偈頌八十五首  其一九','釋妙倫','宋','宋诗','song-poetry','','[]','昔年出此門去，步步踏著。',36,'全唐诗/poet.song.215000.json','["昔年出此門去，步步踏著。", "今日入此門來，頭頭撞著。", "畢竟以何爲驗，洎合道著。"]'),
('3e043176-3823-44f4-b7ba-e084964b98a5','偈頌八十五首  其二○','釋妙倫','宋','宋诗','song-poetry','','[]','內不放出，外不放入。',20,'全唐诗/poet.song.215000.json','["內不放出，外不放入。", "眨得眼來，鐵壁鐵壁。"]'),
('00deac34-12ee-455a-86fb-af5ff24d4a61','偈頌八十五首  其二一','釋妙倫','宋','宋诗','song-poetry','','[]','擒虎兕，辨龍蛇。',32,'全唐诗/poet.song.215000.json','["擒虎兕，辨龍蛇。", "一句子，絕周遮。", "太白不曾登便殿，筆頭昨夜自生花。"]'),
('11e786e7-8d04-42c3-b1bd-574f81cdf1c3','偈頌八十五首  其二二','釋妙倫','宋','宋诗','song-poetry','','[]','峭峻一方，玲瓏八面。',30,'全唐诗/poet.song.215000.json','["峭峻一方，玲瓏八面。", "須彌燈王，有眼者見。", "若不見，隨我脚跟轉。"]'),
('90f3e2db-0773-4a3a-81c6-abd9792bf2fd','偈頌八十五首  其二三','釋妙倫','宋','宋诗','song-poetry','','[]','祇園千樹秀，浄土九蓮敷。',24,'全唐诗/poet.song.215000.json','["祇園千樹秀，浄土九蓮敷。", "多少參玄士，茫茫在半途。"]'),
('02e2589c-68de-48f1-8d0d-3a0ffb9f51dc','偈頌八十五首  其二四','釋妙倫','宋','宋诗','song-poetry','','[]','三條椽下，七尺單前。',66,'全唐诗/poet.song.215000.json','["三條椽下，七尺單前。", "有一則語，天下衲僧做盡伎倆。", "欲會會不得，擬舉舉不全。", "瑞巖老婆心切，略與諸人通一線。", "不容意解，只要心傳，采石渡船。"]'),
('ed87943f-04fc-4d65-b329-2be194cd35aa','偈頌八十五首  其二五','釋妙倫','宋','宋诗','song-poetry','','[]','隠隠烟村聞犬吠，欲尋尋不見人家。',32,'全唐诗/poet.song.215000.json','["隠隠烟村聞犬吠，欲尋尋不見人家。", "忽於橋斷溪回處，流出碧桃三四花。"]'),
('009f7020-f6fc-4353-8e55-fa3438be1faf','偈頌八十五首  其二六','釋妙倫','宋','宋诗','song-poetry','','[]','聖制中，有一訣。',48,'全唐诗/poet.song.215000.json','["聖制中，有一訣。", "上三星，下半月。", "付諸人，須辨別。", "九十日，參教徹。", "參不徹，飲底是洋銅，吞底是熱鐵。"]'),
('451ffcbd-106e-4fe7-a74d-92aa274a1b8e','偈頌八十五首  其二七','釋妙倫','宋','宋诗','song-poetry','','[]','三張白紙，千里同風，此是古人喫不盡底涎唾。',40,'全唐诗/poet.song.215000.json','["三張白紙，千里同風，此是古人喫不盡底涎唾。", "爭如瑞巖，將箇季春極暄，換箇孟夏漸熱。"]'),
('53369e6d-2f0d-450c-8203-ecc635e812d9','偈頌八十五首  其二八','釋妙倫','宋','宋诗','song-poetry','','[]','那一通，你問我，玄關倒插無鬚鎖。',32,'全唐诗/poet.song.215000.json','["那一通，你問我，玄關倒插無鬚鎖。", "等閒一掣掣得開，三箇老婆相對坐。"]'),
('66b95138-86cd-4094-be05-3d69a1e1982b','偈頌八十五首  其二九','釋妙倫','宋','宋诗','song-poetry','','[]','丁出丁，楔出楔。',27,'全唐诗/poet.song.215000.json','["丁出丁，楔出楔。", "老趙州，端的別。", "別別，金剛腦後三斤鐵。"]'),
('52a424ef-61e7-4c25-a23c-203b83264b29','偈頌八十五首  其三○','釋妙倫','宋','宋诗','song-poetry','','[]','水瀉巖前，蛩吟砌下。',50,'全唐诗/poet.song.215000.json','["水瀉巖前，蛩吟砌下。", "問著衲僧，有口如啞。", "百二十日，弄真像假。", "今朝突出拂子頭，浄倮倮，赤灑灑，沒可把。"]'),
('ac7de0f2-a1ed-4421-bceb-b4cb32688722','偈頌八十五首  其三一','釋妙倫','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','秋雲秋水兩依依，塞鴈聲聲度翠微。',32,'全唐诗/poet.song.215000.json','["秋雲秋水兩依依，塞鴈聲聲度翠微。", "多向洞庭芳草岸，楚天空闊不知歸。"]'),
('7bdb56e2-2c7f-47e7-8e7b-a9859c2bc657','偈頌八十五首  其三二','釋妙倫','宋','宋诗','song-poetry','','[]','瑞巖老還債，出生雙耳聵。',52,'全唐诗/poet.song.215000.json','["瑞巖老還債，出生雙耳聵。", "扣道道不知，問禪禪不會。", "怕冷收帽裙，愛凉解衣带。", "上下相依不相怪，由來彼此肚皮大。"]'),
('09c90fe5-b4c7-4344-8655-bf553c6f0aa6','偈頌八十五首  其三三','釋妙倫','宋','宋诗','song-poetry','','[]','九日重陽節，淵明採菊時。',24,'全唐诗/poet.song.215000.json','["九日重陽節，淵明採菊時。", "黄花到處有，何止在東籬。"]'),
('e3bb0420-3fb8-4f88-b4f1-d4dc779d7568','偈頌八十五首  其三四','釋妙倫','宋','宋诗','song-poetry','','[]','華山突兀聳蒼穹，坐斷坤維千萬峰。',32,'全唐诗/poet.song.215000.json','["華山突兀聳蒼穹，坐斷坤維千萬峰。", "潘閬騎馿山下過，只聞啼鳥閙春風。"]'),
('76bf3b65-31f2-4e9a-8c9b-850dc9299e5b','偈頌八十五首  其三五','釋妙倫','宋','宋诗','song-poetry','','[]','游魚澗底沉浮，幽鳥林間上下。',40,'全唐诗/poet.song.215000.json','["游魚澗底沉浮，幽鳥林間上下。", "那堪東園刈麥，西疇插秧。", "小姑摘葉飼蠶，公子揚鞭走馬。"]'),
('b52e9637-41d2-4804-a410-9fae1dc74f60','偈頌八十五首  其三六','釋妙倫','宋','宋诗','song-poetry','','[]','嶄嶄巖石，蔚蔚松蘿。',49,'全唐诗/poet.song.215000.json','["嶄嶄巖石，蔚蔚松蘿。", "左枝右蔓，橫牽豎惹，滿地交羅。", "幾人遭絆倒，反怪葛藤多。", "阿呵呵，跳不出時爭柰何。"]'),
('173f5a7b-87f8-41e4-a5b5-6afbe94f6993','偈頌八十五首  其三七','釋妙倫','宋','宋诗','song-poetry','','[]','後園馿喫草，開口見心肝。',24,'全唐诗/poet.song.215000.json','["後園馿喫草，開口見心肝。", "潘閬倒騎處，有誰能解看。"]'),
('06b1f4a3-b90f-4f7c-93eb-09704a7a95cb','偈頌八十五首  其三八','釋妙倫','宋','宋诗','song-poetry','','[]','小魚吞大魚，尾巴露一橛。',24,'全唐诗/poet.song.215000.json','["小魚吞大魚，尾巴露一橛。", "漁翁醉不知，空把絲綸掣。"]'),
('e288bc24-6288-48f9-9fa4-6bc0b9127dad','偈頌八十五首  其三九','釋妙倫','宋','宋诗','song-poetry','','[]','主人翁，轆轆轉。',107,'全唐诗/poet.song.215000.json','["主人翁，轆轆轉。", "有手脚，無背面。", "或向深山裏敲冰釣魚，或向閙市中炙火摇扇。", "堪笑禪和子，長在蒲團上東討西尋，直是不得一回親見。", "當此自恣，將何證驗。", "瑞巖今夜事不獲已，未免擘破面門開箇方便。", "秋風一陣晚來寒，吹斷白雲三四片。"]'),
('caceab5d-e645-4b67-be39-812e170461dc','偈頌八十五首  其四○','釋妙倫','宋','宋诗','song-poetry','','[]','蕭蕭黄葉埋荒徑，靄靄浮雲鎖野堂。',32,'全唐诗/poet.song.215000.json','["蕭蕭黄葉埋荒徑，靄靄浮雲鎖野堂。", "一陣西風俱埽盡，幾根喬木倚斜陽。"]'),
('170642fd-dd16-404b-a1ca-ade376863652','偈頌八十五首  其四一','釋妙倫','宋','宋诗','song-poetry','','[]','轉身動脚，開口露牙。',77,'全唐诗/poet.song.215000.json','["轉身動脚，開口露牙。", "明明是我，的的非它。", "衲僧不肯向省要處受用，甘自區區於道途之上。", "真可惜，誠可嗟。", "瑞巖老婆心切，未免爲汝指箇歇處。", "便請急急囘首，早早歸家。"]'),
('e3bb464a-15cc-4124-ad1f-a9dc5af9d11b','偈頌八十五首  其四二','釋妙倫','宋','宋诗','song-poetry','','[]','南泉賣身，只貪小利。',66,'全唐诗/poet.song.215000.json','["南泉賣身，只貪小利。", "道吾舞笏，一味鬼戲。", "百丈捲蓆，翻成鈍置。", "趙州喫茶，太煞客氣。", "老大隋更是沒巴鼻，僧問佛法的的意，却道山前麥熟也未。"]'),
('1a393b69-66fa-4508-83bc-40b4a7ba38ee','偈頌八十五首  其四三','釋妙倫','宋','宋诗','song-poetry','','[]','一夏已過了，生涯又復然。',44,'全唐诗/poet.song.215000.json','["一夏已過了，生涯又復然。", "眉毛橫眼上，鼻孔搭唇邊。", "諸人若果疑情未決，但向冷地裏摸索鼻孔看。"]'),
('58af2836-6064-4ba3-8fbd-afe8610765b8','偈頌八十五首  其四四','釋妙倫','宋','宋诗','song-poetry','','[]','鴈山雲，台嶠月。',69,'全唐诗/poet.song.215000.json','["鴈山雲，台嶠月。", "或卷或舒，或圓或缺。", "兩兩三三，朝遊暮往。", "袈裟角，拄杖頭，挑底挑，裹底裹，不妨自怡自悅。", "若到瑞巖定是打教棒折，而今什麽時節。"]'),
('959b5295-de49-4841-bef4-4c0a911014de','偈頌八十五首  其四五','釋妙倫','宋','宋诗','song-poetry','','[]','老姑强作少年時，爛把宮嬙紅粉施。',32,'全唐诗/poet.song.215000.json','["老姑强作少年時，爛把宮嬙紅粉施。", "不管旁邊人冷笑，滿頭猶更插花枝。"]'),
('8d18773d-1162-44b0-b3e9-b237c1e6ff91','偈頌八十五首  其四六','釋妙倫','宋','宋诗','song-poetry','','[]','臘月三十日，一歲已周畢。',24,'全唐诗/poet.song.215000.json','["臘月三十日，一歲已周畢。", "野老競相呼，把火門外立。"]'),
('ed0fbbbc-974d-4735-9c0e-e3caec0ba8a3','偈頌八十五首  其四七','釋妙倫','宋','宋诗','song-poetry','','[]','禪不用參，道不用學。',22,'全唐诗/poet.song.215000.json','["禪不用參，道不用學。", "放下更放下，安樂又安樂。"]'),
('6c0e1590-284d-4093-813d-faf0bb28cb26','偈頌八十五首  其四八','釋妙倫','宋','宋诗','song-poetry','','[]','自把碌磚空裏擲，必端自打自家頭。',32,'全唐诗/poet.song.215000.json','["自把碌磚空裏擲，必端自打自家頭。", "酌然自痛自難說，自著摩挲歸去休。"]'),
('529c9153-ab1c-49eb-b757-68ed91a863a6','偈頌八十五首  其四九','釋妙倫','宋','宋诗','song-poetry','','[]','鮑叔眼下安眉，趙哥口邊著耳。',28,'全唐诗/poet.song.215000.json','["鮑叔眼下安眉，趙哥口邊著耳。", "驀然狹路相逢，兩箇是甚面嘴。"]'),
('8f571527-37c4-4cda-92df-c220e5b69e45','偈頌八十五首  其五○','釋妙倫','宋','宋诗','song-poetry','','[]','寬用工，急著限。',42,'全唐诗/poet.song.215000.json','["寬用工，急著限。", "是也剗，非也剗。", "頂𩕳忽然突出眼，圈圈圞圞，一似古殿裏壁角落頭破燈盞。"]'),
('9d33dc8a-47ff-408b-a397-a03e1aeec013','偈頌八十五首  其五一','釋妙倫','宋','宋诗','song-poetry','','[]','者老和尚，元無所向。',58,'全唐诗/poet.song.215000.json','["者老和尚，元無所向。", "一味麻皮頭，做出萬般樣。", "我也無端被伊葛藤一上，慚愧樁子倒了也。", "銜怨銜恩，含悲合笑，燒一炷香供養。"]'),
('7734a49e-c45a-4a1f-ae19-6e837bce214d','偈頌八十五首  其五二','釋妙倫','宋','宋诗','song-poetry','','[]','庭前新吐一花紅，襲襲馨香醉蜜蜂。',32,'全唐诗/poet.song.215000.json','["庭前新吐一花紅，襲襲馨香醉蜜蜂。", "公子見來情興動，倒吹玉笛弄春風。"]'),
('d08d62cc-63df-4416-ad1d-7b26a1477ec5','偈頌八十五首  其五三','釋妙倫','宋','宋诗','song-poetry','','[]','我有一機，覿面提持。',28,'全唐诗/poet.song.215000.json','["我有一機，覿面提持。", "如擊金石，如奏塤箎，不是知音誰共知。"]'),
('d877ec79-64a1-4293-acf3-c69cdb0b0cd8','偈頌八十五首  其五四','釋妙倫','宋','宋诗','song-poetry','','[]','小姑將彩對花縫，半是深青半是紅。',32,'全唐诗/poet.song.215000.json','["小姑將彩對花縫，半是深青半是紅。", "被賊一時偷去了，渾家空自暗搥胸。"]'),
('7eccd05f-29d1-46fd-91b8-e5550bd18f84','偈頌八十五首  其五五','釋妙倫','宋','宋诗','song-poetry','','[]','雨𩆑寒食，日醖清明。',47,'全唐诗/poet.song.215000.json','["雨𩆑寒食，日醖清明。", "三三兩兩，呼喚踏青。", "禪家流無處著幽情，倒卓烏藤倚石屏，閑聽巖前杜宇一聲聲。"]'),
('89ddd6ba-7a94-4f4d-8ba5-b76c86602408','偈頌八十五首  其五六','釋妙倫','宋','宋诗','song-poetry','','[]','百花叢裏躍鞭過，俊逸風流有許多。',32,'全唐诗/poet.song.215000.json','["百花叢裏躍鞭過，俊逸風流有許多。", "未第儒生偷眼覷，滿懷無柰舊愁何。"]'),
('ffec848c-8a85-431f-aa1f-3df256d0ebfd','偈頌八十五首  其五七','釋妙倫','宋','宋诗','song-poetry','','[]','秋山色老，秋樹葉零。',84,'全唐诗/poet.song.215000.json','["秋山色老，秋樹葉零。", "秋雲影亂，秋水波澄。", "伸手縮手，取之不得，開眼合眼，視之無形。", "五湖衲子，披披搭搭，哆哆和和。", "那裏秤量，者邊匹配。", "瑞巖老漢却不敢與之較重較輕，斤兩分明。"]'),
('f3df2ebe-82dc-42b3-89a5-90709666e908','偈頌八十五首  其五八','釋妙倫','宋','宋诗','song-poetry','','[]','村翁因事扣巫師，禍福通腸直示伊。',32,'全唐诗/poet.song.215000.json','["村翁因事扣巫師，禍福通腸直示伊。", "獲得黄金家富貴，幾多空自起狐疑。"]'),
('9178f4fc-2221-47e0-807e-a811fb286696','偈頌八十五首  其五九','釋妙倫','宋','宋诗','song-poetry','','[]','學道參禪，別無方便。',72,'全唐诗/poet.song.215000.json','["學道參禪，別無方便。", "閙中底靜裏明，靜裏底閙中薦。", "坐斷兩頭，打成一片。", "喜歡豎瞋拳，煩惱呈笑面。", "阿呵呵，瑞巖與麽道，大似落湯螃蟹，七手八脚一時露現。"]'),
('201312da-9b67-451c-a78e-fc2bb764d9cf','偈頌八十五首  其六○','釋妙倫','宋','宋诗','song-poetry','','[]','心心，拙婦穿穴針。',36,'全唐诗/poet.song.215000.json','["心心，拙婦穿穴針。", "智智，巫師駡土地。", "道道，矮子肩栲栳。", "佛佛，烏鴉啗腐骨。"]'),
('3d664b4f-1aa0-470a-81d5-fa34fb8c76ba','偈頌八十五首  其六一','釋妙倫','宋','宋诗','song-poetry','','[]','坐底立，立底坐。',29,'全唐诗/poet.song.215000.json','["坐底立，立底坐。", "我即你，你即我。", "畢竟燒香禮拜誰，幾成話墮。"]'),
('3f01be05-4e9d-417a-9546-e3b2bd79f103','偈頌八十五首  其六二','釋妙倫','宋','宋诗','song-poetry','','[]','宏施韜略，密展謀猷。',28,'全唐诗/poet.song.215000.json','["宏施韜略，密展謀猷。", "胸中浩氣，遠邁伊周，玉爐香噴幾千秋。"]'),
('20b683a4-0e9b-40e3-951b-9f831ad17591','偈頌八十五首  其六三','釋妙倫','宋','宋诗','song-poetry','','[]','我此一關，無背無向。',20,'全唐诗/poet.song.215000.json','["我此一關，無背無向。", "擬欲進前，網在頭上。"]'),
('7cdc2f9d-ade2-4d4a-aa5d-58136f2795ce','偈頌八十五首  其六四','釋妙倫','宋','宋诗','song-poetry','','[]','紫簫聲斷月初斜，笑指蓬瀛是故家。',32,'全唐诗/poet.song.215000.json','["紫簫聲斷月初斜，笑指蓬瀛是故家。", "十二玉樓尋不見，手攀仙鶴步煙霞。"]'),
('35c6cdc8-05a6-48da-a4ba-eac2955d8b5c','偈頌八十五首  其六五','釋妙倫','宋','宋诗','song-poetry','','[]','始從鹿野苑，終至跋提河。',40,'全唐诗/poet.song.215000.json','["始從鹿野苑，終至跋提河。", "於是二中間，未嘗說一字。", "年年花卉競芳時，東風一陣成狼藉。"]'),
('595952c0-0780-4128-93ee-b41970f62843','偈頌八十五首  其六六','釋妙倫','宋','宋诗','song-poetry','','[]','梨花李花白，杏花桃花紅。',60,'全唐诗/poet.song.215000.json','["梨花李花白，杏花桃花紅。", "的的正法眼藏，的的古佛心宗。", "靈雲老幾曾夢見，道得底都是脫空。", "尀耐螺江釣魚船上翁，絲綸倒把攪春風。"]'),
('05d24e70-34dc-4e2d-9a1f-662089af9c59','偈頌八十五首  其六七','釋妙倫','宋','宋诗','song-poetry','','[]','金佛不度爐，道士念蘇嚧。',53,'全唐诗/poet.song.215000.json','["金佛不度爐，道士念蘇嚧。", "木佛不度火，嵩山打竈墮。", "泥佛不度水，鍾馗嚇小鬼。", "真佛屋裏坐，嗄，趙州老漢敗露了也。"]'),
('def0aa22-a284-4bc0-a597-e52e84833d06','偈頌八十五首  其六八','釋妙倫','宋','宋诗','song-poetry','','[]','你是川僧，我是浙僧。',36,'全唐诗/poet.song.215000.json','["你是川僧，我是浙僧。", "相逢相見，元似不曾。", "因何今日成冤憎，不見道臭肉來蠅。"]'),
('c0be75a7-5ed9-496c-a12f-ecf32f470726','偈頌八十五首  其六九','釋妙倫','宋','宋诗','song-poetry','','[]','紅日昇兮，慧目明而不晦。',74,'全唐诗/poet.song.215000.json','["紅日昇兮，慧目明而不晦。", "白雲吐兮，慈容露而不遮。", "林木交加兮胸題卍字，峰巒重疊兮足躡千花。", "好箇天然古釋迦。", "若謂今朝始誕梵王家，苦哉佛陀耶，苦哉佛陀耶。"]'),
('4abcf70a-fe7f-494a-a87c-dad14ee8b398','偈頌八十五首  其七○','釋妙倫','宋','宋诗','song-poetry','','[]','送春賸欲舉金樽，客不開襟怎與論。',32,'全唐诗/poet.song.215000.json','["送春賸欲舉金樽，客不開襟怎與論。", "自飲一盃歸去後，喜逢家樂閙黄昏。"]'),
('5b8c22ad-d5b2-4b4a-a20a-a79e3cfe1929','偈頌八十五首  其七一','釋妙倫','宋','宋诗','song-poetry','','[]','五峰影裏，雙澗聲中。',20,'全唐诗/poet.song.215000.json','["五峰影裏，雙澗聲中。", "有大寶藏，八面玲瓏。"]'),
('b28d791e-5b4b-49a5-92c2-f0624c0605f7','偈頌八十五首  其七二','釋妙倫','宋','宋诗','song-poetry','','[]','德山低頭，夾山點頭。',44,'全唐诗/poet.song.215000.json','["德山低頭，夾山點頭。", "俱胝豎起手指頭，玄沙𡎺破脚指頭，都來不出山僧拄杖頭。", "一葉落，天下秋。"]'),
('418da9d6-1869-4035-a756-f9e0ebf3ef4f','偈頌八十五首  其七三','釋妙倫','宋','宋诗','song-poetry','','[]','足不履地，頭不頂天。',40,'全唐诗/poet.song.215000.json','["足不履地，頭不頂天。", "纔識雙澗，便見雙泉。", "問有今古，答無正偏。", "若也未曉，細嚼黄連。"]'),
('caa3d089-97cb-46bf-a2f8-e41c9553ef25','偈頌八十五首  其七四','釋妙倫','宋','宋诗','song-poetry','','[]','峰頭異角靈毛，澗底錦鱗赬尾。',73,'全唐诗/poet.song.215000.json','["峰頭異角靈毛，澗底錦鱗赬尾。", "各各性命一條，都在山僧手裏。", "今日放開線路，也不妨自馳自驟，自飛自鳴，自泳自遊，自潛自躍，又阿誰管你，諸方密布漫天網子。"]'),
('d5815f8b-a78e-49b0-827b-b3cd52cc596a','偈頌八十五首  其七五','釋妙倫','宋','宋诗','song-poetry','','[]','淘沙得金，鑿石得玉。',20,'全唐诗/poet.song.215000.json','["淘沙得金，鑿石得玉。", "張弓得鳥，擲釣得魚。"]'),
('84bbaf0e-2e20-4a8d-8990-3b73edda7874','偈頌八十五首  其七六','釋妙倫','宋','宋诗','song-poetry','','[]','門外一犬吠，櫩前一鳥鳴。',46,'全唐诗/poet.song.215000.json','["門外一犬吠，櫩前一鳥鳴。", "天際半鈎新月，移影上疎櫺。", "憶得雪山六載，凍不死，餓不殺，夜半見明星。"]'),
('836b710b-6e23-4cb3-82fd-a2046e542c4c','偈頌八十五首  其七七','釋妙倫','宋','宋诗','song-poetry','','[]','一從醉別畫堂前，鬢亂釵橫語笑顛。',32,'全唐诗/poet.song.215000.json','["一從醉別畫堂前，鬢亂釵橫語笑顛。", "最是惱人腸肚處，借婆裙子拜婆年。"]'),
('39c4beb5-a789-49fb-9f7a-ab3d0e4406e9','偈頌八十五首  其七八','釋妙倫','宋','宋诗','song-poetry','','[]','正朝握拂，埽蕩窠窟。',40,'全唐诗/poet.song.215000.json','["正朝握拂，埽蕩窠窟。", "左揀牛溲，右選馬勃。", "豎作一團，是甚臭鶻。", "分付諸人，洗腸換骨。"]'),
('bd31f15e-da8c-47b2-a21b-823f90070be6','偈頌八十五首  其七九','釋妙倫','宋','宋诗','song-poetry','','[]','一豎一展，一放一收。',36,'全唐诗/poet.song.215000.json','["一豎一展，一放一收。", "仰山弄險，過似巖頭。", "頼是隨風囘櫓棹，幾乎翻却釣魚舟。"]'),
('e5432b86-8f37-44d7-9b47-d23c2f30c7d0','偈頌八十五首  其八○','釋妙倫','宋','宋诗','song-poetry','','[]','竇八抽身已敗贓，偷兒曲爲巧遮藏。',32,'全唐诗/poet.song.215000.json','["竇八抽身已敗贓，偷兒曲爲巧遮藏。", "一家著賊猶閑事，攪斷平人幾肚腸。"]'),
('9c58fe87-f87d-4cad-a4e7-09d251d0c080','偈頌八十五首  其八一','釋妙倫','宋','宋诗','song-poetry','','[]','明珠璨璨對人傾，是甚多年魚眼睛。',32,'全唐诗/poet.song.215000.json','["明珠璨璨對人傾，是甚多年魚眼睛。", "拋撒滿前收不上，糞箕埽箒亂縱橫。"]'),
('8f9f5c1a-6bf0-495e-844c-4420d78a3cd1','偈頌八十五首  其八二','釋妙倫','宋','宋诗','song-poetry','','[]','煙橫大野，鴈篆長空。',52,'全唐诗/poet.song.215000.json','["煙橫大野，鴈篆長空。", "玉露滴開八枝九枝黄菊，金風剪下三片兩片丹楓。", "吾家生涯，雖然冷淡，取之無禁，用之無窮。"]'),
('c61e7f14-5d5f-49f9-b09b-b0e2e0087de0','偈頌八十五首  其八三','釋妙倫','宋','宋诗','song-poetry','','[]','掃蕩邊塵未著勞，折弓戲把射青霄。',32,'全唐诗/poet.song.215000.json','["掃蕩邊塵未著勞，折弓戲把射青霄。", "滿攀自覺無多力，隨手那知落一鵰。"]'),
('a5b5b3df-c8c8-443d-b819-99420cd9b8ff','偈頌八十五首  其八四','釋妙倫','宋','宋诗','song-poetry','','[]','輥雪峰毬，打禾山鼓，露柱燈籠齊作舞。',38,'全唐诗/poet.song.215000.json','["輥雪峰毬，打禾山鼓，露柱燈籠齊作舞。", "引得老豐干，倒跨南山虎。", "聖人作，萬物覩。"]'),
('016efdb2-a61d-4389-a911-a250669e80d2','偈頌八十五首  其八五','釋妙倫','宋','宋诗','song-poetry','','[]','將軍令下閃旌旗，胡騎紛紛頓失威。',32,'全唐诗/poet.song.215000.json','["將軍令下閃旌旗，胡騎紛紛頓失威。", "縱有突然驍驟者，不知身已陷重圍。"]'),
('8d9ec44e-bb98-4e22-ac6e-945f7fb9da33','偈頌二十二首  其一','釋妙倫','宋','宋诗','song-poetry','','[]','空兮空兮無背面，拈起豁然成兩片。',44,'全唐诗/poet.song.215000.json','["空兮空兮無背面，拈起豁然成兩片。", "搭向南屏山角頭，千古萬古少人見。", "要見麽，金烏飛上琉璃殿。"]'),
('292d5be7-0f5b-4dbe-b5cc-6cbf825c8a62','偈頌二十二首  其二','釋妙倫','宋','宋诗','song-poetry','','["\u897f\u6e56"]','一自休戈見太平，跨龍仙去彩霞輕。',32,'全唐诗/poet.song.215000.json','["一自休戈見太平，跨龍仙去彩霞輕。", "感恩惟有西湖水，夜夜清波蘸月明。"]'),
('ea8e75ef-dde8-40ca-a766-05726c32eb80','偈頌二十二首  其三','釋妙倫','宋','宋诗','song-poetry','','[]','南山有衆盈籌，總是佛祖冤讎。',89,'全唐诗/poet.song.215000.json','["南山有衆盈籌，總是佛祖冤讎。", "一夏資糧尚少，豈容坐視無謀。", "長安城裏，芳草渡頭。", "頼有作者，爲我希求，要使箇箇飽飫而優遊。", "忽然遇維摩居士東指西指，又且如何對酬。", "一言纔勘破，笑倒老金牛。"]'),
('95d29809-428b-4087-ac5b-7a8e211d2839','偈頌二十二首  其四','釋妙倫','宋','宋诗','song-poetry','','[]','月臨粉壁間尤白，燭入紗籠裏更紅。',32,'全唐诗/poet.song.215000.json','["月臨粉壁間尤白，燭入紗籠裏更紅。", "夜冷井邊聞落葉，已驚秋色到梧桐。"]'),
('e3930fa6-2e04-4a89-ab6b-2e668251db7e','偈頌二十二首  其五','釋妙倫','宋','宋诗','song-poetry','','[]','十五日前，結而不解。',59,'全唐诗/poet.song.215000.json','["十五日前，結而不解。", "十五日後，解而不結。", "正當今日，結也休，解也休。", "草鞋對頰聳八耳，拄杖橫身撐兩頭。", "五湖四海衲子爲冤讎。"]'),
('7ec9baf4-6634-4626-822e-6c29a64a9d24','偈頌二十二首  其六','釋妙倫','宋','宋诗','song-poetry','','[]','庭前黄葉墜，嶺上白雲屯。',24,'全唐诗/poet.song.215000.json','["庭前黄葉墜，嶺上白雲屯。", "風味無多子，何人共我論。"]'),
('85399063-d079-42db-ab5b-737a1e81df3f','偈頌二十二首  其七','釋妙倫','宋','宋诗','song-poetry','','[]','一遇中秋節，競賞中秋月。',62,'全唐诗/poet.song.215000.json','["一遇中秋節，競賞中秋月。", "指底指，玩底玩，說底說，到了何曾離圓缺。", "惟愛老長沙，一踏踏倒小釋迦。", "光燦爛，絕周遮，不知端的落誰家。"]'),
('494f0973-d3d3-46da-bb0a-a1bbb59c3400','偈頌二十二首  其八','釋妙倫','宋','宋诗','song-poetry','','[]','西風一陣惡，北林平地摧。',36,'全唐诗/poet.song.215000.json','["西風一陣惡，北林平地摧。", "曉猿夜鶴，驚怨空徘徊。", "哀哉哀哉，戒光猶自照高臺。"]'),
('b1e65a08-14c2-4206-8d86-843343be953c','偈頌二十二首  其九','釋妙倫','宋','宋诗','song-poetry','','[]','渚流虹影，樞繞電光。',20,'全唐诗/poet.song.215000.json','["渚流虹影，樞繞電光。", "聖人出現，化洽殊方。"]'),
('f18ae0dc-eb3f-4a7f-b24b-aee6c7edfccf','偈頌二十二首  其一○','釋妙倫','宋','宋诗','song-poetry','','[]','日暖噴庭花，風輕摇岸柳。',28,'全唐诗/poet.song.215000.json','["日暖噴庭花，風輕摇岸柳。", "雙林入滅老臊胡，至今猶露摩胸手。"]'),
('5e05a018-8042-4e5d-8a96-d6ed13f8222d','偈頌二十二首  其一一','釋妙倫','宋','宋诗','song-poetry','','[]','千尋浪裏出頭，萬仞崖前展手。',48,'全唐诗/poet.song.215000.json','["千尋浪裏出頭，萬仞崖前展手。", "七百甲子老翁，剛然弄一場醜。", "摘楊花，摘楊花，翻身跳上樹，驚散暮林鴉。"]'),
('a3f70520-4fe7-417b-b1a9-0dec670a1042','偈頌二十二首  其一二','釋妙倫','宋','宋诗','song-poetry','','[]','玉纜纖纖布嫩芽，香苞朶朶依新葉。',32,'全唐诗/poet.song.215000.json','["玉纜纖纖布嫩芽，香苞朶朶依新葉。", "化工底事把天機，剖腹傾心俱漏泄。"]'),
('8e413a5e-b1da-49ef-b781-d0b70a128ca3','偈頌二十二首  其一三','釋妙倫','宋','宋诗','song-poetry','','[]','白蘋洲畔，紅蓼岸頭。',56,'全唐诗/poet.song.215000.json','["白蘋洲畔，紅蓼岸頭。", "漁人得意，撥動孤舟。", "飛起一行兩行塞雁，漾開七箇八箇沙鷗。", "絲綸在手，隨放隨收，時有金鱗上直鈎。"]'),
('3736aec7-dc40-41a7-b0e7-107c3cd2ce8d','偈頌二十二首  其一四','釋妙倫','宋','宋诗','song-poetry','','[]','九月九，一句話。',37,'全唐诗/poet.song.215000.json','["九月九，一句話。", "有準繩，無柄欛。", "惟有陶靖節知縫罅，悠然見南山，笑傲東籬下。"]'),
('52830b99-b4e3-42f4-a5b8-aa838e8f90ad','偈頌二十二首  其一五','釋妙倫','宋','宋诗','song-poetry','','[]','將不去，拈不來。',28,'全唐诗/poet.song.215000.json','["將不去，拈不來。", "兩箇漢，一場獃。", "至今平地上，狼藉覆蒼苔。"]'),
('d8e5ed4e-9bd1-43c1-a386-29e992f292f6','偈頌二十二首  其一六','釋妙倫','宋','宋诗','song-poetry','','[]','安眠露地牛，未脫黄金索。',24,'全唐诗/poet.song.215000.json','["安眠露地牛，未脫黄金索。", "常在顧盼中，牧童難捉摸。"]'),
('3c34d53e-acdd-4083-a662-9d7e2ea6e5ad','偈頌二十二首  其一七','釋妙倫','宋','宋诗','song-poetry','','[]','年年是好年，日日是好日。',38,'全唐诗/poet.song.215000.json','["年年是好年，日日是好日。", "南山今日好處又非常，石人起拜木人揖。", "蛇生角，虎插翼。"]'),
('305cd81a-9d7d-4314-9f8e-71014c59026a','偈頌二十二首  其一八','釋妙倫','宋','宋诗','song-poetry','','[]','煙迷岸樹，水沒汀莎。',24,'全唐诗/poet.song.215000.json','["煙迷岸樹，水沒汀莎。", "渡頭撥動釣舟，野鴨翩然飛過。"]'),
('1fe8954a-b69e-49e1-a6ee-0aa9d28799d9','偈頌二十二首  其一九','釋妙倫','宋','宋诗','song-poetry','','[]','雲收幽谷靜，雨歇幽澗鳴。',77,'全唐诗/poet.song.215000.json','["雲收幽谷靜，雨歇幽澗鳴。", "風暖幽鳥語，日融幽草青。", "二祖不知，截斷一手臂。", "歸宗不會，拭壞雙眼睛。", "致使衲僧，箇箇半疑半信，半醉半醒。", "爭知道自來滿口，咀華而嚼英。"]'),
('20992084-0875-4f29-8cc2-34e8d13e21a4','偈頌二十二首  其二○','釋妙倫','宋','宋诗','song-poetry','','[]','九十日一夏，始終無縫罅。',40,'全唐诗/poet.song.215000.json','["九十日一夏，始終無縫罅。", "拶到末梢頭，有箇好說話。", "長爪梵志註九經，瞎眼波斯書八卦。"]'),
('89fbf545-a21a-440c-bf73-8cf3d873d2ad','偈頌二十二首  其二一','釋妙倫','宋','宋诗','song-poetry','','[]','雪山層層，雪澗冷冷。',38,'全唐诗/poet.song.215000.json','["雪山層層，雪澗冷冷。", "瞿曇過去久矣，今宵誰覩明星。", "奇哉，低聲，恐成妄語誑衆生。"]'),
('e735cd8d-287e-490d-b155-39bfc56fa7ad','偈頌二十二首  其二二','釋妙倫','宋','宋诗','song-poetry','','[]','貓弄鼠，猿禁猴，雲門固是有殺活機謀。',32,'全唐诗/poet.song.215000.json','["貓弄鼠，猿禁猴，雲門固是有殺活機謀。", "檢點來，依舊出不得者僧話頭。"]'),
('b00efc4d-9a2c-4980-b4ff-c66e42e336c5','觀音贊','釋妙倫','宋','宋诗','song-poetry','','[]','皎皎月沈波，萋萋草泣露。',24,'全唐诗/poet.song.215000.json','["皎皎月沈波，萋萋草泣露。", "良哉觀世音，不會轉身句。"]'),
('792eebfd-a881-4cfc-875f-d5ea0ca55fa9','又泛水像贊','釋妙倫','宋','宋诗','song-poetry','','[]','覺而動，照而寂。',34,'全唐诗/poet.song.215000.json','["覺而動，照而寂。", "雲浄月明，波停水碧。", "圓通觸處露全身，依舊脚跟浮逼逼。"]'),
('f06f237d-6d35-46a0-b0d0-90fc2e9f2c95','布袋和尚贊','釋妙倫','宋','宋诗','song-poetry','','[]','朝向廛中遊，暮打市裏過。',24,'全唐诗/poet.song.215000.json','["朝向廛中遊，暮打市裏過。", "滯貨賣不行，頼是肚皮大。"]'),
('659781d1-aca4-4c4e-8872-5558e5734b54','達磨贊','釋妙倫','宋','宋诗','song-poetry','','[]','西竺乾，東震旦。',36,'全唐诗/poet.song.215000.json','["西竺乾，東震旦。", "遍流毒，是者漢。", "不知賺了多少衲僧，至今八錯七差三馬九亂。"]'),
('517a700a-d964-4918-bab2-259d3bce872e','六祖夜渡贊','釋妙倫','宋','宋诗','song-poetry','','[]','樹煙漠漠水沈沈，父子相拋用賊心。',32,'全唐诗/poet.song.215000.json','["樹煙漠漠水沈沈，父子相拋用賊心。", "授了衣盂連夜渡，釘樁摇櫓到于今。"]'),
('19bbc819-6851-487e-9e06-539a9aae1b2f','維摩贊','釋妙倫','宋','宋诗','song-poetry','','[]','倚胡床，執白拂。',34,'全唐诗/poet.song.215000.json','["倚胡床，執白拂。", "三十三人，盡底籍沒。", "却將一默對文殊，兔子何曾離得窟。"]'),
('d5728054-5ac9-48e5-9848-fbff66131cde','靈照女贊','釋妙倫','宋','宋诗','song-poetry','','[]','生不居家，長不出嫁。',34,'全唐诗/poet.song.215000.json','["生不居家，長不出嫁。", "一柄笊籬，天上天下。", "雖然不直分文，只是無人著價。"]'),
('93d019e0-0cc6-4298-9100-197aaf1aba76','崇德圓老請贊','釋妙倫','宋','宋诗','song-poetry','','[]','無圓位中，一毫難狀。',55,'全唐诗/poet.song.215000.json','["無圓位中，一毫難狀。", "於第二門，有箇模樣。", "長安城裏卓紅旗，鴈蕩峰頭翻白浪。", "更要不覩是籍沒一切人家財，猶要算白帳。"]'),
('375f3578-70ef-4aad-8b5a-7fe297ca6b58','雪山梵老請贊','釋妙倫','宋','宋诗','song-poetry','','[]','握三尺鐵，震一聲雷。',38,'全唐诗/poet.song.215000.json','["握三尺鐵，震一聲雷。", "剛把密旨，翻作禍胎。", "流落西村李翁田地上，叢林又是一番災。"]'),
('89b01697-6051-4245-b41e-3465abd7b081','真如靖老請贊','釋妙倫','宋','宋诗','song-poetry','','[]','夜叉心，菩薩面。',48,'全唐诗/poet.song.215000.json','["夜叉心，菩薩面。", "動則雲翻大野鬼悉懼聞，靜則練繞長溪人皆喜見。", "有一道迷魂呪，三千里外學念者也靈驗。"]'),
('e171f81a-c778-438f-8486-c51fcf396037','治平璧老請贊','釋妙倫','宋','宋诗','song-poetry','','[]','似馬無騣，似牛無角。',31,'全唐诗/poet.song.215000.json','["似馬無騣，似牛無角。", "描摸出來，非常大錯。", "錯錯，萬古一崖倚寥廓。"]'),
('4ee5bcd4-bded-4441-81da-85116fd9a45c','支提宏老請贊','釋妙倫','宋','宋诗','song-poetry','','[]','搭一隻手，揮三尺鐵。',61,'全唐诗/poet.song.215000.json','["搭一隻手，揮三尺鐵。", "天下衲僧，望風膽裂。", "豈料豐干院裏撞著箇匾頭魔孽，盡把家私俱漏洩。", "却向玉融側童峰前，對人點胸，背地吐舌。"]'),
('c1696c10-05bc-46f9-886f-98405e9a0b7a','連雲樞老請贊','釋妙倫','宋','宋诗','song-poetry','','[]','密運玄樞，恢張要旨。',36,'全唐诗/poet.song.215000.json','["密運玄樞，恢張要旨。", "名邈得來，成甚面嘴。", "若是金毛獅子子，誵訛豈止三千里。"]'),
('24d5cfbe-7f7e-4abd-b08a-bbea36f378b6','慈恩涇老請贊','釋妙倫','宋','宋诗','song-poetry','','[]','兩耳全聵，雙目半昏。',75,'全唐诗/poet.song.215000.json','["兩耳全聵，雙目半昏。", "涇清渭濁，誰與辨論。", "只麽廝淈𣸩，狼藉破沙盆。", "有箇不唧𠺕底，剛要面前塗糊背後揩抹。", "黑漫漫地恰似雲屯挂向壽峰頂上，往往喚作南山古樹根。"]'),
('7ee90282-4c7b-45f3-94d3-ef7da1e12736','精嚴昂老請贊','釋妙倫','宋','宋诗','song-poetry','','[]','軒昂氣宇，矍鑠精神。',32,'全唐诗/poet.song.215000.json','["軒昂氣宇，矍鑠精神。", "木雞驅成鸞鳳，芻狗逼作麒麟，世上知心能幾人。"]'),
('26356b51-6bc1-4e71-8c56-d64943b254ae','寶藏主請贊','釋妙倫','宋','宋诗','song-poetry','','[]','乾之下，坤之上。',44,'全唐诗/poet.song.215000.json','["乾之下，坤之上。", "有一寶，無異相。", "剛地描摸出來，便見許多模樣。", "引一切人到面前，學算鬼丁帳。"]'),
('2f1cd230-59a9-4af6-bb8e-d14fec93ca71','月藏主請贊','釋妙倫','宋','宋诗','song-poetry','','[]','頭顱突兀，面孔鱗皴。',39,'全唐诗/poet.song.215000.json','["頭顱突兀，面孔鱗皴。", "剛把一莖燈草，對人秤作半斤。", "阿呵呵，從教道月明照見夜行人。"]'),
('0de36f3d-3e8b-4aac-8e87-2c00ea7be5c6','埴知客請贊','釋妙倫','宋','宋诗','song-poetry','','[]','寒巖其骨，槁木其形。',49,'全唐诗/poet.song.215000.json','["寒巖其骨，槁木其形。", "解語非舌，能言非聲。", "埏埴立於未立，氣質成於未成。", "自者般伎倆，也有人描模上丹青。"]'),
('39eae8aa-deda-4b75-9dfd-b5e430b2b280','若楫請贊','釋妙倫','宋','宋诗','song-poetry','','[]','貌兮蘚石，形兮雲松。',56,'全唐诗/poet.song.215000.json','["貌兮蘚石，形兮雲松。", "口捷如啞，耳聰若聾。", "布重網無明山上，蕩一楫煩惱海中。", "吽，五日後也有箇弄脫空，水底放出泥大蟲。"]'),
('88b87352-06a5-4a0b-b9f7-2cbc31ff2911','友方請贊','釋妙倫','宋','宋诗','song-poetry','','[]','怒具慈悲，喜懷慘酷。',58,'全唐诗/poet.song.215000.json','["怒具慈悲，喜懷慘酷。", "指方爲圓，拗曲作直。", "不特鑿石栽花，兼要堆雲種竹。", "五五合成三十六，好彩是汝不學他，學他和汝入地獄。"]'),
('874d6abd-8ba9-4135-a027-96721d1faf8d','浄惠教老請贊','釋妙倫','宋','宋诗','song-poetry','','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','霜茁其巔，雲橫其肩。',61,'全唐诗/poet.song.215000.json','["霜茁其巔，雲橫其肩。", "眼無一角，鼻少半邊。", "太湖水底走馬，洞庭山上撐船。", "天下衲僧名不得狀不得，取不得捨不得，一齊喚作教外別傳。"]'),
('00195e9f-6a13-43d8-aa4e-7d1212cf027a','觀音觀老請贊','釋妙倫','宋','宋诗','song-poetry','','[]','眼無筋，頭無腦。',48,'全唐诗/poet.song.215000.json','["眼無筋，頭無腦。", "是箇非箇併除，佛兮魔兮俱掃。", "須彌山折筯挑來，眉毛上懸挂恰好。", "是誰識他，觀音長老。"]'),
('ffb815f4-6969-4408-bbc2-9a26a14e46c9','瑞巖衆行者請贊','釋妙倫','宋','宋诗','song-poetry','','[]','米裏有蟲，麥裏有麵。',32,'全唐诗/poet.song.215000.json','["米裏有蟲，麥裏有麵。", "非是老盧，何曾覷見。", "見不見，八角磨盤空裏轉。"]'),
('42847ca0-c240-494f-b229-6c65985e224a','壽首座請贊','釋妙倫','宋','宋诗','song-poetry','','[]','漆桶一枚，無大得大。',48,'全唐诗/poet.song.215000.json','["漆桶一枚，無大得大。", "鼓合叢林，翻成口過。", "有語不勘玄機，有棒不打鐵磨。", "南屏今日開眼放一箇，咄咄咄。"]'),
('d3771720-843a-459e-b258-af6a61fca05a','日本雲上人請贊','釋妙倫','宋','宋诗','song-poetry','','[]','山頭雲，天上月。',69,'全唐诗/poet.song.215000.json','["山頭雲，天上月。", "雲月有殊，光影無別。", "此是吾端的，不許見，不許聞。", "大唐國有人，必能辨，必能別。", "不妨捲去挂向大溪頭，教他幾箇橫論豎論東說西說。"]'),
('b9bfa9d7-1a55-41bf-8174-b79443677458','日本門上人請贊','釋妙倫','宋','宋诗','song-poetry','','[]','須彌繞白日，碧落穿紅霞。',42,'全唐诗/poet.song.215000.json','["須彌繞白日，碧落穿紅霞。", "喚作真則錯，喚作相則差。", "只此一門難摸索，賺他幾箇失脚走天涯。"]'),
('dbadbfb6-94a5-4933-af74-068a5e9e8289','日本見上人請贊','釋妙倫','宋','宋诗','song-poetry','','[]','一見便見，一得永得。',63,'全唐诗/poet.song.215000.json','["一見便見，一得永得。", "有影無形，易辯難識。", "大唐不許藏蹤，日本那容隠迹。", "扶桑夜半日頭紅，不妨背手拈起一觀，決定頭斜面曲，鼻橫眼直。"]'),
('f5f8579b-32cd-437c-b484-414a977b76e3','與若虛新戒付衣','釋妙倫','宋','宋诗','song-poetry','','[]','靈山密付，少室親傳。',36,'全唐诗/poet.song.215000.json','["靈山密付，少室親傳。", "或長或短，或方或圓。", "直下若能提得起，優曇一朵瑞祇園。"]'),
('95aff155-6e42-419d-b1b7-f11a2d8e242f','西巖','釋妙倫','宋','宋诗','song-poetry','','[]','怪石嵌空濺碧流，從來無路與人游。',32,'全唐诗/poet.song.215000.json','["怪石嵌空濺碧流，從來無路與人游。", "莫嫌立處孤危甚，要與東山作對頭。"]'),
('11a715a9-e1a2-47fd-8334-976516b2d7b4','牧溪','釋妙倫','宋','宋诗','song-poetry','','[]','百草頭邊意已賒，鞭繩放下卧平沙。',32,'全唐诗/poet.song.215000.json','["百草頭邊意已賒，鞭繩放下卧平沙。", "覺來古岸東風急，橫笛一聲山日斜。"]'),
('f47c7362-4603-4909-b246-4ba8157f5e1b','了翁','釋妙倫','宋','宋诗','song-poetry','','[]','踏斷草鞋，拗折拄杖。',30,'全唐诗/poet.song.215000.json','["踏斷草鞋，拗折拄杖。", "徹底風流，匙挑不上。", "擬問如何，擘面便掌。"]'),
('9cfcef23-66ee-48a5-a1db-6b98fb87ffcc','笑堂','釋妙倫','宋','宋诗','song-poetry','','[]','冷地無端錯喜歡，却將鴟吻對門安。',32,'全唐诗/poet.song.215000.json','["冷地無端錯喜歡，却將鴟吻對門安。", "引它鐵作面皮漢，千里聞風也破顔。"]'),
('58d828ae-3903-42bd-a91b-5dca284aae96','無雜','釋妙倫','宋','宋诗','song-poetry','','[]','平常用處黑漫漫，十二時中沒兩般。',32,'全唐诗/poet.song.215000.json','["平常用處黑漫漫，十二時中沒兩般。", "大小趙州噇飯漢，斧頭返被蛀蟲鑽。"]'),
('77abf4c2-4cf3-4c06-b8d9-f3322657688c','懶散','釋妙倫','宋','宋诗','song-poetry','','[]','一味放落魄，誰人柰得何。',24,'全唐诗/poet.song.215000.json','["一味放落魄，誰人柰得何。", "忽然刀斫手，依舊著摩挲。"]');
